    { id: 'dashboard', label: 'Dashboard', icon: '📊', roles: [UserType.ADMIN, UserType.TEHSIL] },
    { id: 'entry', label: 'Account Entry', icon: '📝', roles: [UserType.ADMIN, UserType.TEHSIL] },
    { id: 'verification', label: 'Verification', icon: '✅', roles: [UserType.ADMIN, UserType.TEHSIL] },
  ];

  const filteredMenu = menuItems.filter(item => item.roles.includes(user.User_Type));

  return (
    <>
      {/* Mobile Backdrop */}
      {isOpen && (
        <div 
          className="fixed inset-0 bg-black bg-opacity-50 z-20 md:hidden" 
          onClick={() => setIsOpen(false)}
        />
      )}

      {/* Sidebar Content */}
      <div className={`fixed inset-y-0 left-0 transform ${isOpen ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0 transition-transform duration-300 ease-in-out bg-slate-900 text-white w-64 z-30 flex flex-col`}>
