  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <h2 className="text-2xl font-bold text-slate-800">Welcome, {user.Officer_Name}</h2>
        <p className="text-slate-500">Here is your BLO Management summary for today.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {stats.map((stat, idx) => (
          <div key={idx} className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 flex items-center space-x-4">
            <div className={`${stat.color} text-white p-3 rounded-lg text-2xl`}>
              {stat.icon}
            </div>
            <div>
              <p className="text-sm font-medium text-slate-500 uppercase tracking-wider">{stat.label}</p>
              <p className="text-3xl font-bold text-slate-900">{stat.value}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <h3 className="text-lg font-semibold text-slate-800 mb-4 border-b pb-2">User Profile Information</h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <div>
            <p className="text-xs text-slate-500 uppercase">Designation</p>
            <p className="font-medium text-slate-700">{user.Designation}</p>
          </div>
          <div>
            <p className="text-xs text-slate-500 uppercase">Mobile Number</p>
            <p className="font-medium text-slate-700">{user.Mobile}</p>
          </div>
          <div>
            <p className="text-xs text-slate-500 uppercase">Access Level</p>
            <p className="font-medium text-slate-700 capitalize">{user.User_Type}</p>
