export default Dashboard;

import React, { useState } from 'react';
import { BLOAccount, User, UserType, Bank, BankBranch } from '../types';
import { searchIFSCViaGemini } from '../services/geminiService';

interface AccountEntryProps {
  user: User;
  accounts: BLOAccount[];
  banks: Bank[];
  branches: BankBranch[];
  onUpdate: (updated: BLOAccount, newBank?: Bank, newBranch?: BankBranch) => void;
}

const AccountEntry: React.FC<AccountEntryProps> = ({ user, accounts, banks, branches, onUpdate }) => {
  const [selectedBLO, setSelectedBLO] = useState<BLOAccount | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const [editForm, setEditForm] = useState<BLOAccount | null>(null);

  const filteredAccounts = user.User_Type === UserType.ADMIN 
    ? accounts 
    : accounts.filter(a => a.User_ID === user.User_ID);

  const handleEdit = (blo: BLOAccount) => {
    setSelectedBLO(blo);
    setEditForm({ ...blo });
  };

  const handleIFSCChange = async (val: string) => {
    if (!editForm) return;
    setEditForm({ ...editForm, IFSC_Code: val.toUpperCase() });

    if (val.length === 11) {
      setIsSearching(true);
      const result = await searchIFSCViaGemini(val);
      if (result) {
        // Find or prepare to add bank/branch
        let bank = banks.find(b => b.Bank_Name.toLowerCase() === result.bankName.toLowerCase());
        let branch = branches.find(br => br.IFSC_Code === result.ifsc);

        const newBank: Bank | undefined = !bank ? {
          Bank_ID: 'B_' + Date.now(),
          Bank_Name: result.bankName,
          T_STMP_ADD: new Date().toISOString(),
          T_STMP_UPD: new Date().toISOString()
        } : undefined;

        const targetBankId = bank ? bank.Bank_ID : newBank!.Bank_ID;

        const newBranch: BankBranch | undefined = !branch ? {
          Branch_ID: 'BR_' + Date.now(),
          Branch_Name: result.branchName,
          IFSC_Code: result.ifsc,
          Bank_ID: targetBankId,
          T_STMP_ADD: new Date().toISOString(),
          T_STMP_UPD: new Date().toISOString()
        } : undefined;

        setEditForm(prev => prev ? ({
          ...prev,
          Bank_ID: targetBankId,
          Branch_ID: branch ? branch.Branch_ID : newBranch!.Branch_ID
        }) : null);

        // Actual saving happens on form submit, but we can stage these
        (window as any)._stagedBank = newBank;
        (window as any)._stagedBranch = newBranch;
      }
      setIsSearching(false);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && editForm) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setEditForm({ ...editForm, Account_Passbook_Doc: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editForm) {
      onUpdate(
        editForm, 
        (window as any)._stagedBank, 
        (window as any)._stagedBranch
      );
      setSelectedBLO(null);
      setEditForm(null);
      delete (window as any)._stagedBank;
      delete (window as any)._stagedBranch;
    }
  };

  if (selectedBLO && editForm) {
    const isLocked = editForm.Verified === 'yes' && user.User_Type !== UserType.ADMIN;

    return (
      <div className="bg-white rounded-xl shadow-lg border border-slate-200 overflow-hidden">
        <div className="bg-emerald-600 px-6 py-4 flex justify-between items-center text-white">
          <h3 className="text-xl font-bold">Edit BLO Account: {selectedBLO.BLO_Name}</h3>
          <button onClick={() => setSelectedBLO(null)} className="text-white/80 hover:text-white">✕</button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-8">
          {isLocked && (
            <div className="bg-amber-50 border border-amber-200 p-4 rounded-lg text-amber-800 text-sm">
              ⚠️ This record is verified and locked. Only administrators can make changes.
            </div>
          )}

          {/* Section 1: Assembly Details */}
          <div>
            <h4 className="text-emerald-700 font-bold border-b pb-2 mb-4 uppercase text-xs tracking-widest">Assembly Details</h4>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="space-y-1">
                <label className="text-xs font-semibold text-slate-500">AC No.</label>
                <input disabled value={editForm.AC_No} className="w-full bg-slate-50 border border-slate-200 rounded p-2 text-sm" />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-semibold text-slate-500">AC Name</label>
                <input disabled value={editForm.AC_Name} className="w-full bg-slate-50 border border-slate-200 rounded p-2 text-sm" />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-semibold text-slate-500">Tehsil</label>
                <input disabled value={editForm.Tehsil} className="w-full bg-slate-50 border border-slate-200 rounded p-2 text-sm" />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-semibold text-slate-500">Part No.</label>
                <input disabled value={editForm.Part_No} className="w-full bg-slate-50 border border-slate-200 rounded p-2 text-sm" />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-semibold text-slate-500">Part Name (EN)</label>
                <input disabled value={editForm.Part_Name_EN} className="w-full bg-slate-50 border border-slate-200 rounded p-2 text-sm" />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-semibold text-slate-500">Part Name (HI)</label>
                <input disabled value={editForm.Part_Name_HI} className="w-full bg-slate-50 border border-slate-200 rounded p-2 text-sm" />
              </div>
            </div>
          </div>

          {/* Section 2: BLO Details */}
          <div>
            <h4 className="text-emerald-700 font-bold border-b pb-2 mb-4 uppercase text-xs tracking-widest">BLO Details</h4>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="space-y-1">
                <label className="text-xs font-semibold text-slate-500">BLO Name</label>
                <input 
                  disabled={isLocked}
                  value={editForm.BLO_Name} 
                  onChange={e => setEditForm({...editForm, BLO_Name: e.target.value})}
                  className="w-full border border-slate-300 rounded p-2 text-sm focus:ring-2 focus:ring-emerald-500 outline-none" 
                />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-semibold text-slate-500">Gender</label>
                <select 
                  disabled={isLocked}
                  value={editForm.Gender} 
                  onChange={e => setEditForm({...editForm, Gender: e.target.value as any})}
                  className="w-full border border-slate-300 rounded p-2 text-sm"
                >
                  <option>Male</option>
                  <option>Female</option>
                  <option>Other</option>
                </select>
              </div>
              <div className="space-y-1">
                <label className="text-xs font-semibold text-slate-500">Mobile</label>
                <input 
                  disabled={isLocked}
                  value={editForm.Mobile} 
                  onChange={e => setEditForm({...editForm, Mobile: e.target.value})}
                  className="w-full border border-slate-300 rounded p-2 text-sm" 
                />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-semibold text-slate-500">EPIC No.</label>
                <input 
                  disabled={isLocked}
                  value={editForm.EPIC} 
                  onChange={e => setEditForm({...editForm, EPIC: e.target.value})}
                  className="w-full border border-slate-300 rounded p-2 text-sm" 
                />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-semibold text-slate-500">Designation</label>
                <input 
                  disabled={isLocked}
                  value={editForm.Designation} 
                  onChange={e => setEditForm({...editForm, Designation: e.target.value})}
                  className="w-full border border-slate-300 rounded p-2 text-sm" 
                />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-semibold text-slate-500">Department</label>
                <input 
                  disabled={isLocked}
                  value={editForm.Department} 
                  onChange={e => setEditForm({...editForm, Department: e.target.value})}
                  className="w-full border border-slate-300 rounded p-2 text-sm" 
                />
              </div>
            </div>
          </div>

          {/* Section 3: Account Details */}
          <div>
            <h4 className="text-emerald-700 font-bold border-b pb-2 mb-4 uppercase text-xs tracking-widest">Account Details</h4>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1 relative">
                <label className="text-xs font-semibold text-slate-500">IFSC Code (Search Facility)</label>
                <div className="flex gap-2">
                  <input 
                    disabled={isLocked}
                    value={editForm.IFSC_Code} 
                    onChange={e => handleIFSCChange(e.target.value)}
                    placeholder="Enter 11 digit IFSC"
                    className="flex-1 border border-slate-300 rounded p-2 text-sm" 
                  />
                  {isSearching && <span className="absolute right-3 top-9 text-xs text-emerald-600 animate-pulse">Searching...</span>}
                </div>
                <div className="text-[10px] text-slate-400 mt-1 italic">
                  {banks.find(b => b.Bank_ID === editForm.Bank_ID)?.Bank_Name || 'Bank not found'} - {branches.find(br => br.Branch_ID === editForm.Branch_ID)?.Branch_Name || 'Branch not found'}
                </div>
              </div>
              <div className="space-y-1">
                <label className="text-xs font-semibold text-slate-500">Account Number</label>
                <input 
                  disabled={isLocked}
                  value={editForm.Account_Number} 
                  onChange={e => setEditForm({...editForm, Account_Number: e.target.value})}
                  className="w-full border border-slate-300 rounded p-2 text-sm" 
                />
              </div>
              <div className="space-y-1 col-span-1 md:col-span-2">
                <label className="text-xs font-semibold text-slate-500">Upload Passbook (PDF/JPG)</label>
                <input 
                  disabled={isLocked}
                  type="file" 
                  accept="image/*,application/pdf"
                  onChange={handleFileChange}
                  className="w-full text-sm text-slate-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-emerald-50 file:text-emerald-700 hover:file:bg-emerald-100" 
                />
                {editForm.Account_Passbook_Doc && (
                  <div className="mt-2">
                    <span className="text-xs text-emerald-600 font-medium">✓ Document uploaded</span>
                  </div>
                )}
              </div>
            </div>
          </div>

          <div className="flex justify-end space-x-3 pt-6 border-t">
            <button 
              type="button"
              onClick={() => setSelectedBLO(null)}
              className="px-6 py-2 border border-slate-300 rounded-lg text-slate-600 hover:bg-slate-50"
            >
              Cancel
            </button>
            <button 
              disabled={isLocked}
              type="submit"
              className="px-6 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 shadow-md disabled:opacity-50"
            >
              Save Changes
            </button>
          </div>
        </form>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-800">Account Entry Module</h2>
        <span className="text-sm text-slate-500">{filteredAccounts.length} Records found</span>
