                    <p className="font-bold text-slate-900">{blo.BLO_Name}</p>
                    <p className="text-xs text-slate-500">AC: {blo.AC_No}, Part: {blo.Part_No}</p>
                  </div>
                  <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase ${
                    blo.Verified === 'yes' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                  }`}>
                    {blo.Verified === 'yes' ? 'Verified' : 'Pending'}
