import React, { useState, useEffect, useCallback } from 'react';
import { User, BLOAccount, Bank, BankBranch, AppState, UserType } from './types';
import { getStoredData, saveData } from './services/dataService';
import Login from './pages/Login';
import Dashboard from './pages/Dashboard';
import AccountEntry from './pages/AccountEntry';
import Verification from './pages/Verification';
import Sidebar from './components/Sidebar';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    currentUser: null,
    accounts: [],
    banks: [],
    branches: [],
    users: []
  });

  const [currentPage, setCurrentPage] = useState('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isInitialized, setIsInitialized] = useState(false);

  // Initialize data once
  useEffect(() => {
    const data = getStoredData();
    setState(prev => ({
      ...prev,
      ...data
    }));
    setIsInitialized(true);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleLogin = (user: User) => {
    setState(prev => ({ ...prev, currentUser: user }));
    setCurrentPage('dashboard');
  };

  const handleLogout = () => {
    setState(prev => ({ ...prev, currentUser: null }));
  };

  const updateAccount = useCallback((updated: BLOAccount, newBank?: Bank, newBranch?: BankBranch) => {
    setState(prev => {
      const nextAccounts = prev.accounts.map(a => a.BLO_ID === updated.BLO_ID ? { ...updated, T_STMP_UPD: new Date().toISOString() } : a);
      let nextBanks = prev.banks;
      let nextBranches = prev.branches;

      if (newBank) {
        if (!nextBanks.find(b => b.Bank_ID === newBank.Bank_ID)) {
          nextBanks = [...nextBanks, newBank];
        }
      }
      if (newBranch) {
        if (!nextBranches.find(br => br.Branch_ID === newBranch.Branch_ID)) {
          nextBranches = [...nextBranches, newBranch];
        }
      }

      saveData('blo_accounts', nextAccounts);
      saveData('blo_banks', nextBanks);
      saveData('blo_branches', nextBranches);

      return {
        ...prev,
        accounts: nextAccounts,
        banks: nextBanks,
        branches: nextBranches
      };
    });
  }, []);

  const handleVerify = useCallback((bloId: string, verified: 'yes' | 'no') => {
    setState(prev => {
      const nextAccounts = prev.accounts.map(a => 
        a.BLO_ID === bloId ? { ...a, Verified: verified, T_STMP_UPD: new Date().toISOString() } : a
      );
      saveData('blo_accounts', nextAccounts);
      return { ...prev, accounts: nextAccounts };
    });
  }, []);

  if (!isInitialized) return <div className="min-h-screen flex items-center justify-center bg-slate-50">Loading...</div>;

  if (!state.currentUser) {
    return <Login users={state.users} onLogin={handleLogin} />;
  }

  const renderContent = () => {
    switch (currentPage) {
      case 'dashboard':
        return <Dashboard user={state.currentUser!} accounts={state.accounts} />;
      case 'entry':
        return (
          <AccountEntry 
            user={state.currentUser!} 
            accounts={state.accounts} 
            banks={state.banks} 
            branches={state.branches}
            onUpdate={updateAccount}
          />
        );
      case 'verification':
        return (
          <Verification 
            user={state.currentUser!} 
            accounts={state.accounts}
            banks={state.banks} 
            branches={state.branches}
            onVerify={handleVerify}
          />
        );
      default:
        return <Dashboard user={state.currentUser!} accounts={state.accounts} />;
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex">
      <Sidebar 
        user={state.currentUser!} 
        currentPage={currentPage} 
        onNavigate={setCurrentPage} 
        isOpen={isSidebarOpen}
        setIsOpen={setIsSidebarOpen}
        onLogout={handleLogout}
      />

      <div className="flex-1 md:ml-64 flex flex-col">
        {/* Top bar for mobile */}
        <header className="md:hidden bg-slate-900 text-white p-4 flex justify-between items-center sticky top-0 z-10">
          <h1 className="text-lg font-bold">BLO Portal</h1>
          <button 
            onClick={() => setIsSidebarOpen(true)}
            className="p-2 rounded bg-slate-800"
          >
            ☰
          </button>
        </header>

        <main className="p-4 md:p-8 max-w-7xl mx-auto w-full">
          {renderContent()}
        </main>
      </div>
    </div>
  );
};

export default App;

