import React, { useState } from 'react';
import { BLOAccount, User, UserType, Bank, BankBranch } from '../types';

interface VerificationProps {
  user: User;
  accounts: BLOAccount[];
  banks: Bank[];
  branches: BankBranch[];
  onVerify: (bloId: string, verified: 'yes' | 'no') => void;
}

const Verification: React.FC<VerificationProps> = ({ user, accounts, banks, branches, onVerify }) => {
  const [selectedBLO, setSelectedBLO] = useState<BLOAccount | null>(null);
  const isAdmin = user.User_Type === UserType.ADMIN;

  const filteredAccounts = user.User_Type === UserType.ADMIN 
    ? accounts 
    : accounts.filter(a => a.User_ID === user.User_ID);

  const handleVerifyToggle = (blo: BLOAccount) => {
    if (blo.Verified === 'yes' && !isAdmin) {
      alert("Only administrators can un-verify records.");
      return;
    }
    const nextState = blo.Verified === 'yes' ? 'no' : 'yes';
    onVerify(blo.BLO_ID, nextState);
    if (selectedBLO?.BLO_ID === blo.BLO_ID) {
      setSelectedBLO({...blo, Verified: nextState});
    }
  };

  return (
    <div className="container-fluid py-2">
      <div className="row g-4">
        <div className={`col-12 col-lg-4 ${selectedBLO ? 'd-none d-lg-block' : ''}`}>
          <div className="d-flex justify-content-between align-items-center mb-4">
            <h3 className="fw-bold mb-0">Verification</h3>
          </div>
          <div className="card shadow-sm border-0 overflow-hidden">
            <div className="list-group list-group-flush">
              {filteredAccounts.map(blo => (
                <button
                  key={blo.BLO_ID}
                  onClick={() => setSelectedBLO(blo)}
                  className={`list-group-item list-group-item-action p-4 border-0 border-bottom ${selectedBLO?.BLO_ID === blo.BLO_ID ? 'bg-primary-subtle' : ''}`}
                >
                  <div className="d-flex justify-content-between align-items-start">
                    <div>
                      <h6 className="fw-bold mb-1">{blo.BLO_Name}</h6>
                      <p className="small text-muted mb-0">Part {blo.Part_No} | {blo.AC_Name}</p>
                    </div>
                    {blo.Verified === 'yes' ? (
                      <i className="bi bi-check-circle-fill text-success fs-5"></i>
                    ) : (
                      <i className="bi bi-clock-history text-warning fs-5"></i>
                    )}
                  </div>
                </button>
              ))}
            </div>
          </div>
        </div>

        {selectedBLO ? (
          <div className="col-12 col-lg-8">
            <div className="card shadow-lg border-0 h-100">
              <div className="card-header bg-dark text-white p-4 d-flex justify-content-between align-items-center">
                <h5 className="mb-0 fw-bold">Verification Workbench</h5>
                <button onClick={() => setSelectedBLO(null)} className="btn btn-sm btn-outline-light d-lg-none">Close</button>
              </div>
              <div className="row g-0 flex-grow-1">
                {/* PDF/Image Preview */}
                <div className="col-12 col-md-6 bg-light d-flex flex-column border-end" style={{ minHeight: '500px' }}>
                  <div className="p-3 bg-secondary bg-opacity-10 fw-bold small text-muted text-uppercase border-bottom">Document Preview</div>
                  <div className="flex-grow-1 p-3 d-flex align-items-center justify-content-center">
                    {selectedBLO.Account_Passbook_Doc ? (
                      selectedBLO.Account_Passbook_Doc.startsWith('data:application/pdf') ? (
                        <embed src={selectedBLO.Account_Passbook_Doc} className="w-100 h-100 rounded" />
                      ) : (
                        <img src={selectedBLO.Account_Passbook_Doc} alt="Passbook" className="img-fluid rounded shadow-sm" />
                      )
                    ) : (
