import React, { useState, useEffect, useCallback } from 'react';
import { User, BLOAccount, Bank, BankBranch, AppState, Department, Designation } from './types';
import { fetchAllData, updateAccountOnSheet, updateVerificationOnSheet, addBankOnSheet, addBranchOnSheet } from './services/dataService';
import Login from './pages/Login';
import Dashboard from './pages/Dashboard';
import AccountEntry from './pages/AccountEntry';
import Verification from './pages/Verification';
import Sidebar from './components/Sidebar';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    currentUser: null,
    accounts: [],
    banks: [],
    branches: [],
    users: [],
    departments: [],
    designations: []
  });

  const [currentPage, setCurrentPage] = useState('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isInitialized, setIsInitialized] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const loadData = async () => {
    setIsLoading(true);
    try {
      const data = await fetchAllData();
      setState(prev => ({ ...prev, ...data }));
    } catch (error) {
      console.error("Could not load data:", error);
      alert("Error connecting to Google Sheets. Check console and API_URL config.");
    } finally {
      setIsLoading(false);
      setIsInitialized(true);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const handleLogin = (user: User) => {
    setState(prev => ({ ...prev, currentUser: user }));
    setCurrentPage('dashboard');
  };

  const handleLogout = () => {
    setState(prev => ({ ...prev, currentUser: null }));
  };

  const updateAccount = useCallback(async (updated: BLOAccount, newBank?: Bank, newBranch?: BankBranch) => {
    setIsLoading(true);
    try {
      if (newBank) await addBankOnSheet(newBank);
      if (newBranch) await addBranchOnSheet(newBranch);

      const success = await updateAccountOnSheet(updated);
      if (success) {
        // Refresh local state
        await loadData();
        alert("Record updated successfully in Google Sheets.");
      } else {
        alert("Failed to update record.");
      }
    } catch (e) {
      alert("Operation failed.");
    } finally {
      setIsLoading(false);
    }
  }, []);

  const handleVerify = useCallback(async (bloId: string, verified: 'yes' | 'no') => {
    setIsLoading(true);
    try {
      const success = await updateVerificationOnSheet(bloId, verified);
      if (success) {
        await loadData();
      } else {
        alert("Verification update failed.");
      }
    } catch (e) {
      alert("Operation failed.");
    } finally {
      setIsLoading(false);
    }
  }, []);

  if (!isInitialized) {
    return (
      <div className="min-vh-100 d-flex flex-column align-items-center justify-content-center bg-light">
        <div className="spinner-border text-primary mb-3" role="status"></div>
        <div className="fw-bold text-muted">Connecting to Google Sheets...</div>
      </div>
    );
  }

  if (!state.currentUser) {
    return <Login users={state.users} onLogin={handleLogin} />;
  }

  const renderContent = () => {
    switch (currentPage) {
      case 'dashboard':
        return <Dashboard user={state.currentUser!} accounts={state.accounts} />;
      case 'entry':
        return (
          <AccountEntry 
            user={state.currentUser!} 
            accounts={state.accounts} 
            banks={state.banks} 
            branches={state.branches}
            departments={state.departments}
            designations={state.designations}
            onUpdate={updateAccount}
          />
        );
      case 'verification':
        return (
          <Verification 
            user={state.currentUser!} 
            accounts={state.accounts}
            banks={state.banks} 
            branches={state.branches}
            departments={state.departments}
            designations={state.designations}
            onVerify={handleVerify}
          />
        );
      default:
        return <Dashboard user={state.currentUser!} accounts={state.accounts} />;
    }
  };

  return (
    <div className="app-container">
      {isLoading && (
        <div className="position-fixed top-0 start-0 w-100 h-100 d-flex align-items-center justify-content-center bg-white bg-opacity-75 z-3" style={{ zIndex: 9999 }}>
          <div className="text-center">
            <div className="spinner-border text-primary" role="status"></div>
            <p className="mt-2 fw-bold text-primary">Synchronizing...</p>
          </div>
        </div>
      )}

      <Sidebar 
        user={state.currentUser!} 
        currentPage={currentPage} 
        onNavigate={setCurrentPage} 
        isOpen={isSidebarOpen}
        setIsOpen={setIsSidebarOpen}
        onLogout={handleLogout}
      />

      <div className="main-content">
        <div className="d-lg-none bg-white shadow-sm p-3 mb-4 rounded-3 d-flex justify-content-between align-items-center">
          <div className="d-flex align-items-center">
            <div className="bg-primary rounded-2 p-1 me-2">
              <i className="bi bi-shield-check text-white fs-5"></i>
            </div>
            <h5 className="mb-0 fw-bold">BLO PORTAL</h5>
          </div>
          <button className="btn btn-light" onClick={() => setIsSidebarOpen(true)}>
            <i className="bi bi-list fs-4"></i>
          </button>
        </div>

        {renderContent()}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { BLOAccount, User, UserType, Bank, BankBranch, Department, Designation } from '../types';
import { searchIFSCViaGemini } from '../services/geminiService';

interface AccountEntryProps {
  user: User;
  accounts: BLOAccount[];
  banks: Bank[];
  branches: BankBranch[];
  departments: Department[];
  designations: Designation[];
  onUpdate: (updated: BLOAccount, newBank?: Bank, newBranch?: BankBranch) => void;
}

const AccountEntry: React.FC<AccountEntryProps> = ({ user, accounts, banks, branches, departments, designations, onUpdate }) => {
  const [selectedBLO, setSelectedBLO] = useState<BLOAccount | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const [editForm, setEditForm] = useState<BLOAccount | null>(null);

  const [searchFeedback, setSearchFeedback] = useState<{ type: 'success' | 'error' | 'info' | 'none', message: string }>({ type: 'none', message: '' });
  const [stagedBank, setStagedBank] = useState<Bank | null>(null);
  const [stagedBranch, setStagedBranch] = useState<BankBranch | null>(null);

  // Track the last searched IFSC to avoid redundant auto-searches
  const lastSearchedRef = useRef<string>('');

  const filteredAccounts = user.User_Type === UserType.ADMIN 
    ? accounts 
    : accounts.filter(a => a.User_ID === user.User_ID);

  const handleEdit = (blo: BLOAccount) => {
    setSelectedBLO(blo);
    setEditForm({ ...blo });
    setSearchFeedback({ type: 'none', message: '' });
    setStagedBank(null);
    setStagedBranch(null);
    lastSearchedRef.current = blo.IFSC_Code || '';
  };

  const triggerIFSCSearch = async (ifscCode: string) => {
    if (!ifscCode || ifscCode.length !== 11) {
      setSearchFeedback({ type: 'error', message: 'Please enter a valid 11-digit IFSC code.' });
      return;
    }

    setIsSearching(true);
    setSearchFeedback({ type: 'none', message: '' });
    setStagedBank(null);
    setStagedBranch(null);
    lastSearchedRef.current = ifscCode;

    // 1. Check local sheet data FIRST
    const localBranch = branches.find(br => br.IFSC_Code.toUpperCase() === ifscCode.toUpperCase());
    if (localBranch) {
      setEditForm(prev => prev ? ({
        ...prev,
        Bank_ID: localBranch.Bank_ID,
        Branch_ID: localBranch.Branch_ID
      }) : null);

      setSearchFeedback({ type: 'success', message: 'Bank details found in current directory.' });
      setIsSearching(false);
      return;
    }

    // 2. If not found in local data, proceed to Gemini search for discovery
    try {
      const result = await searchIFSCViaGemini(ifscCode);
      if (result) {
        // Normalize names for comparison
        const normalizedBankName = result.bankName.trim().toLowerCase();

        let bank = banks.find(b => b.Bank_Name.toLowerCase() === normalizedBankName);

        const newBankObj: Bank | undefined = !bank ? {
          Bank_ID: 'B_' + Date.now(),
          Bank_Name: result.bankName,
          T_STMP_ADD: new Date().toISOString(),
          T_STMP_UPD: new Date().toISOString()
        } : undefined;

        const targetBankId = bank ? bank.Bank_ID : newBankObj!.Bank_ID;

        const newBranchObj: BankBranch = {
          Branch_ID: 'BR_' + Date.now(),
          Branch_Name: result.branchName,
          IFSC_Code: result.ifsc.toUpperCase(),
          Bank_ID: targetBankId,
          T_STMP_ADD: new Date().toISOString(),
          T_STMP_UPD: new Date().toISOString()
        };

        setEditForm(prev => prev ? ({
          ...prev,
          IFSC_Code: result.ifsc.toUpperCase(),
          Bank_ID: targetBankId,
          Branch_ID: newBranchObj.Branch_ID
        }) : null);

        if (newBankObj) setStagedBank(newBankObj);
        setStagedBranch(newBranchObj);

        setSearchFeedback({ 
          type: 'info', 
          message: `Discovered new details! Bank: ${result.bankName}, Branch: ${result.branchName}. This will be added to the directory upon save.` 
        });
      } else {
        setSearchFeedback({ type: 'error', message: 'Could not find bank details for this IFSC code. Please verify the code.' });
      }
    } catch (err) {
      setSearchFeedback({ type: 'error', message: 'Search failed. Please check your internet connection.' });
    } finally {
      setIsSearching(false);
    }
  };

  // Automatic search when IFSC reaches 11 characters
  useEffect(() => {
    if (editForm && editForm.IFSC_Code.length === 11 && editForm.IFSC_Code !== lastSearchedRef.current) {
      triggerIFSCSearch(editForm.IFSC_Code);
    }
  }, [editForm?.IFSC_Code]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && editForm) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setEditForm({ ...editForm, Account_Passbook_Doc: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editForm) {
      if (!editForm.Account_Number || !editForm.IFSC_Code) {
        alert("Account Number and IFSC Code are mandatory.");
        return;
      }

      onUpdate(editForm, stagedBank || undefined, stagedBranch || undefined);
      setSelectedBLO(null);
      setEditForm(null);
      setStagedBank(null);
      setStagedBranch(null);
    }
  };

  if (selectedBLO && editForm) {
    const isLocked = editForm.Verified === 'yes' && user.User_Type !== UserType.ADMIN;

    const currentBank = banks.find(b => b.Bank_ID === editForm.Bank_ID) || (stagedBank?.Bank_ID === editForm.Bank_ID ? stagedBank : null);
    const currentBranch = branches.find(br => br.Branch_ID === editForm.Branch_ID) || (stagedBranch?.Branch_ID === editForm.Branch_ID ? stagedBranch : null);

    return (
      <div className="container-fluid py-2">
        <div className="card shadow-lg border-0 overflow-hidden">
          <div className="card-header bg-primary text-white p-4 d-flex justify-content-between align-items-center">
            <h5 className="mb-0 fw-bold d-flex align-items-center">
              <i className="bi bi-bank2 me-3 fs-4"></i>
              Manage Bank Account: {selectedBLO.BLO_Name}
            </h5>
            <button onClick={() => setSelectedBLO(null)} className="btn-close btn-close-white"></button>
          </div>
          <div className="card-body p-4 bg-light-subtle">
            <form onSubmit={handleSubmit}>
              {isLocked && (
                <div className="alert alert-warning mb-4 shadow-sm border-0 d-flex align-items-center">
                  <i className="bi bi-lock-fill fs-4 me-3"></i>
                  <div>This record is <strong>Verified</strong>. Changes are restricted.</div>
                </div>
              )}

              {/* 1. Assembly Details Section */}
              <div className="card border-0 shadow-sm mb-4">
                <div className="card-body p-4">
