                          <div className="fw-bold text-dark mb-1">
                            {designations.find(d => d.Desg_ID === selectedBLO.Desg_ID)?.Desg_Name || 'Unknown Designation'}
                          </div>
                          <div className="small text-secondary">
                            {departments.find(d => d.Dept_ID === selectedBLO.Dept_ID)?.Dept_Name || 'Unknown Department'}
                          </div>
