                    <div className="card border-0 bg-secondary bg-opacity-10 p-3 mb-4">
                      <div className="row g-2">
                        <div className="col-6">
                          <label className="extra-small text-muted text-uppercase fw-bold" style={{fontSize: '0.65rem'}}>IFSC Code</label>
