/**
 * BLO Account Management System - Google Sheets Backend
 * Sheets expected: User, BLO_Account, Bank, Bank_Branch, Department, Designation
 */

const SPREADSHEET_ID = '199EWhTKl3E1MxSSL2-xFFIHrvhKJnADLCtLyWI4pSMc';
const TARGET_FOLDER_ID = '1kOZQqX8bBNLswS-ogfmmL0-dnvPjODPv';

function doGet(e) {
  if (e.parameter.check === 'true') {
    return ContentService.createTextOutput(JSON.stringify(checkConfig()))
      .setMimeType(ContentService.MimeType.JSON);
  }

  const data = {
    users: getSheetData('User'),
    accounts: getSheetData('BLO_Account'),
    banks: getSheetData('Bank'),
    branches: getSheetData('Bank_Branch'),
    departments: getSheetData('Department'),
    designations: getSheetData('Designation')
  };

  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  try {
    const params = JSON.parse(e.postData.contents);
    const action = params.action;
    const payload = params.payload;

    let result = { success: false };

    if (action === 'updateAccount') {
      result = updateRecord('BLO_Account', 'BLO_ID', payload.BLO_ID, payload);
    } else if (action === 'addBank') {
      result = addRecord('Bank', payload);
    } else if (action === 'addBranch') {
      result = addRecord('Bank_Branch', payload);
    } else if (action === 'verifyAccount') {
      result = updateRecord('BLO_Account', 'BLO_ID', payload.BLO_ID, { Verified: payload.Verified });
    } else if (action === 'checkConfig') {
      result = checkConfig();
    }

    return ContentService.createTextOutput(JSON.stringify(result))
      .setMimeType(ContentService.MimeType.JSON);
  } catch (error) {
    console.error("Critical doPost Error: " + error.toString());
    return ContentService.createTextOutput(JSON.stringify({ 
      success: false, 
      error: "Critical Error: " + error.toString() 
    })).setMimeType(ContentService.MimeType.JSON);
  }
}

function checkConfig() {
  const reports = {
    spreadsheet: { status: 'Checking...', id: SPREADSHEET_ID },
    folder: { status: 'Checking...', id: TARGET_FOLDER_ID },
    success: true,
    timestamp: new Date().toISOString()
  };

  try {
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    reports.spreadsheet.status = 'OK - Access granted. Name: ' + ss.getName();
    reports.spreadsheet.sheets = ss.getSheets().map(s => s.getName());
  } catch (e) {
    reports.spreadsheet.status = 'ERROR: ' + e.toString();
    reports.success = false;
  }

  try {
    const folder = DriveApp.getFolderById(TARGET_FOLDER_ID);
    reports.folder.status = 'OK - Access granted. Name: ' + folder.getName();
    const tempFile = folder.createFile('diag_test_' + Date.now() + '.txt', 'Testing permissions...');
    reports.folder.writePermission = 'OK - File creation successful. URL: ' + tempFile.getUrl();
    tempFile.setTrashed(true);
  } catch (e) {
    reports.folder.status = 'ERROR: ' + e.toString();
    reports.success = false;
  }

  return reports;
}

function getSheetData(sheetName) {
  try {
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const sheet = ss.getSheetByName(sheetName);
    if (!sheet) return [];

    const values = sheet.getDataRange().getValues();
    if (values.length <= 1) return [];

    const headers = values[0];
    const data = [];

    for (let i = 1; i < values.length; i++) {
      const obj = {};
      for (let j = 0; j < headers.length; j++) {
        obj[headers[j]] = values[i][j];
      }
      data.push(obj);
    }
    return data;
  } catch (e) {
    console.error("Get Sheet Data Error [" + sheetName + "]: " + e.toString());
    return [];
  }
}

function updateRecord(sheetName, idColumnName, idValue, updateObj) {
  try {
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const sheet = ss.getSheetByName(sheetName);
    if (!sheet) return { success: false, message: 'Sheet "' + sheetName + '" not found' };

    const data = sheet.getDataRange().getValues();
    const headers = data[0];
    const idColIndex = headers.indexOf(idColumnName);

    if (idColIndex === -1) return { success: false, message: 'ID Column "' + idColumnName + '" not found' };

    for (let i = 1; i < data.length; i++) {
      if (data[i][idColIndex] == idValue) {
        updateObj['T_STMP_UPD'] = new Date().toISOString();

        // Handle file upload and deletion of old file
        if (updateObj['Account_Passbook_Doc'] && updateObj['Account_Passbook_Doc'].startsWith('data:')) {
          const colIdxDoc = headers.indexOf('Account_Passbook_Doc');
          const oldDocUrl = colIdxDoc !== -1 ? data[i][colIdxDoc] : '';

          // Delete old file if it exists and is a Drive URL
          if (oldDocUrl && oldDocUrl.indexOf('drive.google.com') !== -1) {
            try {
              const fileId = extractFileIdFromUrl(oldDocUrl);
              if (fileId) {
                DriveApp.getFileById(fileId).setTrashed(true);
                console.log("Trashed old file: " + fileId);
              }
            } catch (err) {
              console.warn("Could not delete old file: " + err.toString());
            }
          }

          const getVal = (key) => {
            if (updateObj[key] !== undefined && updateObj[key] !== null && updateObj[key] !== '') return updateObj[key];
            const colIdx = headers.indexOf(key);
            return colIdx !== -1 ? data[i][colIdx] : '';
          };

          const acNo = getVal('AC_No');
          const partNo = getVal('Part_No');
          const mobile = getVal('Mobile');
          const fileName = (acNo || 'NA') + "_" + (partNo || 'NA') + "_" + (mobile || 'NA');

          try {
            const driveUrl = uploadBase64ToDrive(updateObj['Account_Passbook_Doc'], fileName);
            if (driveUrl) {
              updateObj['Account_Passbook_Doc'] = driveUrl;
            }
          } catch (e) {
            return { success: false, message: 'Google Drive Upload Error: ' + e.toString() };
          }
        }

        for (let key in updateObj) {
          const colIndex = headers.indexOf(key);
          if (colIndex !== -1) {
            sheet.getRange(i + 1, colIndex + 1).setValue(updateObj[key]);
          }
        }
        return { success: true };
      }
    }
    return { success: false, message: 'Record with ID ' + idValue + ' not found' };
  } catch (e) {
    return { success: false, message: 'Update Error: ' + e.toString() };
  }
}

function extractFileIdFromUrl(url) {
  const match = url.match(/[-\w]{25,}/);
  return match ? match[0] : null;
}

function uploadBase64ToDrive(base64Data, fileName) {
  const parts = base64Data.split(',');
  const meta = parts[0];
  const base64Content = parts[1];
  const mimeType = meta.match(/:(.*?);/)[1];
  const cleanContent = base64Content.replace(/\s/g, '');
  const decodedData = Utilities.base64Decode(cleanContent);

  let extension = '';
  if (mimeType.includes('pdf')) extension = '.pdf';
  else if (mimeType.includes('jpeg')) extension = '.jpg';
  else if (mimeType.includes('png')) extension = '.png';

  const blob = Utilities.newBlob(decodedData, mimeType, fileName + extension);
  const folder = DriveApp.getFolderById(TARGET_FOLDER_ID);
  const file = folder.createFile(blob);

  try {
    file.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);
  } catch (e) {}

  return file.getUrl();
}

function addRecord(sheetName, recordObj) {
  try {
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const sheet = ss.getSheetByName(sheetName);
    if (!sheet) return { success: false, message: 'Sheet "' + sheetName + '" not found' };

    const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
    const newRow = new Array(headers.length).fill('');

    recordObj['T_STMP_ADD'] = new Date().toISOString();
    recordObj['T_STMP_UPD'] = new Date().toISOString();

    for (let key in recordObj) {
      const colIndex = headers.indexOf(key);
      if (colIndex !== -1) {
        newRow[colIndex] = recordObj[key];
      }
    }

    sheet.appendRow(newRow);
    return { success: true };
  } catch (e) {
    return { success: false, message: 'Add Record Error: ' + e.toString() };
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { BLOAccount, User, UserType, Bank, BankBranch, Department, Designation } from '../types';
import { searchIFSCViaGemini } from '../services/geminiService';

interface AccountEntryProps {
  user: User;
  accounts: BLOAccount[];
  banks: Bank[];
  branches: BankBranch[];
  departments: Department[];
  designations: Designation[];
  onUpdate: (updated: BLOAccount, newBank?: Bank, newBranch?: BankBranch) => void;
}

const AccountEntry: React.FC<AccountEntryProps> = ({ user, accounts, banks, branches, departments, designations, onUpdate }) => {
  const [selectedBLO, setSelectedBLO] = useState<BLOAccount | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const [editForm, setEditForm] = useState<BLOAccount | null>(null);

  const [searchFeedback, setSearchFeedback] = useState<{ type: 'success' | 'error' | 'info' | 'none', message: string }>({ type: 'none', message: '' });
  const [stagedBank, setStagedBank] = useState<Bank | null>(null);
  const [stagedBranch, setStagedBranch] = useState<BankBranch | null>(null);

  const lastSearchedRef = useRef<string>('');

  const filteredAccounts = user.User_Type === UserType.ADMIN 
    ? accounts 
    : accounts.filter(a => String(a.User_ID).trim() === String(user.User_ID).trim());

  const getEntityLabel = (obj: any, preferredKeys: string[]): string => {
    if (!obj) return '---';
    for (const key of preferredKeys) {
      if (obj[key] !== undefined && obj[key] !== null && String(obj[key]).trim() !== '') {
        return String(obj[key]).trim();
      }
    }
    const keys = Object.keys(obj);
    const fallbackKey = keys.find(k => k.toLowerCase().includes('name') || k.toLowerCase().includes('designation') || k.toLowerCase().includes('department'));
    if (fallbackKey) return String(obj[fallbackKey]);
    return 'Unknown';
  };

  const getDeptName = (id: any) => {
    const dept = departments.find(d => String(d.Dept_ID).trim() === String(id).trim());
    return getEntityLabel(dept, ['Dept_Name', 'Department', 'Name']);
  };

  const getDesgName = (id: any) => {
    const desg = designations.find(d => String(d.Desg_ID).trim() === String(id).trim());
    return getEntityLabel(desg, ['Desg_Name', 'Designation', 'Name']);
  };

  const handleEdit = (blo: BLOAccount) => {
    setSelectedBLO(blo);
    setEditForm({ ...blo });
    setSearchFeedback({ type: 'none', message: '' });
    setStagedBank(null);
    setStagedBranch(null);
    lastSearchedRef.current = blo.IFSC_Code || '';
  };

  const triggerIFSCSearch = async (ifscCode: string) => {
    if (!ifscCode || ifscCode.length !== 11) {
      setSearchFeedback({ type: 'error', message: 'Please enter a valid 11-digit IFSC code.' });
      return;
    }

    setIsSearching(true);
    setSearchFeedback({ type: 'none', message: '' });
    setStagedBank(null);
    setStagedBranch(null);
    lastSearchedRef.current = ifscCode;

    const localBranch = branches.find(br => String(br.IFSC_Code).toUpperCase() === ifscCode.toUpperCase());
    if (localBranch) {
      setEditForm(prev => prev ? ({
        ...prev,
        Bank_ID: localBranch.Bank_ID,
        Branch_ID: localBranch.Branch_ID
      }) : null);

      setSearchFeedback({ type: 'success', message: 'Bank details found in current directory.' });
      setIsSearching(false);
      return;
    }

    try {
      const result = await searchIFSCViaGemini(ifscCode);
      if (result) {
        const normalizedBankName = result.bankName.trim().toLowerCase();
        let bank = banks.find(b => String(b.Bank_Name).toLowerCase() === normalizedBankName);

        const newBankObj: Bank | undefined = !bank ? {
          Bank_ID: 'B_' + Date.now(),
          Bank_Name: result.bankName,
          T_STMP_ADD: new Date().toISOString(),
          T_STMP_UPD: new Date().toISOString()
        } : undefined;

        const targetBankId = bank ? bank.Bank_ID : newBankObj!.Bank_ID;

        const newBranchObj: BankBranch = {
          Branch_ID: 'BR_' + Date.now(),
          Branch_Name: result.branchName,
          IFSC_Code: result.ifsc.toUpperCase(),
          Bank_ID: targetBankId,
          T_STMP_ADD: new Date().toISOString(),
          T_STMP_UPD: new Date().toISOString()
        };

        setEditForm(prev => prev ? ({
          ...prev,
          IFSC_Code: result.ifsc.toUpperCase(),
          Bank_ID: targetBankId,
          Branch_ID: newBranchObj.Branch_ID
        }) : null);

        if (newBankObj) setStagedBank(newBankObj);
        setStagedBranch(newBranchObj);

        setSearchFeedback({ 
          type: 'info', 
          message: `Discovered new details! Bank: ${result.bankName}, Branch: ${result.branchName}. This will be added to the directory upon save.` 
        });
      } else {
        setSearchFeedback({ type: 'error', message: 'Could not find bank details for this IFSC code. Please verify the code.' });
      }
    } catch (err) {
      setSearchFeedback({ type: 'error', message: 'Search failed. Please check your internet connection.' });
    } finally {
      setIsSearching(false);
    }
  };

  useEffect(() => {
    if (editForm && String(editForm.IFSC_Code).length === 11 && String(editForm.IFSC_Code) !== lastSearchedRef.current) {
      triggerIFSCSearch(editForm.IFSC_Code);
    }
  }, [editForm?.IFSC_Code]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && editForm) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setEditForm({ ...editForm, Account_Passbook_Doc: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleDeptChange = (deptId: string) => {
    if (editForm) {
      setEditForm({
        ...editForm,
        Dept_ID: String(deptId).trim(),
        Desg_ID: '' 
      });
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editForm) {
      if (!editForm.Account_Number || !editForm.IFSC_Code) {
        alert("Account Number and IFSC Code are mandatory.");
        return;
      }
      onUpdate(editForm, stagedBank || undefined, stagedBranch || undefined);
      setSelectedBLO(null);
      setEditForm(null);
      setStagedBank(null);
      setStagedBranch(null);
    }
  };

  if (selectedBLO && editForm) {
    const isLocked = editForm.Verified === 'yes' && user.User_Type !== UserType.ADMIN;
    const isFileNew = editForm.Account_Passbook_Doc && editForm.Account_Passbook_Doc.startsWith('data:');

    const currentBank = banks.find(b => String(b.Bank_ID).trim() === String(editForm.Bank_ID).trim()) || (stagedBank?.Bank_ID === editForm.Bank_ID ? stagedBank : null);
    const currentBranch = branches.find(br => String(br.Branch_ID).trim() === String(editForm.Branch_ID).trim()) || (stagedBranch?.Branch_ID === editForm.Branch_ID ? stagedBranch : null);

    const availableDesignations = designations.filter(d => 
      editForm.Dept_ID && 
      String(d.Dept_ID).trim() === String(editForm.Dept_ID).trim()
    );

    return (
      <div className="container-fluid py-2">
        <div className="card shadow-lg border-0 overflow-hidden">
          <div className="card-header bg-primary text-white p-4 d-flex justify-content-between align-items-center">
            <h5 className="mb-0 fw-bold d-flex align-items-center">
              <i className="bi bi-bank2 me-3 fs-4"></i>
              Manage Bank Account: {selectedBLO.BLO_Name}
            </h5>
            <button onClick={() => setSelectedBLO(null)} className="btn-close btn-close-white"></button>
          </div>
          <div className="card-body p-4 bg-light-subtle">
            <form onSubmit={handleSubmit}>
              {isLocked && (
                <div className="alert alert-warning mb-4 shadow-sm border-0 d-flex align-items-center">
                  <i className="bi bi-lock-fill fs-4 me-3"></i>
                  <div>This record is <strong>Verified</strong>. Changes are restricted.</div>
                </div>
              )}

              {/* 1. Assembly Details Section - VIEW ONLY */}
              <div className="card border-0 shadow-sm mb-4 bg-light">
                <div className="card-body p-4">
                  <h6 className="text-secondary fw-bold text-uppercase small mb-4 d-flex align-items-center">
