                <div className="card-body p-4">
                  <h6 className="text-primary fw-bold text-uppercase small mb-4 d-flex align-items-center">
                    <i className="bi bi-person-badge-fill me-2"></i>
                    BLO Details
                  </h6>
                  <div className="row g-3">
                    <div className="col-md-6">
                      <label className="form-label extra-small fw-bold text-muted">BLO Name</label>
                      <input disabled={isLocked} type="text" className="form-control form-control-sm" value={editForm.BLO_Name} onChange={e => setEditForm({...editForm, BLO_Name: e.target.value})} />
                    </div>
                    <div className="col-md-3">
                      <label className="form-label extra-small fw-bold text-muted">Gender</label>
                      <select disabled={isLocked} className="form-select form-select-sm" value={editForm.Gender} onChange={e => setEditForm({...editForm, Gender: e.target.value as any})}>
                        <option>Male</option>
                        <option>Female</option>
                        <option>Other</option>
                      </select>
                    </div>
                    <div className="col-md-3">
                      <label className="form-label extra-small fw-bold text-muted">Mobile</label>
                      <input disabled={isLocked} type="text" className="form-control form-control-sm" value={editForm.Mobile} onChange={e => setEditForm({...editForm, Mobile: e.target.value})} />
                    </div>

                    <div className="col-md-4">
                      <label className="form-label extra-small fw-bold text-muted">Department</label>
                      <select 
                        disabled={isLocked} 
                        className="form-select form-select-sm shadow-sm" 
                        value={editForm.Dept_ID} 
                        onChange={e => handleDeptChange(e.target.value)}
                      >
                        <option value="">Select Department</option>
                        {departments.map(d => (
                          <option key={String(d.Dept_ID)} value={String(d.Dept_ID)}>
                            {getEntityLabel(d, ['Dept_Name', 'Department', 'Name'])}
                          </option>
                        ))}
                      </select>
                    </div>

                    <div className="col-md-4">
                      <label className="form-label extra-small fw-bold text-muted">Designation</label>
                      <select 
                        disabled={isLocked || !editForm.Dept_ID} 
                        className="form-select form-select-sm shadow-sm" 
                        value={editForm.Desg_ID} 
                        onChange={e => setEditForm({...editForm, Desg_ID: e.target.value})}
                      >
                        <option value="">{editForm.Dept_ID ? (availableDesignations.length > 0 ? 'Select Designation' : 'No Designations Found') : 'Select Department First'}</option>
                        {availableDesignations.map(d => (
                          <option key={String(d.Desg_ID)} value={String(d.Desg_ID)}>
                            {getEntityLabel(d, ['Desg_Name', 'Designation', 'Name'])}
                          </option>
                        ))}
                      </select>
                    </div>

                    <div className="col-md-4">
                      <label className="form-label extra-small fw-bold text-muted">EPIC (Voter ID)</label>
                      <input disabled={isLocked} type="text" className="form-control form-control-sm" value={editForm.EPIC} onChange={e => setEditForm({...editForm, EPIC: e.target.value})} />
                    </div>
                  </div>
                </div>
              </div>

              {/* 3. Account Details Section */}
              <div className="card border-0 shadow-sm mb-5">
                <div className="card-body p-4 bg-white border-start border-primary border-5 rounded-end">
                  <h6 className="text-primary fw-bold text-uppercase small mb-4 d-flex align-items-center">
                    <i className="bi bi-credit-card-2-front me-2"></i>
                    Account Details
                  </h6>
                  <div className="row g-4">
                    <div className="col-md-6">
                      <div className="p-3 border rounded-3 bg-light">
                        <label className="form-label fw-bold text-dark mb-2">IFSC Code</label>
                        <div className="input-group input-group-lg shadow-sm">
                          <input 
                            disabled={isLocked} 
                            type="text" 
                            className="form-control fw-bold text-primary text-uppercase" 
                            placeholder="Enter 11-digit IFSC" 
                            maxLength={11}
                            value={editForm.IFSC_Code} 
                            onChange={e => setEditForm({...editForm, IFSC_Code: e.target.value.toUpperCase().trim()})} 
                          />
                          <button 
                            type="button" 
                            className="btn btn-primary px-4" 
                            onClick={() => triggerIFSCSearch(editForm.IFSC_Code)}
                            disabled={isSearching || isLocked}
                          >
                            {isSearching ? <i className="bi bi-arrow-repeat spin"></i> : <><i className="bi bi-search me-2"></i>Search</>}
                          </button>
                        </div>

                        {searchFeedback.type !== 'none' && (
                          <div className={`mt-2 small fw-bold text-${searchFeedback.type === 'error' ? 'danger' : searchFeedback.type === 'info' ? 'primary' : 'success'}`}>
                            {searchFeedback.message}
                          </div>
                        )}

                        <div className="mt-3 p-3 rounded bg-white border border-info-subtle shadow-sm">
                          <div className="small text-muted text-uppercase fw-bold mb-2" style={{fontSize: '0.65rem'}}>System Verification:</div>

                          {(currentBank || currentBranch) ? (
                            <>
                              <div className="fw-bold text-dark d-flex align-items-center">
                                {currentBank?.Bank_Name || '---'}
                                {(stagedBank || stagedBranch) && <span className="ms-2 badge bg-info extra-small text-uppercase" style={{fontSize: '0.55rem'}}>New Discovery</span>}
                              </div>
                              <div className="small text-secondary">{currentBranch?.Branch_Name || '---'}</div>
                            </>
                          ) : (
                            <div className="text-muted italic small">No record found. Type valid IFSC and click Search.</div>
                          )}
                        </div>
                      </div>
                    </div>
                    <div className="col-md-6">
                      <div className="p-3 border rounded-3 bg-light">
                        <label className="form-label fw-bold text-dark mb-2">Account Number</label>
                        <input 
                          disabled={isLocked} 
                          type="text" 
                          className="form-control form-control-lg shadow-sm fw-bold text-dark" 
                          placeholder="Enter Full Account Number"
                          value={editForm.Account_Number} 
                          onChange={e => setEditForm({...editForm, Account_Number: e.target.value.replace(/\D/g, '')})} 
                        />
                        <div className="form-text mt-2"><i className="bi bi-info-circle me-1"></i> Digits only. No spaces.</div>
                      </div>
                    </div>
                    <div className="col-12">
                      <label className="form-label small fw-bold text-secondary">Account Passbook Doc (Upload PDF/JPG)</label>
                      <input disabled={isLocked} type="file" className="form-control bg-white shadow-sm mb-3" onChange={handleFileChange} accept=".pdf,image/*" />

                      {editForm.Account_Passbook_Doc && (
                        <div className="mt-2">
                          <div className="p-3 border rounded bg-white shadow-sm mb-3">
                            <h6 className="fw-bold extra-small text-muted text-uppercase mb-3 d-flex align-items-center">
                              <i className="bi bi-eye me-2"></i>
                              Document Preview
                              {isFileNew && <span className="ms-auto badge bg-info">Live Preview</span>}
                            </h6>
                            <div className="bg-light rounded overflow-hidden d-flex align-items-center justify-content-center" style={{ minHeight: '300px', maxHeight: '500px' }}>
                              {editForm.Account_Passbook_Doc.startsWith('data:application/pdf') || (editForm.Account_Passbook_Doc.includes('drive.google.com') && editForm.Account_Passbook_Doc.toLowerCase().includes('.pdf')) ? (
                                <embed 
                                  src={editForm.Account_Passbook_Doc.includes('drive.google.com') ? editForm.Account_Passbook_Doc.replace('/view', '/preview') : editForm.Account_Passbook_Doc} 
                                  className="w-100" 
                                  style={{ height: '500px' }} 
                                />
                              ) : (
                                <img 
                                  src={editForm.Account_Passbook_Doc.includes('drive.google.com') ? editForm.Account_Passbook_Doc.replace('/view', '/preview') : editForm.Account_Passbook_Doc} 
                                  alt="Selected Passbook" 
                                  className="img-fluid"
                                  style={{ maxHeight: '500px' }}
                                />
                              )}
                            </div>
                          </div>

                          <div className="d-flex align-items-center gap-2">
                            {isFileNew ? (
                              <div className="alert alert-info py-2 px-3 small border-0 d-flex align-items-center mb-0 w-100 shadow-sm">
                                <i className="bi bi-cloud-arrow-up-fill fs-5 me-2"></i>
                                <span>New document selected. The old file on Drive will be replaced upon saving.</span>
                              </div>
                            ) : (
                              <div className="d-flex align-items-center gap-2">
                                <span className="badge bg-success px-3 py-2 shadow-sm"><i className="bi bi-check2-circle me-1"></i> Cloud Link Active</span>
                              </div>
                            )}
                          </div>
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              </div>

              <div className="mt-5 pt-4 border-top d-flex gap-3 justify-content-end align-items-center">
                <button type="button" onClick={() => setSelectedBLO(null)} className="btn btn-outline-secondary px-4">Cancel</button>
                <button type="submit" disabled={isLocked} className="btn btn-primary btn-lg px-5 shadow-sm fw-bold">
                  Save & Push to Cloud
                </button>
              </div>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="container-fluid py-2">
      <div className="d-flex flex-column flex-md-row justify-content-between align-items-md-center mb-4 gap-3">
        <div>
          <h3 className="fw-bold mb-1">BLO Bank Directory</h3>
          <p className="text-muted small mb-0">Update and manage bank account details for election personnel.</p>
        </div>
        <div className="d-flex align-items-center gap-2">
          <span className="badge bg-primary px-3 py-2">{filteredAccounts.length} Total Records</span>
        </div>
      </div>

      <div className="card border-0 shadow-sm overflow-hidden">
        <div className="table-responsive">
          <table className="table table-hover align-middle mb-0">
            <thead className="table-dark">
              <tr>
                <th className="py-3 px-4 fw-bold small">PART / AC</th>
                <th className="py-3 px-4 fw-bold small">BLO NAME / DEPT</th>
                <th className="py-3 px-4 fw-bold small bg-primary-subtle text-primary">ACCOUNT NUMBER</th>
                <th className="py-3 px-4 fw-bold small bg-primary-subtle text-primary">IFSC CODE</th>
                <th className="py-3 px-4 fw-bold small text-center">STATUS</th>
                <th className="py-3 px-4 fw-bold small text-end">ACTIONS</th>
              </tr>
            </thead>
            <tbody>
              {filteredAccounts.map(blo => (
                <tr key={blo.BLO_ID} className={blo.Verified === 'yes' ? 'table-success-subtle' : ''}>
                  <td className="px-4 py-3">
                    <div className="fw-bold text-dark">P-{blo.Part_No}</div>
                    <div className="extra-small text-muted">{blo.AC_Name}</div>
                  </td>
                  <td className="px-4 py-3">
                    <div className="fw-semibold text-primary">{blo.BLO_Name}</div>
                    <div className="extra-small fw-bold text-uppercase text-muted">
                      {getDesgName(blo.Desg_ID)} | {getDeptName(blo.Dept_ID)}
                    </div>
                  </td>
                  <td className="px-4 py-3 bg-light font-monospace">
                    {blo.Account_Number ? (
                      <span className="fw-bold text-dark">{blo.Account_Number}</span>
                    ) : (
                      <span className="text-danger small italic"><i className="bi bi-x-circle me-1"></i> Pending</span>
                    )}
                  </td>
                  <td className="px-4 py-3 bg-light font-monospace">
                    {blo.IFSC_Code ? (
                      <span className="fw-bold text-primary">{blo.IFSC_Code}</span>
                    ) : (
                      <span className="text-danger small italic">---</span>
                    )}
                  </td>
                  <td className="px-4 py-3 text-center">
                    <div className="d-flex flex-column align-items-center">
                      {blo.Verified === 'yes' ? (
                        <span className="badge bg-success-subtle text-success rounded-pill px-3">
                          <i className="bi bi-shield-check me-1"></i> Verified
                        </span>
                      ) : (
                        <span className="badge bg-warning-subtle text-warning-emphasis rounded-pill px-3">
                          Pending
                        </span>
                      )}
                      {blo.Account_Passbook_Doc && blo.Account_Passbook_Doc.startsWith('http') && (
                        <i className="bi bi-cloud-check text-success extra-small mt-1" title="Document Available"></i>
                      )}
                    </div>
                  </td>
                  <td className="px-4 py-3 text-end">
                    <button 
                      onClick={() => handleEdit(blo)} 
                      className={`btn btn-sm px-3 ${blo.Verified === 'yes' && user.User_Type !== UserType.ADMIN ? 'btn-outline-secondary' : 'btn-primary shadow-sm'}`}
                    >
                      <i className={`bi ${blo.Verified === 'yes' && user.User_Type !== UserType.ADMIN ? 'bi-eye' : 'bi-pencil'} me-1`}></i> 
                      {blo.Verified === 'yes' && user.User_Type !== UserType.ADMIN ? 'View' : 'Edit'}
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default AccountEntry;

import React, { useState, useEffect, useRef } from 'react';
import { BLOAccount, User, UserType, Bank, BankBranch, Department, Designation } from '../types';
import { searchIFSCViaGemini } from '../services/geminiService';

interface VerificationProps {
  user: User;
  accounts: BLOAccount[];
  banks: Bank[];
  branches: BankBranch[];
  departments: Department[];
  designations: Designation[];
  onVerify: (bloId: string, verified: 'yes' | 'no') => void;
  onUpdate?: (updated: BLOAccount, newBank?: Bank, newBranch?: BankBranch) => void;
}

const Verification: React.FC<VerificationProps> = ({ user, accounts, banks, branches, departments, designations, onVerify, onUpdate }) => {
  const [selectedBLO, setSelectedBLO] = useState<BLOAccount | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [editForm, setEditForm] = useState<BLOAccount | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const lastSearchedRef = useRef<string>('');

  const isAdmin = user.User_Type === UserType.ADMIN;

  const filteredAccounts = user.User_Type === UserType.ADMIN 
    ? accounts 
    : accounts.filter(a => String(a.User_ID).trim() === String(user.User_ID).trim());

  const getEntityLabel = (obj: any, preferredKeys: string[]): string => {
    if (!obj) return '---';
    for (const key of preferredKeys) {
      if (obj[key] !== undefined && obj[key] !== null && String(obj[key]).trim() !== '') {
        return String(obj[key]).trim();
      }
    }
    const keys = Object.keys(obj);
    const fallbackKey = keys.find(k => k.toLowerCase().includes('name') || k.toLowerCase().includes('designation') || k.toLowerCase().includes('department'));
    return fallbackKey ? String(obj[fallbackKey]) : 'Unknown';
  };

  const handleVerifyToggle = (blo: BLOAccount) => {
    if (blo.Verified === 'yes' && !isAdmin) {
      alert("Only administrators can un-verify records.");
      return;
    }
    const nextState = blo.Verified === 'yes' ? 'no' : 'yes';
    onVerify(blo.BLO_ID, nextState);
    if (selectedBLO?.BLO_ID === blo.BLO_ID) {
      setSelectedBLO({...blo, Verified: nextState});
    }
  };

  const startEditing = () => {
    if (!selectedBLO) return;
    setEditForm({ ...selectedBLO });
    lastSearchedRef.current = selectedBLO.IFSC_Code || '';
    setIsEditing(true);
  };

  const handleSaveEdit = async () => {
    if (!editForm || !onUpdate) return;
    onUpdate(editForm);
    setSelectedBLO(editForm);
    setIsEditing(false);
  };

  const triggerIFSCSearch = async (ifscCode: string) => {
    if (!ifscCode || ifscCode.length !== 11) return;
    setIsSearching(true);
    lastSearchedRef.current = ifscCode;
    const result = await searchIFSCViaGemini(ifscCode);
    if (result && editForm) {
      setEditForm({
        ...editForm,
        IFSC_Code: result.ifsc.toUpperCase()
      });
    }
    setIsSearching(false);
  };

  const renderDocumentViewer = (doc: string) => {
    if (!doc) return (
      <div className="text-center text-muted m-auto p-5">
        <i className="bi bi-file-earmark-excel fs-1 mb-3 d-block"></i>
        <p className="fw-bold">No Proof Document Uploaded</p>
      </div>
    );

    if (doc.includes('drive.google.com')) {
      const previewUrl = doc.replace('/view?usp=sharing', '/preview').replace('/view', '/preview');
      return (
        <iframe src={previewUrl} className="w-100 h-100 rounded shadow" frameBorder="0"></iframe>
      );
    }

    if (doc.startsWith('data:application/pdf')) {
      return <embed src={doc} className="w-100 h-100 rounded shadow" />;
    } else if (doc.startsWith('data:image')) {
      return (
        <img src={doc} alt="Passbook" className="img-fluid rounded shadow-lg m-auto" style={{maxHeight: '90%'}} />
      );
    }

    return (
      <div className="text-center p-4">
        <p>Format not viewable. <a href={doc} target="_blank" rel="noreferrer">Open Link</a></p>
      </div>
    );
  };

  return (
    <div className="container-fluid py-2">
      <div className="row g-4">
        <div className={`col-12 col-lg-4 ${selectedBLO ? 'd-none d-lg-block' : ''}`}>
          <div className="d-flex justify-content-between align-items-center mb-4">
            <h3 className="fw-bold mb-0">Verification Queue</h3>
          </div>
          <div className="card shadow-sm border-0 overflow-hidden">
            <div className="list-group list-group-flush" style={{maxHeight: '75vh', overflowY: 'auto'}}>
              {filteredAccounts.map(blo => (
                <button
                  key={blo.BLO_ID}
                  onClick={() => { setSelectedBLO(blo); setIsEditing(false); }}
                  className={`list-group-item list-group-item-action p-3 border-0 border-bottom ${selectedBLO?.BLO_ID === blo.BLO_ID ? 'bg-primary-subtle' : ''}`}
                >
                  <div className="d-flex justify-content-between align-items-start">
                    <div>
                      <h6 className="fw-bold mb-1">{blo.BLO_Name}</h6>
                      <p className="small text-muted mb-1">P-{blo.Part_No} | {blo.AC_Name}</p>
                    </div>
                    {blo.Verified === 'yes' ? (
                      <span className="badge bg-success rounded-circle p-1"><i className="bi bi-check text-white"></i></span>
                    ) : (
                      <span className="badge bg-warning-subtle text-warning border p-1 rounded-circle"><i className="bi bi-clock"></i></span>
                    )}
                  </div>
                </button>
              ))}
            </div>
          </div>
        </div>

        {selectedBLO ? (
          <div className="col-12 col-lg-8">
            <div className="card shadow-lg border-0 h-100 flex-column overflow-hidden">
              <div className="card-header bg-dark text-white p-4 d-flex justify-content-between align-items-center">
                <h5 className="mb-0 fw-bold d-flex align-items-center">
                  <i className="bi bi-search me-3 fs-4 text-warning"></i>
                  {isEditing ? 'Correcting Record' : 'Verification Workbench'}
                </h5>
                <button onClick={() => { setSelectedBLO(null); setIsEditing(false); }} className="btn btn-sm btn-outline-light d-lg-none">Close</button>
              </div>

              <div className="row g-0 flex-grow-1">
                <div className="col-12 col-md-7 bg-dark bg-opacity-10 d-flex flex-column border-end" style={{ minHeight: '600px' }}>
                  <div className="p-3 bg-secondary bg-opacity-25 fw-bold small text-dark text-uppercase border-bottom">Document Proof</div>
                  <div className="flex-grow-1 p-2 d-flex align-items-start justify-content-center overflow-auto bg-slate-900">
                    {renderDocumentViewer(isEditing && editForm ? editForm.Account_Passbook_Doc : selectedBLO.Account_Passbook_Doc)}
                  </div>
                </div>

                <div className="col-12 col-md-5 d-flex flex-column p-4 bg-white">
                  {isEditing && editForm ? (
                    <div className="flex-grow-1">
                      <h6 className="fw-bold text-primary mb-4 text-uppercase extra-small">Quick Detail Correction</h6>
                      <div className="mb-3">
                        <label className="form-label extra-small fw-bold text-muted">Account Number</label>
                        <input 
                          type="text" 
                          className="form-control fw-bold font-monospace" 
                          value={editForm.Account_Number} 
                          onChange={e => setEditForm({...editForm, Account_Number: e.target.value.replace(/\D/g, '')})} 
                        />
                      </div>
                      <div className="mb-3">
                        <label className="form-label extra-small fw-bold text-muted">IFSC Code</label>
                        <div className="input-group">
                          <input 
                            type="text" 
                            className="form-control font-monospace text-uppercase" 
                            value={editForm.IFSC_Code} 
                            onChange={e => setEditForm({...editForm, IFSC_Code: e.target.value.toUpperCase().trim()})} 
                          />
                          <button 
                            className="btn btn-outline-primary" 
                            type="button" 
                            onClick={() => triggerIFSCSearch(editForm.IFSC_Code)}
                            disabled={isSearching}
                          >
                            {isSearching ? <i className="bi bi-arrow-repeat spin"></i> : <i className="bi bi-search"></i>}
                          </button>
                        </div>
                      </div>
                      <div className="mb-4">
                        <label className="form-label extra-small fw-bold text-muted">BLO Mobile</label>
                        <input 
                          type="text" 
                          className="form-control" 
                          value={editForm.Mobile} 
                          onChange={e => setEditForm({...editForm, Mobile: e.target.value})} 
                        />
                      </div>

                      <div className="d-grid gap-2">
                        <button onClick={handleSaveEdit} className="btn btn-primary py-2 fw-bold shadow-sm">Update Details</button>
                        <button onClick={() => setIsEditing(false)} className="btn btn-outline-secondary py-2">Cancel Edit</button>
                      </div>
                    </div>
                  ) : (
                    <div className="flex-grow-1 d-flex flex-column">
                      <div className="card border-0 bg-primary bg-opacity-10 p-4 mb-4 text-center">
                        <label className="fw-bold text-primary text-uppercase mb-2" style={{fontSize: '0.7rem'}}>Account Number</label>
                        <div className="h3 fw-bold text-dark font-monospace mb-0">{selectedBLO.Account_Number || 'NOT ENTERED'}</div>
                      </div>

                      <div className="card border-0 bg-secondary bg-opacity-10 p-3 mb-4">
                        <div className="row g-2">
                          <div className="col-6">
                            <label className="extra-small text-muted text-uppercase fw-bold">IFSC Code</label>
                            <div className="fw-bold font-monospace">{selectedBLO.IFSC_Code || '---'}</div>
                          </div>
                          <div className="col-6">
                            <label className="extra-small text-muted text-uppercase fw-bold">EPIC</label>
                            <div className="fw-bold">{selectedBLO.EPIC || '---'}</div>
                          </div>
                          <div className="col-12 pt-3 mt-2 border-top">
                            <label className="extra-small text-muted text-uppercase fw-bold">Designation</label>
                            <div className="small fw-semibold">{getEntityLabel(designations.find(d => String(d.Desg_ID).trim() === String(selectedBLO.Desg_ID).trim()), ['Desg_Name', 'Designation', 'Name'])}</div>
                          </div>
                        </div>
                      </div>

                      <div className="mt-auto d-grid gap-2">
                        {selectedBLO.Verified === 'no' && (
                          <button onClick={startEditing} className="btn btn-outline-primary py-2 fw-bold d-flex align-items-center justify-content-center">
                            <i className="bi bi-pencil-square me-2"></i> Edit Details
                          </button>
                        )}

                        {selectedBLO.Verified === 'yes' ? (
                          <button onClick={() => handleVerifyToggle(selectedBLO)} className="btn btn-danger py-3 shadow fw-bold" disabled={!isAdmin}>
                            <i className="bi bi-unlock-fill me-2"></i> UN-VERIFY
                          </button>
                        ) : (
                          <button 
                            onClick={() => handleVerifyToggle(selectedBLO)} 
                            className={`btn btn-success py-3 shadow fw-bold ${!selectedBLO.Account_Number ? 'disabled' : ''}`}
                          >
                            <i className="bi bi-shield-fill-check me-2"></i> CONFIRM & VERIFY
                          </button>
                        )}
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        ) : (
