                            <label className="extra-small text-muted text-uppercase fw-bold">Designation</label>
                            <div className="small fw-semibold">{getEntityLabel(designations.find(d => String(d.Dept_ID).trim() === String(selectedBLO.Dept_ID).trim() && String(d.Desg_ID).trim() === String(selectedBLO.Desg_ID).trim()), ['Desg_Name', 'Designation', 'Name'])}</div>
                          </div>
                        </div>
                      </div>

                      <div className="mt-auto d-grid gap-2">
                        {selectedBLO.Verified === 'no' && (
                          <button onClick={startEditing} className="btn btn-outline-primary py-2 fw-bold d-flex align-items-center justify-content-center">
                            <i className="bi bi-pencil-square me-2"></i> Edit Details
                          </button>
                        )}

                        {selectedBLO.Verified === 'yes' ? (
                          <button onClick={() => handleVerifyToggle(selectedBLO)} className="btn btn-danger py-3 shadow fw-bold" disabled={!isAdmin}>
                            <i className="bi bi-unlock-fill me-2"></i> UN-VERIFY
                          </button>
                        ) : (
                          <button 
                            onClick={() => handleVerifyToggle(selectedBLO)} 
                            className={`btn btn-success py-3 shadow fw-bold ${!selectedBLO.Account_Number ? 'disabled' : ''}`}
                          >
                            <i className="bi bi-shield-fill-check me-2"></i> CONFIRM & VERIFY
                          </button>
                        )}
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        ) : (
          <div className="col-lg-8 d-none d-lg-flex align-items-center justify-content-center bg-white rounded-4 border">
            <div className="text-center p-5">
              <i className="bi bi-check2-all text-primary display-1 mb-3"></i>
              <h4 className="fw-bold">Ready for Matching</h4>
              <p className="text-muted">Select an officer to verify their bank details against the uploaded document.</p>
              <div className="mt-3 badge bg-info-subtle text-info px-3 py-2">
                Showing {filteredAccounts.length} accounts with completed entries.
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default Verification;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { BLOAccount, User, UserType, Bank, BankBranch, Department, Designation } from '../types';
import { searchIFSCViaGemini } from '../services/geminiService';

interface AccountEntryProps {
  user: User;
  accounts: BLOAccount[];
  banks: Bank[];
  branches: BankBranch[];
  departments: Department[];
  designations: Designation[];
  onUpdate: (updated: BLOAccount, newBank?: Bank, newBranch?: BankBranch) => void;
}

const AccountEntry: React.FC<AccountEntryProps> = ({ user, accounts, banks, branches, departments, designations, onUpdate }) => {
  const [selectedBLO, setSelectedBLO] = useState<BLOAccount | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const [editForm, setEditForm] = useState<BLOAccount | null>(null);

  // Filters and Pagination
  const [filterTehsil, setFilterTehsil] = useState('');
  const [filterAC, setFilterAC] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [pageSize, setPageSize] = useState<number | 'all'>(10);

  const [searchFeedback, setSearchFeedback] = useState<{ type: 'success' | 'error' | 'info' | 'none', message: string }>({ type: 'none', message: '' });
  const [stagedBank, setStagedBank] = useState<Bank | null>(null);
  const [stagedBranch, setStagedBranch] = useState<BankBranch | null>(null);

  const lastSearchedRef = useRef<string>('');

  const isAdmin = user.User_Type === UserType.ADMIN;

  // Filter Logic
  const filteredAccounts = useMemo(() => {
    let list = isAdmin 
      ? accounts 
      : accounts.filter(a => String(a.User_ID).trim() === String(user.User_ID).trim());

    if (isAdmin) {
      if (filterTehsil) list = list.filter(a => a.Tehsil === filterTehsil);
      if (filterAC) list = list.filter(a => a.AC_Name === filterAC);
    }
    return list;
  }, [accounts, user, isAdmin, filterTehsil, filterAC]);

  // Unique lists for Admin filters
  const uniqueTehsils = useMemo(() => Array.from(new Set(accounts.map(a => a.Tehsil))).sort(), [accounts]);
  const uniqueACs = useMemo(() => Array.from(new Set(accounts.map(a => a.AC_Name))).sort(), [accounts]);

  // Pagination Logic
  const totalPages = pageSize === 'all' ? 1 : Math.ceil(filteredAccounts.length / Number(pageSize));
  const paginatedAccounts = useMemo(() => {
    if (pageSize === 'all') return filteredAccounts;
    const start = (currentPage - 1) * Number(pageSize);
    return filteredAccounts.slice(start, start + Number(pageSize));
  }, [filteredAccounts, currentPage, pageSize]);

  // Effect to reset page when filters change
  useEffect(() => {
    setCurrentPage(1);
  }, [filterTehsil, filterAC, pageSize]);

  const getEntityLabel = (obj: any, preferredKeys: string[]): string => {
    if (!obj) return '---';
    for (const key of preferredKeys) {
      if (obj[key] !== undefined && obj[key] !== null && String(obj[key]).trim() !== '') {
        return String(obj[key]).trim();
      }
    }
    const keys = Object.keys(obj);
    const fallbackKey = keys.find(k => k.toLowerCase().includes('name') || k.toLowerCase().includes('designation') || k.toLowerCase().includes('department'));
    return fallbackKey ? String(obj[fallbackKey]) : 'Unknown';
  };

  const getDeptName = (id: any) => {
    const dept = departments.find(d => String(d.Dept_ID).trim() === String(id).trim());
    return getEntityLabel(dept, ['Dept_Name', 'Department', 'Name']);
  };

  const getDesgName = (id: any) => {
    const desg = designations.find(d => String(d.Desg_ID).trim() === String(id).trim());
    return getEntityLabel(desg, ['Desg_Name', 'Designation', 'Name']);
  };

  const handleEdit = (blo: BLOAccount) => {
    setSelectedBLO(blo);
    setEditForm({ ...blo });
    setSearchFeedback({ type: 'none', message: '' });
    setStagedBank(null);
    setStagedBranch(null);
    lastSearchedRef.current = blo.IFSC_Code || '';
  };

  const triggerIFSCSearch = async (ifscCode: string) => {
    if (!ifscCode || ifscCode.length !== 11) {
      setSearchFeedback({ type: 'error', message: 'Please enter a valid 11-digit IFSC code.' });
      return;
    }
    setIsSearching(true);
    setSearchFeedback({ type: 'none', message: '' });
    setStagedBank(null);
    setStagedBranch(null);
    lastSearchedRef.current = ifscCode;

    const localBranch = branches.find(br => String(br.IFSC_Code).toUpperCase() === ifscCode.toUpperCase());
    if (localBranch) {
      setEditForm(prev => prev ? ({ ...prev, Bank_ID: localBranch.Bank_ID, Branch_ID: localBranch.Branch_ID }) : null);
      setSearchFeedback({ type: 'success', message: 'Bank details found in current directory.' });
      setIsSearching(false);
      return;
    }

    try {
      const result = await searchIFSCViaGemini(ifscCode);
      if (result) {
        const normalizedBankName = result.bankName.trim().toLowerCase();
        let bank = banks.find(b => String(b.Bank_Name).toLowerCase() === normalizedBankName);
        const newBankObj: Bank | undefined = !bank ? { Bank_ID: 'B_' + Date.now(), Bank_Name: result.bankName, T_STMP_ADD: new Date().toISOString(), T_STMP_UPD: new Date().toISOString() } : undefined;
        const targetBankId = bank ? bank.Bank_ID : newBankObj!.Bank_ID;
        const newBranchObj: BankBranch = { Branch_ID: 'BR_' + Date.now(), Branch_Name: result.branchName, IFSC_Code: result.ifsc.toUpperCase(), Bank_ID: targetBankId, T_STMP_ADD: new Date().toISOString(), T_STMP_UPD: new Date().toISOString() };
        setEditForm(prev => prev ? ({ ...prev, IFSC_Code: result.ifsc.toUpperCase(), Bank_ID: targetBankId, Branch_ID: newBranchObj.Branch_ID }) : null);
        if (newBankObj) setStagedBank(newBankObj);
        setStagedBranch(newBranchObj);
        setSearchFeedback({ type: 'info', message: `Discovered new details! Bank: ${result.bankName}, Branch: ${result.branchName}. This will be added to the directory upon save.` });
      } else {
        setSearchFeedback({ type: 'error', message: 'Could not find bank details for this IFSC code.' });
      }
    } catch (err) {
      setSearchFeedback({ type: 'error', message: 'Search failed.' });
    } finally { setIsSearching(false); }
  };

  useEffect(() => {
    if (editForm && String(editForm.IFSC_Code).length === 11 && String(editForm.IFSC_Code) !== lastSearchedRef.current) {
      triggerIFSCSearch(editForm.IFSC_Code);
    }
  }, [editForm?.IFSC_Code]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && editForm) {
      const reader = new FileReader();
      reader.onloadend = () => { setEditForm({ ...editForm, Account_Passbook_Doc: reader.result as string }); };
      reader.readAsDataURL(file);
    }
  };

  const handleDeptChange = (deptId: string) => {
    if (editForm) { setEditForm({ ...editForm, Dept_ID: String(deptId).trim(), Desg_ID: '' }); }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editForm) {
      if (!editForm.Account_Number || !editForm.IFSC_Code || !editForm.Account_Passbook_Doc) {
        alert("Required fields missing.");
        return;
      }
      onUpdate(editForm, stagedBank || undefined, stagedBranch || undefined);
      setSelectedBLO(null); setEditForm(null); setStagedBank(null); setStagedBranch(null);
    }
  };

  const renderPreview = (doc: string) => {
    if (!doc) return null;
    if (doc.includes('drive.google.com')) {
      const previewUrl = doc.replace('/view?usp=sharing', '/preview').replace('/view', '/preview');
      return <iframe src={previewUrl} className="w-100 rounded border-0 shadow-sm" style={{ height: '500px' }} title="Drive Document Preview"></iframe>;
    }
    if (doc.startsWith('data:application/pdf')) return <iframe src={doc} className="w-100 rounded border-0" style={{ height: '500px' }} title="PDF Preview"></iframe>;
    if (doc.startsWith('data:image')) return <img src={doc} alt="Passbook" className="img-fluid" style={{ maxHeight: '500px' }} />;
    return <div className="alert alert-secondary py-3 text-center">Unsupported document format.</div>;
  };

  if (selectedBLO && editForm) {
    const isLocked = editForm.Verified === 'yes' && user.User_Type !== UserType.ADMIN;
    const isFileNew = editForm.Account_Passbook_Doc && editForm.Account_Passbook_Doc.startsWith('data:');
    const currentBank = banks.find(b => String(b.Bank_ID).trim() === String(editForm.Bank_ID).trim()) || (stagedBank?.Bank_ID === editForm.Bank_ID ? stagedBank : null);
    const currentBranch = branches.find(br => String(br.Branch_ID).trim() === String(editForm.Branch_ID).trim()) || (stagedBranch?.Branch_ID === editForm.Branch_ID ? stagedBranch : null);
    const availableDesignations = designations.filter(d => editForm.Dept_ID && String(d.Dept_ID).trim() === String(editForm.Dept_ID).trim());

    return (
      <div className="container-fluid py-2">
        <div className="card shadow-lg border-0 overflow-hidden">
          <div className="card-header bg-primary text-white p-4 d-flex justify-content-between align-items-center">
            <h5 className="mb-0 fw-bold d-flex align-items-center">
              <i className="bi bi-bank2 me-3 fs-4"></i>
              Manage Bank Account: {selectedBLO.BLO_Name}
            </h5>
            <button onClick={() => setSelectedBLO(null)} className="btn-close btn-close-white"></button>
          </div>
          <div className="card-body p-4 bg-light-subtle">
            <form onSubmit={handleSubmit}>
              {isLocked && <div className="alert alert-warning mb-4 shadow-sm border-0 d-flex align-items-center"><i className="bi bi-lock-fill fs-4 me-3"></i> This record is <strong>Verified</strong>.</div>}
              <div className="card border-0 shadow-sm mb-4 bg-light">
                <div className="card-body p-4">
                  <h6 className="text-secondary fw-bold text-uppercase small mb-4 d-flex align-items-center"><i className="bi bi-geo-alt-fill me-2"></i> Assembly Details</h6>
                  <div className="row g-3">
                    <div className="col-md-2"><label className="form-label extra-small fw-bold text-muted">AC No.</label><input type="text" readOnly disabled className="form-control form-control-sm bg-white-50 border-0" value={editForm.AC_No} /></div>
                    <div className="col-md-6"><label className="form-label extra-small fw-bold text-muted">AC Name</label><input type="text" readOnly disabled className="form-control form-control-sm bg-white-50 border-0" value={editForm.AC_Name} /></div>
                    <div className="col-md-4"><label className="form-label extra-small fw-bold text-muted">Tehsil</label><input type="text" readOnly disabled className="form-control form-control-sm bg-white-50 border-0" value={editForm.Tehsil} /></div>
                  </div>
                </div>
              </div>
              <div className="card border-0 shadow-sm mb-4">
                <div className="card-body p-4">
                  <h6 className="text-primary fw-bold text-uppercase small mb-4 d-flex align-items-center"><i className="bi bi-person-badge-fill me-2"></i> BLO Details</h6>
                  <div className="row g-3">
                    <div className="col-md-6"><label className="form-label extra-small fw-bold text-muted">BLO Name</label><input disabled={isLocked} type="text" className="form-control form-control-sm" value={editForm.BLO_Name} onChange={e => setEditForm({...editForm, BLO_Name: e.target.value})} /></div>
                    <div className="col-md-3"><label className="form-label extra-small fw-bold text-muted">Mobile</label><input disabled={isLocked} type="text" className="form-control form-control-sm" value={editForm.Mobile} onChange={e => setEditForm({...editForm, Mobile: e.target.value})} /></div>
                  </div>
                </div>
              </div>
              <div className="card border-0 shadow-sm mb-5">
                <div className="card-body p-4 bg-white border-start border-primary border-5 rounded-end">
                  <h6 className="text-primary fw-bold text-uppercase small mb-4"><i className="bi bi-credit-card-2-front me-2"></i> Account Details</h6>
                  <div className="row g-4">
                    <div className="col-md-6">
                      <label className="form-label fw-bold text-dark mb-2">IFSC Code *</label>
                      <div className="input-group input-group-lg shadow-sm">
                        <input disabled={isLocked} type="text" className="form-control fw-bold text-primary text-uppercase" placeholder="IFSC" maxLength={11} value={editForm.IFSC_Code} onChange={e => setEditForm({...editForm, IFSC_Code: e.target.value.toUpperCase().trim()})} required />
                        <button type="button" className="btn btn-primary px-4" onClick={() => triggerIFSCSearch(editForm.IFSC_Code)} disabled={isSearching || isLocked}>{isSearching ? <i className="bi bi-arrow-repeat spin"></i> : 'Search'}</button>
                      </div>
                    </div>
                    <div className="col-md-6">
                      <label className="form-label fw-bold text-dark mb-2">Account Number *</label>
                      <input disabled={isLocked} type="text" inputMode="numeric" pattern="[0-9]*" className="form-control form-control-lg shadow-sm fw-bold text-dark" placeholder="Account Number" value={String(editForm.Account_Number || '')} onChange={e => setEditForm({...editForm, Account_Number: e.target.value.replace(/\D/g, '')})} required />
                    </div>
                    <div className="col-12">
                      <label className="form-label small fw-bold text-secondary">Passbook Document *</label>
                      <input disabled={isLocked} type="file" className="form-control bg-white shadow-sm mb-3" onChange={handleFileChange} accept=".pdf,image/*" required={!editForm.Account_Passbook_Doc} />
                      {editForm.Account_Passbook_Doc && <div className="mt-2"><div className="p-3 border rounded bg-white shadow-sm mb-3">{renderPreview(editForm.Account_Passbook_Doc)}</div></div>}
                    </div>
                  </div>
                </div>
              </div>
              <div className="mt-5 pt-4 border-top d-flex gap-3 justify-content-end align-items-center">
                <button type="button" onClick={() => setSelectedBLO(null)} className="btn btn-outline-secondary px-4">Cancel</button>
                <button type="submit" disabled={isLocked} className="btn btn-primary btn-lg px-5 shadow-sm fw-bold">Save Changes</button>
              </div>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="container-fluid py-2">
      <div className="d-flex flex-column flex-md-row justify-content-between align-items-md-center mb-4 gap-3">
        <div>
          <h3 className="fw-bold mb-1">BLO Bank Directory</h3>
          <p className="text-muted small mb-0">Update and manage bank account details for election personnel.</p>
        </div>
      </div>

      {isAdmin && (
        <div className="card border-0 shadow-sm mb-4 bg-light">
          <div className="card-body p-3">
            <div className="row g-3 align-items-center">
              <div className="col-md-auto"><span className="fw-bold extra-small text-muted text-uppercase">Filters:</span></div>
              <div className="col-md-3">
                <select className="form-select form-select-sm" value={filterTehsil} onChange={e => setFilterTehsil(e.target.value)}>
                  <option value="">All Tehsils</option>
                  {uniqueTehsils.map(t => <option key={t} value={t}>{t}</option>)}
                </select>
              </div>
              <div className="col-md-3">
                <select className="form-select form-select-sm" value={filterAC} onChange={e => setFilterAC(e.target.value)}>
                  <option value="">All ACs</option>
                  {uniqueACs.map(ac => <option key={ac} value={ac}>{ac}</option>)}
                </select>
              </div>
              <div className="col-md-auto ms-auto">
                <button className="btn btn-sm btn-outline-secondary" onClick={() => { setFilterTehsil(''); setFilterAC(''); }}>Clear Filters</button>
              </div>
            </div>
          </div>
        </div>
      )}

      <div className="card border-0 shadow-sm overflow-hidden">
        <div className="table-responsive">
          <table className="table table-hover align-middle mb-0">
            <thead className="table-dark">
              <tr>
                <th className="py-3 px-4 fw-bold small">PART / AC</th>
                <th className="py-3 px-4 fw-bold small">BLO NAME / TEHSIL</th>
                <th className="py-3 px-4 fw-bold small bg-primary-subtle text-primary">ACCOUNT NUMBER</th>
                <th className="py-3 px-4 fw-bold small text-center">STATUS</th>
                <th className="py-3 px-4 fw-bold small text-end">ACTIONS</th>
              </tr>
            </thead>
            <tbody>
              {paginatedAccounts.map(blo => (
                <tr key={blo.BLO_ID} className={blo.Verified === 'yes' ? 'table-success-subtle' : ''}>
                  <td className="px-4 py-3">
                    <div className="fw-bold text-dark">P-{blo.Part_No}</div>
                    <div className="extra-small text-muted">{blo.AC_Name}</div>
                  </td>
                  <td className="px-4 py-3">
                    <div className="fw-semibold text-primary">{blo.BLO_Name}</div>
                    <div className="extra-small fw-bold text-uppercase text-muted">{blo.Tehsil}</div>
                  </td>
                  <td className="px-4 py-3 bg-light font-monospace">
                    {blo.Account_Number ? <span className="fw-bold text-dark">{blo.Account_Number}</span> : <span className="text-danger small italic">Pending</span>}
                  </td>
                  <td className="px-4 py-3 text-center">
                    {blo.Verified === 'yes' ? <span className="badge bg-success-subtle text-success rounded-pill px-3">Verified</span> : <span className="badge bg-warning-subtle text-warning-emphasis rounded-pill px-3">Pending</span>}
                  </td>
                  <td className="px-4 py-3 text-end">
                    <button onClick={() => handleEdit(blo)} className="btn btn-sm px-3 btn-primary shadow-sm"><i className="bi bi-pencil me-1"></i> Edit</button>
                  </td>
                </tr>
              ))}
              {paginatedAccounts.length === 0 && <tr><td colSpan={5} className="text-center py-5 text-muted">No records found matching filters.</td></tr>}
            </tbody>
          </table>
        </div>

        {/* Pagination Footer */}
        <div className="card-footer bg-white border-top p-3">
          <div className="row g-3 align-items-center">
            <div className="col-md-auto text-muted extra-small">
              Showing {filteredAccounts.length > 0 ? (currentPage - 1) * (pageSize === 'all' ? filteredAccounts.length : Number(pageSize)) + 1 : 0} to {Math.min(currentPage * (pageSize === 'all' ? filteredAccounts.length : Number(pageSize)), filteredAccounts.length)} of {filteredAccounts.length} records
            </div>
            <div className="col-md-auto ms-auto d-flex align-items-center gap-3">
              <div className="d-flex align-items-center gap-2">
                <span className="extra-small text-muted text-uppercase fw-bold">Rows:</span>
                <select className="form-select form-select-sm" style={{ width: '80px' }} value={pageSize} onChange={e => { setPageSize(e.target.value === 'all' ? 'all' : Number(e.target.value)); setCurrentPage(1); }}>
                  <option value={10}>10</option>
                  <option value={25}>25</option>
                  <option value={50}>50</option>
                  <option value={100}>100</option>
                  <option value="all">All</option>
                </select>
              </div>
              <div className="btn-group btn-group-sm">
                <button className="btn btn-outline-secondary px-3" disabled={currentPage === 1} onClick={() => setCurrentPage(p => p - 1)}>
                  <i className="bi bi-chevron-left me-1"></i> Prev
                </button>
                <button className="btn btn-outline-secondary px-3" disabled={currentPage >= totalPages} onClick={() => setCurrentPage(p => p + 1)}>
                  Next <i className="bi bi-chevron-right ms-1"></i>
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AccountEntry;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { BLOAccount, User, UserType, Bank, BankBranch, Department, Designation } from '../types';
import { searchIFSCViaGemini } from '../services/geminiService';
import * as XLSX from 'xlsx';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';

interface VerificationProps {
  user: User;
  accounts: BLOAccount[];
  banks: Bank[];
  branches: BankBranch[];
  departments: Department[];
  designations: Designation[];
  onVerify: (bloId: string, verified: 'yes' | 'no') => void;
  onUpdate?: (updated: BLOAccount, newBank?: Bank, newBranch?: BankBranch) => void;
}

const Verification: React.FC<VerificationProps> = ({ user, accounts, banks, branches, departments, designations, onVerify, onUpdate }) => {
  const [selectedBLO, setSelectedBLO] = useState<BLOAccount | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [editForm, setEditForm] = useState<BLOAccount | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const [isExporting, setIsExporting] = useState(false);

  // Filtering & Pagination States
  const [filterTehsil, setFilterTehsil] = useState('');
  const [filterAC, setFilterAC] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [pageSize, setPageSize] = useState<number | 'all'>(10);

  const lastSearchedRef = useRef<string>('');
  const isAdmin = user.User_Type === UserType.ADMIN;

  // Filter logic: Admin specific filtering for Tehsil and AC
  const filteredAccounts = useMemo(() => {
    let list = (user.User_Type === UserType.ADMIN 
      ? accounts 
      : accounts.filter(a => String(a.User_ID).trim() === String(user.User_ID).trim()))
      .filter(a => a.Account_Number && String(a.Account_Number).trim() !== '');

    if (isAdmin) {
      if (filterTehsil) list = list.filter(a => a.Tehsil === filterTehsil);
      if (filterAC) list = list.filter(a => a.AC_Name === filterAC);
    }
    return list;
  }, [accounts, user, isAdmin, filterTehsil, filterAC]);

  // Pagination Logic
  const totalPages = pageSize === 'all' ? 1 : Math.ceil(filteredAccounts.length / Number(pageSize));
  const paginatedAccounts = useMemo(() => {
    if (pageSize === 'all') return filteredAccounts;
    const start = (currentPage - 1) * Number(pageSize);
    return filteredAccounts.slice(start, start + Number(pageSize));
  }, [filteredAccounts, currentPage, pageSize]);

  // Unique Lists for Filters
  const uniqueTehsils = useMemo(() => Array.from(new Set(accounts.map(a => a.Tehsil))).sort(), [accounts]);
  const uniqueACs = useMemo(() => Array.from(new Set(accounts.map(a => a.AC_Name))).sort(), [accounts]);

  // Reset page when filters change
  useEffect(() => {
    setCurrentPage(1);
  }, [filterTehsil, filterAC, pageSize]);

  const getEntityLabel = (obj: any, preferredKeys: string[]): string => {
    if (!obj) return '---';
    for (const key of preferredKeys) {
      if (obj[key] !== undefined && obj[key] !== null && String(obj[key]).trim() !== '') return String(obj[key]).trim();
    }
    return 'Unknown';
  };

  const handleVerifyToggle = (blo: BLOAccount) => {
    if (blo.Verified === 'yes' && !isAdmin) { alert("Admin access required."); return; }
    const nextState = blo.Verified === 'yes' ? 'no' : 'yes';
    onVerify(blo.BLO_ID, nextState);
    if (selectedBLO?.BLO_ID === blo.BLO_ID) { setSelectedBLO({...blo, Verified: nextState}); }
  };

  const handleSaveEdit = async () => {
    if (!editForm || !onUpdate) return;
    onUpdate(editForm);
    setSelectedBLO(editForm);
    setIsEditing(false);
  };

  const renderDocumentViewer = (doc: string) => {
    if (!doc) return <div className="text-center text-muted m-auto p-5"><i className="bi bi-file-earmark-excel fs-1 mb-3 d-block"></i> No Proof Uploaded</div>;
    if (doc.includes('drive.google.com')) {
      const previewUrl = doc.replace('/view?usp=sharing', '/preview').replace('/view', '/preview');
      return <iframe src={previewUrl} title="Drive PDF Viewer" className="w-100 h-100 rounded shadow border-0"></iframe>;
    }
    if (doc.startsWith('data:image')) return <img src={doc} alt="Passbook" className="img-fluid rounded shadow-lg m-auto" style={{maxHeight: '90%'}} />;
    return <div className="text-center p-4">Unsupported format.</div>;
  };

  return (
    <div className="container-fluid py-2">
      <div className="row g-4">
        {/* Sidebar / Queue Column */}
        <div className={`col-12 col-lg-4 ${selectedBLO ? 'd-none d-lg-block' : ''}`}>
          <div className="d-flex flex-column gap-3 mb-3">
            <h3 className="fw-bold mb-0">Verification Queue</h3>

            {isAdmin && (
              <div className="card border-0 shadow-sm bg-light-subtle">
                <div className="card-body p-3">
                  <div className="d-flex flex-column gap-2">
                    <select className="form-select form-select-sm" value={filterTehsil} onChange={e => setFilterTehsil(e.target.value)}>
                      <option value="">All Tehsils</option>
                      {uniqueTehsils.map(t => <option key={t} value={t}>{t}</option>)}
                    </select>
                    <select className="form-select form-select-sm" value={filterAC} onChange={e => setFilterAC(e.target.value)}>
                      <option value="">All ACs</option>
                      {uniqueACs.map(ac => <option key={ac} value={ac}>{ac}</option>)}
                    </select>
                  </div>
                </div>
              </div>
            )}
          </div>

          <div className="card shadow-sm border-0 overflow-hidden">
            <div className="list-group list-group-flush" style={{maxHeight: '60vh', overflowY: 'auto'}}>
              {paginatedAccounts.length === 0 && <div className="p-4 text-center text-muted italic">No records found.</div>}
              {paginatedAccounts.map(blo => (
                <button key={blo.BLO_ID} onClick={() => { setSelectedBLO(blo); setIsEditing(false); }} className={`list-group-item list-group-item-action p-3 border-0 border-bottom ${selectedBLO?.BLO_ID === blo.BLO_ID ? 'bg-primary-subtle' : ''}`}>
                  <div className="d-flex justify-content-between align-items-start">
                    <div className="overflow-hidden">
                      <h6 className="fw-bold mb-1 text-truncate">{blo.BLO_Name}</h6>
                      <p className="extra-small text-muted mb-1">P-{blo.Part_No} | {blo.Tehsil}</p>
                      <div className="extra-small font-monospace text-primary">{blo.Account_Number}</div>
                    </div>
                    {blo.Verified === 'yes' ? <span className="badge bg-success rounded-circle p-1"><i className="bi bi-check text-white"></i></span> : <span className="badge bg-warning-subtle text-warning p-1 rounded-circle"><i className="bi bi-clock"></i></span>}
                  </div>
                </button>
              ))}
            </div>

            {/* Pagination Controls in Queue */}
            <div className="card-footer bg-white border-top p-2">
              <div className="d-flex align-items-center justify-content-between">
                <select className="form-select form-select-sm w-auto" style={{ fontSize: '0.7rem' }} value={pageSize} onChange={e => setPageSize(e.target.value === 'all' ? 'all' : Number(e.target.value))}>
                  <option value={10}>10</option>
                  <option value={25}>25</option>
                  <option value="all">All</option>
                </select>
                <div className="btn-group">
                  <button className="btn btn-sm btn-outline-secondary" disabled={currentPage === 1} onClick={() => setCurrentPage(p => p - 1)}><i className="bi bi-chevron-left"></i></button>
                  <span className="btn btn-sm btn-light disabled px-3 fw-bold" style={{ fontSize: '0.7rem' }}>{currentPage}</span>
                  <button className="btn btn-sm btn-outline-secondary" disabled={currentPage >= totalPages} onClick={() => setCurrentPage(p => p + 1)}><i className="bi bi-chevron-right"></i></button>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Main Workspace */}
        {selectedBLO ? (
          <div className="col-12 col-lg-8">
            <div className="card shadow-lg border-0 h-100 flex-column overflow-hidden">
              <div className="card-header bg-dark text-white p-4 d-flex justify-content-between align-items-center">
                <h5 className="mb-0 fw-bold">{isEditing ? 'Correcting Record' : 'Verification Workbench'}</h5>
                <button onClick={() => { setSelectedBLO(null); setIsEditing(false); }} className="btn btn-sm btn-outline-light">Close</button>
              </div>
              <div className="row g-0 flex-grow-1">
                <div className="col-md-7 bg-dark bg-opacity-10 d-flex flex-column border-end" style={{ minHeight: '500px' }}>
                  <div className="p-3 bg-secondary bg-opacity-25 fw-bold small text-dark text-uppercase border-bottom">Document Proof</div>
                  <div className="flex-grow-1 p-2 d-flex align-items-start justify-content-center overflow-auto">{renderDocumentViewer(isEditing && editForm ? editForm.Account_Passbook_Doc : selectedBLO.Account_Passbook_Doc)}</div>
                </div>
                <div className="col-md-5 p-4 bg-white d-flex flex-column">
                  {isEditing && editForm ? (
                    <div>
                      <h6 className="fw-bold text-primary mb-4 text-uppercase extra-small">Quick Correction</h6>
                      <div className="mb-3">
                        <label className="form-label extra-small fw-bold text-muted">Account Number</label>
                        <input type="text" className="form-control fw-bold font-monospace" value={String(editForm.Account_Number || '')} onChange={e => setEditForm({...editForm, Account_Number: e.target.value.replace(/\D/g, '')})} />
                      </div>
                      <div className="mb-3">
                        <label className="form-label extra-small fw-bold text-muted">IFSC Code</label>
                        <input type="text" className="form-control font-monospace text-uppercase" value={editForm.IFSC_Code} onChange={e => setEditForm({...editForm, IFSC_Code: e.target.value.toUpperCase().trim()})} />
                      </div>
                      <div className="d-grid gap-2 mt-4">
                        <button onClick={handleSaveEdit} className="btn btn-primary py-2 fw-bold shadow-sm">Update Details</button>
                        <button onClick={() => setIsEditing(false)} className="btn btn-outline-secondary py-2">Cancel Edit</button>
                      </div>
                    </div>
                  ) : (
                    <div className="flex-grow-1 d-flex flex-column">
                      <div className="card border-0 bg-primary bg-opacity-10 p-4 mb-4 text-center">
                        <label className="fw-bold text-primary text-uppercase mb-2 extra-small">Account Number</label>
                        <div className="h3 fw-bold text-dark font-monospace mb-0">{selectedBLO.Account_Number}</div>
                      </div>
                      <div className="card border-0 bg-secondary bg-opacity-10 p-3 mb-4">
                        <div className="row g-2">
                          <div className="col-6"><label className="extra-small text-muted text-uppercase fw-bold">IFSC Code</label><div className="fw-bold font-monospace">{selectedBLO.IFSC_Code}</div></div>
                          <div className="col-6"><label className="extra-small text-muted text-uppercase fw-bold">Tehsil</label><div className="fw-bold">{selectedBLO.Tehsil}</div></div>
                        </div>
                      </div>
                      <div className="mt-auto d-grid gap-2">
                        {selectedBLO.Verified === 'no' && <button onClick={() => setIsEditing(true)} className="btn btn-outline-primary py-2 fw-bold"><i className="bi bi-pencil-square me-2"></i> Edit Details</button>}
                        <button onClick={() => handleVerifyToggle(selectedBLO)} className={`btn ${selectedBLO.Verified === 'yes' ? 'btn-danger' : 'btn-success'} py-3 shadow fw-bold`} disabled={selectedBLO.Verified === 'yes' && !isAdmin}>
                          <i className={`bi ${selectedBLO.Verified === 'yes' ? 'bi-unlock-fill' : 'bi-shield-fill-check'} me-2`}></i> {selectedBLO.Verified === 'yes' ? 'UN-VERIFY' : 'CONFIRM & VERIFY'}
                        </button>
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        ) : (
          <div className="col-lg-8 d-none d-lg-flex align-items-center justify-content-center bg-white rounded-4 border">
            <div className="text-center p-5">
              <i className="bi bi-check2-all text-primary display-1 mb-3"></i>
              <h4 className="fw-bold">Ready for Audit</h4>
              <p className="text-muted">Select an officer from the queue to start verification.</p>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

