  accounts: BLOAccount[];
  banks: Bank[];
  branches: BankBranch[];
  departments: Department[];
  designations: Designation[];
  onVerify: (bloId: string, verified: 'yes' | 'no') => void;
  onUpdate?: (updated: BLOAccount, newBank?: Bank, newBranch?: BankBranch) => void;
}

const Verification: React.FC<VerificationProps> = ({ user, accounts, banks, branches, departments, designations, onVerify, onUpdate }) => {
  const [selectedBLO, setSelectedBLO] = useState<BLOAccount | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [editForm, setEditForm] = useState<BLOAccount | null>(null);
  const [isSearching, setIsSearching] = useState(false);

  // Filtering & Pagination States
  const [filterTehsil, setFilterTehsil] = useState('');
  const [filterAC, setFilterAC] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [pageSize, setPageSize] = useState<number | 'all'>(10);

  const lastSearchedRef = useRef<string>('');
  const isAdmin = user.User_Type === UserType.ADMIN;

  // Scoped filtering logic
  const filteredAccounts = useMemo(() => {
    let list = (user.User_Type === UserType.ADMIN 
      ? accounts 
      : accounts.filter(a => String(a.User_ID).trim() === String(user.User_ID).trim()))
      .filter(a => a.Account_Number && String(a.Account_Number).trim() !== '');

    if (isAdmin) {
      if (filterTehsil) list = list.filter(a => a.Tehsil === filterTehsil);
      if (filterAC) list = list.filter(a => a.AC_Name === filterAC);
    }
    return list;
  }, [accounts, user, isAdmin, filterTehsil, filterAC]);

  // Pagination Logic
  const totalPages = pageSize === 'all' ? 1 : Math.ceil(filteredAccounts.length / Number(pageSize));
  const paginatedAccounts = useMemo(() => {
    if (pageSize === 'all') return filteredAccounts;
    const start = (currentPage - 1) * Number(pageSize);
    return filteredAccounts.slice(start, start + Number(pageSize));
  }, [filteredAccounts, currentPage, pageSize]);

  // Unique Lists for Filters
  const uniqueTehsils = useMemo(() => Array.from(new Set(accounts.map(a => a.Tehsil))).sort(), [accounts]);
  const uniqueACs = useMemo(() => Array.from(new Set(accounts.map(a => a.AC_Name))).sort(), [accounts]);

  // Reset page when settings change
  useEffect(() => {
    setCurrentPage(1);
  }, [filterTehsil, filterAC, pageSize]);

  const handleVerifyToggle = (blo: BLOAccount) => {
    if (blo.Verified === 'yes' && !isAdmin) { alert("Admin authorization required."); return; }
    const nextState = blo.Verified === 'yes' ? 'no' : 'yes';
    onVerify(blo.BLO_ID, nextState);
    if (selectedBLO?.BLO_ID === blo.BLO_ID) { setSelectedBLO({...blo, Verified: nextState}); }
  };

  const renderDocumentViewer = (doc: string) => {
    if (!doc) return <div className="text-center text-muted m-auto p-5"><i className="bi bi-file-earmark-excel fs-1 mb-3 d-block"></i> No Document Found</div>;
    if (doc.includes('drive.google.com')) {
      const previewUrl = doc.replace('/view?usp=sharing', '/preview').replace('/view', '/preview');
      return <iframe src={previewUrl} title="Drive Viewer" className="w-100 h-100 rounded shadow border-0"></iframe>;
    }
    if (doc.startsWith('data:image')) return <img src={doc} alt="Passbook" className="img-fluid rounded shadow-lg m-auto" style={{maxHeight: '90%'}} />;
    return <div className="text-center p-4">Unsupported file format.</div>;
  };

  return (
    <div className="container-fluid py-2">
      <div className="row g-4">
        {/* Sidebar Navigation */}
        <div className={`col-12 col-lg-4 ${selectedBLO ? 'd-none d-lg-block' : ''}`}>
          <div className="d-flex flex-column gap-3 mb-3">
            <h3 className="fw-bold mb-0">Pending Audits</h3>

            {isAdmin && (
              <div className="card border-0 shadow-sm bg-white p-3">
                <div className="d-flex flex-column gap-2">
                  <span className="extra-small fw-bold text-muted text-uppercase mb-1">Administrative Filters:</span>
                  <select className="form-select form-select-sm" value={filterTehsil} onChange={e => setFilterTehsil(e.target.value)}>
                    <option value="">All Tehsils</option>
                    {uniqueTehsils.map(t => <option key={t} value={t}>{t}</option>)}
                  </select>
                  <select className="form-select form-select-sm" value={filterAC} onChange={e => setFilterAC(e.target.value)}>
                    <option value="">All Assemblies</option>
                    {uniqueACs.map(ac => <option key={ac} value={ac}>{ac}</option>)}
                  </select>
                </div>
              </div>
            )}
          </div>

          <div className="card shadow-sm border-0 overflow-hidden">
            <div className="list-group list-group-flush" style={{maxHeight: '60vh', overflowY: 'auto'}}>
              {paginatedAccounts.length === 0 && <div className="p-4 text-center text-muted italic">No matching entries found.</div>}
              {paginatedAccounts.map(blo => (
                <button key={blo.BLO_ID} onClick={() => { setSelectedBLO(blo); setIsEditing(false); }} className={`list-group-item list-group-item-action p-3 border-0 border-bottom ${selectedBLO?.BLO_ID === blo.BLO_ID ? 'bg-primary-subtle' : ''}`}>
                  <div className="d-flex justify-content-between align-items-start">
                    <div className="overflow-hidden">
                      <h6 className="fw-bold mb-1 text-truncate">{blo.BLO_Name}</h6>
                      <p className="extra-small text-muted mb-1">P-{blo.Part_No} | {blo.Tehsil}</p>
                      <div className="extra-small font-monospace text-primary fw-bold">{blo.Account_Number}</div>
                    </div>
                    {blo.Verified === 'yes' ? <span className="badge bg-success rounded-circle p-1"><i className="bi bi-check text-white"></i></span> : <span className="badge bg-warning-subtle text-warning p-1 rounded-circle"><i className="bi bi-clock"></i></span>}
                  </div>
                </button>
              ))}
            </div>

            {/* Consistent Sidebar Pagination */}
            <div className="card-footer bg-white border-top p-3">
              <div className="d-flex align-items-center justify-content-between">
                <select className="form-select form-select-sm w-auto" style={{ fontSize: '0.7rem' }} value={pageSize} onChange={e => setPageSize(e.target.value === 'all' ? 'all' : Number(e.target.value))}>
                  <option value={10}>10</option>
                  <option value={25}>25</option>
                  <option value={50}>50</option>
                  <option value="all">All</option>
                </select>
                <div className="btn-group btn-group-sm">
                  <button className="btn btn-outline-secondary" disabled={currentPage === 1} onClick={() => setCurrentPage(p => p - 1)}><i className="bi bi-chevron-left"></i></button>
                  <button className="btn btn-outline-secondary" disabled={currentPage >= totalPages} onClick={() => setCurrentPage(p => p + 1)}><i className="bi bi-chevron-right"></i></button>
                </div>
              </div>
              <div className="extra-small text-muted text-center mt-2">Page {currentPage} of {totalPages || 1}</div>
            </div>
          </div>
        </div>

        {/* Audit Workspace */}
        {selectedBLO ? (
          <div className="col-12 col-lg-8">
            <div className="card shadow-lg border-0 h-100 flex-column overflow-hidden">
              <div className="card-header bg-dark text-white p-4 d-flex justify-content-between align-items-center">
                <h5 className="mb-0 fw-bold">Verification Workbench</h5>
                <button onClick={() => { setSelectedBLO(null); setIsEditing(false); }} className="btn btn-sm btn-outline-light">Close View</button>
              </div>
              <div className="row g-0 flex-grow-1">
                <div className="col-md-7 bg-dark bg-opacity-10 d-flex flex-column border-end" style={{ minHeight: '500px' }}>
                  <div className="p-3 bg-secondary bg-opacity-25 fw-bold small text-dark text-uppercase border-bottom">Document Proof</div>
                  <div className="flex-grow-1 p-2 d-flex align-items-start justify-content-center overflow-auto">{renderDocumentViewer(selectedBLO.Account_Passbook_Doc)}</div>
                </div>
                <div className="col-md-5 p-4 bg-white d-flex flex-column">
                  <div className="flex-grow-1 d-flex flex-column">
                    <div className="card border-0 bg-primary bg-opacity-10 p-4 mb-4 text-center">
                      <label className="fw-bold text-primary text-uppercase mb-2 extra-small">Account Number</label>
                      <div className="h3 fw-bold text-dark font-monospace mb-0">{selectedBLO.Account_Number}</div>
                    </div>
                    <div className="card border-0 bg-secondary bg-opacity-10 p-3 mb-4">
                      <div className="row g-2">
                        <div className="col-6"><label className="extra-small text-muted text-uppercase fw-bold">IFSC</label><div className="fw-bold font-monospace">{selectedBLO.IFSC_Code}</div></div>
                        <div className="col-6"><label className="extra-small text-muted text-uppercase fw-bold">Tehsil</label><div className="fw-bold">{selectedBLO.Tehsil}</div></div>
                      </div>
                    </div>
                    <div className="mt-auto d-grid gap-2">
                      <button onClick={() => handleVerifyToggle(selectedBLO)} className={`btn ${selectedBLO.Verified === 'yes' ? 'btn-danger' : 'btn-success'} py-3 shadow fw-bold`} disabled={selectedBLO.Verified === 'yes' && !isAdmin}>
                        <i className={`bi ${selectedBLO.Verified === 'yes' ? 'bi-unlock-fill' : 'bi-shield-fill-check'} me-2`}></i> 
                        {selectedBLO.Verified === 'yes' ? 'UN-VERIFY RECORD' : 'CONFIRM & VERIFY'}
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        ) : (
          <div className="col-lg-8 d-none d-lg-flex align-items-center justify-content-center bg-white rounded-4 border">
            <div className="text-center p-5">
              <i className="bi bi-clipboard-check text-primary display-1 mb-3"></i>
              <h4 className="fw-bold">Ready for Audit</h4>
              <p className="text-muted">Select an officer from the sidebar to verify their uploaded documents.</p>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default Verification;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { BLOAccount, User, UserType, Bank, BankBranch, Department, Designation } from '../types';
import { searchIFSCViaGemini } from '../services/geminiService';

interface AccountEntryProps {
  user: User;
  accounts: BLOAccount[];
  banks: Bank[];
  branches: BankBranch[];
  departments: Department[];
  designations: Designation[];
  onUpdate: (updated: BLOAccount, newBank?: Bank, newBranch?: BankBranch) => void;
}

const AccountEntry: React.FC<AccountEntryProps> = ({ user, accounts, banks, branches, departments, designations, onUpdate }) => {
  const [selectedBLO, setSelectedBLO] = useState<BLOAccount | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const [editForm, setEditForm] = useState<BLOAccount | null>(null);

  // Filters and Pagination
  const [filterTehsil, setFilterTehsil] = useState('');
  const [filterAC, setFilterAC] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [pageSize, setPageSize] = useState<number | 'all'>(10);

  const [searchFeedback, setSearchFeedback] = useState<{ type: 'success' | 'error' | 'info' | 'none', message: string }>({ type: 'none', message: '' });
  const [stagedBank, setStagedBank] = useState<Bank | null>(null);
  const [stagedBranch, setStagedBranch] = useState<BankBranch | null>(null);

  const lastSearchedRef = useRef<string>('');
  const isAdmin = user.User_Type === UserType.ADMIN;

  // 1. Filtering Logic
  const filteredAccounts = useMemo(() => {
    let list = isAdmin 
      ? accounts 
      : accounts.filter(a => String(a.User_ID).trim() === String(user.User_ID).trim());

    if (isAdmin) {
      if (filterTehsil) list = list.filter(a => a.Tehsil === filterTehsil);
      if (filterAC) list = list.filter(a => a.AC_Name === filterAC);
    }
    return list;
  }, [accounts, user, isAdmin, filterTehsil, filterAC]);

  // 2. Pagination Logic
  const totalPages = pageSize === 'all' ? 1 : Math.ceil(filteredAccounts.length / Number(pageSize));
  const paginatedAccounts = useMemo(() => {
    if (pageSize === 'all') return filteredAccounts;
    const start = (currentPage - 1) * Number(pageSize);
    return filteredAccounts.slice(start, start + Number(pageSize));
  }, [filteredAccounts, currentPage, pageSize]);

  // Unique lists for Admin filters
  const uniqueTehsils = useMemo(() => Array.from(new Set(accounts.map(a => a.Tehsil))).sort(), [accounts]);
  const uniqueACs = useMemo(() => Array.from(new Set(accounts.map(a => a.AC_Name))).sort(), [accounts]);

  // Reset page when filters change
  useEffect(() => {
    setCurrentPage(1);
  }, [filterTehsil, filterAC, pageSize]);

  const getEntityLabel = (obj: any, preferredKeys: string[]): string => {
    if (!obj) return '---';
    for (const key of preferredKeys) {
      if (obj[key] !== undefined && obj[key] !== null && String(obj[key]).trim() !== '') return String(obj[key]).trim();
    }
    return 'Unknown';
  };

  const handleEdit = (blo: BLOAccount) => {
    setSelectedBLO(blo);
    setEditForm({ ...blo });
    setSearchFeedback({ type: 'none', message: '' });
    setStagedBank(null);
    setStagedBranch(null);
    lastSearchedRef.current = blo.IFSC_Code || '';
  };

  const triggerIFSCSearch = async (ifscCode: string) => {
    if (!ifscCode || ifscCode.length !== 11) {
      setSearchFeedback({ type: 'error', message: 'Enter valid 11-digit IFSC.' });
      return;
    }
    setIsSearching(true);
    setSearchFeedback({ type: 'none', message: '' });
    lastSearchedRef.current = ifscCode;

    // Check Local directory first
    const localBranch = branches.find(br => String(br.IFSC_Code).toUpperCase() === ifscCode.toUpperCase());
    if (localBranch) {
      setEditForm(prev => prev ? ({ ...prev, Bank_ID: localBranch.Bank_ID, Branch_ID: localBranch.Branch_ID }) : null);
      setSearchFeedback({ type: 'success', message: 'Found in local database.' });
      setIsSearching(false);
      return;
    }

    try {
      const result = await searchIFSCViaGemini(ifscCode);
      if (result && editForm) {
        let bank = banks.find(b => String(b.Bank_Name).toLowerCase() === result.bankName.toLowerCase());
        const newBankObj: Bank | undefined = !bank ? { Bank_ID: 'B_' + Date.now(), Bank_Name: result.bankName, T_STMP_ADD: new Date().toISOString(), T_STMP_UPD: new Date().toISOString() } : undefined;
        const targetBankId = bank ? bank.Bank_ID : newBankObj!.Bank_ID;
        const newBranchObj: BankBranch = { Branch_ID: 'BR_' + Date.now(), Branch_Name: result.branchName, IFSC_Code: result.ifsc.toUpperCase(), Bank_ID: targetBankId, T_STMP_ADD: new Date().toISOString(), T_STMP_UPD: new Date().toISOString() };

        setEditForm({ ...editForm, IFSC_Code: result.ifsc.toUpperCase(), Bank_ID: targetBankId, Branch_ID: newBranchObj.Branch_ID });
        if (newBankObj) setStagedBank(newBankObj);
        setStagedBranch(newBranchObj);
        setSearchFeedback({ type: 'info', message: `Detected: ${result.bankName}, ${result.branchName}` });
      }
    } catch (err) {
      setSearchFeedback({ type: 'error', message: 'Search failed.' });
    } finally { setIsSearching(false); }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && editForm) {
      const reader = new FileReader();
      reader.onloadend = () => { setEditForm({ ...editForm, Account_Passbook_Doc: reader.result as string }); };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editForm) {
      if (!editForm.Account_Number || !editForm.IFSC_Code) {
        alert("Bank details are required.");
        return;
      }
      onUpdate(editForm, stagedBank || undefined, stagedBranch || undefined);
      setSelectedBLO(null);
    }
  };

  const renderPreview = (doc: string) => {
    if (!doc) return <div className="p-5 text-center text-muted border rounded">No document uploaded yet.</div>;
    if (doc.includes('drive.google.com')) {
      const previewUrl = doc.replace('/view?usp=sharing', '/preview').replace('/view', '/preview');
      return <iframe src={previewUrl} className="w-100 rounded border shadow-sm" style={{ height: '400px' }} title="Doc Preview"></iframe>;
    }
    if (doc.startsWith('data:image')) return <img src={doc} alt="Passbook" className="img-fluid rounded border shadow-sm" style={{ maxHeight: '400px' }} />;
    if (doc.startsWith('data:application/pdf')) return <iframe src={doc} className="w-100 rounded border" style={{ height: '400px' }} title="PDF Preview"></iframe>;
    return <div className="alert alert-secondary">Format not supported for inline preview.</div>;
  };

  if (selectedBLO && editForm) {
    const isLocked = editForm.Verified === 'yes' && !isAdmin;
    const availableDesignations = designations.filter(d => String(d.Dept_ID).trim() === String(editForm.Dept_ID).trim());

    return (
      <div className="container-fluid py-2">
        <div className="card shadow-lg border-0 overflow-hidden">
          <div className="card-header bg-primary text-white p-4 d-flex justify-content-between align-items-center">
            <h5 className="mb-0 fw-bold">Account Entry Finalization: {selectedBLO.BLO_Name}</h5>
            <button onClick={() => setSelectedBLO(null)} className="btn-close btn-close-white"></button>
          </div>
          <div className="card-body p-4 bg-light-subtle">
            <form onSubmit={handleSubmit}>
              {isLocked && <div className="alert alert-warning mb-4 fw-bold"><i className="bi bi-lock-fill me-2"></i> This record is verified and locked for editing.</div>}

              <div className="row g-4">
                {/* Assembly Section */}
                <div className="col-12">
                  <div className="card border-0 shadow-sm bg-light">
                    <div className="card-body">
                      <h6 className="text-secondary fw-bold text-uppercase small mb-3">Assembly & Region</h6>
                      <div className="row g-3">
                        <div className="col-md-2"><label className="form-label extra-small fw-bold">AC No</label><input disabled className="form-control form-control-sm" value={editForm.AC_No} /></div>
                        <div className="col-md-5"><label className="form-label extra-small fw-bold">Assembly Name</label><input disabled className="form-control form-control-sm" value={editForm.AC_Name} /></div>
                        <div className="col-md-5"><label className="form-label extra-small fw-bold">Tehsil</label><input disabled className="form-control form-control-sm" value={editForm.Tehsil} /></div>
                      </div>
                    </div>
                  </div>
                </div>

                {/* BLO Details Section */}
                <div className="col-md-6">
                  <div className="card border-0 shadow-sm h-100">
                    <div className="card-body">
                      <h6 className="text-primary fw-bold text-uppercase small mb-3">Officer Profile</h6>
                      <div className="mb-3"><label className="form-label extra-small fw-bold">BLO Name</label><input disabled={isLocked} className="form-control" value={editForm.BLO_Name} onChange={e => setEditForm({...editForm, BLO_Name: e.target.value})} /></div>
                      <div className="row g-2 mb-3">
                        <div className="col-6"><label className="form-label extra-small fw-bold">Mobile</label><input disabled={isLocked} className="form-control" value={editForm.Mobile} onChange={e => setEditForm({...editForm, Mobile: e.target.value})} /></div>
                        <div className="col-6"><label className="form-label extra-small fw-bold">EPIC</label><input disabled={isLocked} className="form-control text-uppercase" value={editForm.EPIC} onChange={e => setEditForm({...editForm, EPIC: e.target.value.toUpperCase()})} /></div>
                      </div>
                      <div className="row g-2">
                        <div className="col-6">
                          <label className="form-label extra-small fw-bold">Department</label>
                          <select disabled={isLocked} className="form-select" value={editForm.Dept_ID} onChange={e => setEditForm({...editForm, Dept_ID: e.target.value, Desg_ID: ''})}>
                            <option value="">Select Dept</option>
                            {departments.map(d => <option key={d.Dept_ID} value={d.Dept_ID}>{d.Dept_Name}</option>)}
                          </select>
                        </div>
                        <div className="col-6">
                          <label className="form-label extra-small fw-bold">Designation</label>
                          <select disabled={isLocked} className="form-select" value={editForm.Desg_ID} onChange={e => setEditForm({...editForm, Desg_ID: e.target.value})}>
                            <option value="">Select Desg</option>
                            {availableDesignations.map(d => <option key={d.Desg_ID} value={d.Desg_ID}>{d.Desg_Name}</option>)}
                          </select>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>

                {/* Bank Details Section */}
                <div className="col-md-6">
                  <div className="card border-0 shadow-sm h-100 border-start border-primary border-5">
                    <div className="card-body">
                      <h6 className="text-primary fw-bold text-uppercase small mb-3">Bank Account Information</h6>
                      <div className="mb-3">
                        <label className="form-label extra-small fw-bold">IFSC Code *</label>
                        <div className="input-group">
                          <input disabled={isLocked} className="form-control font-monospace text-uppercase" maxLength={11} value={editForm.IFSC_Code} onChange={e => setEditForm({...editForm, IFSC_Code: e.target.value.toUpperCase()})} />
                          <button type="button" className="btn btn-primary px-3" onClick={() => triggerIFSCSearch(editForm.IFSC_Code)} disabled={isSearching || isLocked}>
                            {isSearching ? <i className="bi bi-arrow-repeat spin"></i> : 'Search'}
                          </button>
                        </div>
                        {searchFeedback.type !== 'none' && <div className={`mt-1 extra-small text-${searchFeedback.type === 'error' ? 'danger' : 'success'}`}>{searchFeedback.message}</div>}
                      </div>
                      <div className="mb-3">
                        <label className="form-label extra-small fw-bold">Account Number *</label>
                        <input disabled={isLocked} className="form-control font-monospace fw-bold" value={String(editForm.Account_Number || '')} onChange={e => setEditForm({...editForm, Account_Number: e.target.value.replace(/\D/g, '')})} placeholder="Enter Bank Account No" />
                      </div>
                      <div className="mb-0">
                        <label className="form-label extra-small fw-bold">Upload Passbook Proof *</label>
                        <input disabled={isLocked} type="file" className="form-control" onChange={handleFileChange} accept=".pdf,image/*" />
                      </div>
                    </div>
                  </div>
                </div>

                {/* Preview Section */}
                <div className="col-12">
                  <div className="card border-0 shadow-sm">
                    <div className="card-body">
                      <h6 className="text-muted fw-bold text-uppercase extra-small mb-3">Document Preview</h6>
                      {renderPreview(editForm.Account_Passbook_Doc)}
                    </div>
                  </div>
                </div>
              </div>

              <div className="mt-5 text-end">
                <button type="button" onClick={() => setSelectedBLO(null)} className="btn btn-outline-secondary me-3">Discard Changes</button>
                <button type="submit" disabled={isLocked} className="btn btn-primary px-5 py-2 fw-bold shadow">SAVE & FINALIZE</button>
              </div>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="container-fluid py-2">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h3 className="fw-bold mb-0">Booth Bank Directory</h3>
      </div>

      {isAdmin && (
        <div className="card border-0 shadow-sm mb-4 bg-white">
          <div className="card-body p-3">
            <div className="row g-3 align-items-center">
              <div className="col-md-auto"><span className="fw-bold extra-small text-muted text-uppercase">Admin Filters:</span></div>
              <div className="col-md-3">
                <select className="form-select form-select-sm" value={filterTehsil} onChange={e => setFilterTehsil(e.target.value)}>
                  <option value="">All Tehsils</option>
                  {uniqueTehsils.map(t => <option key={t} value={t}>{t}</option>)}
                </select>
              </div>
              <div className="col-md-3">
                <select className="form-select form-select-sm" value={filterAC} onChange={e => setFilterAC(e.target.value)}>
                  <option value="">All Assembly Constituencies</option>
                  {uniqueACs.map(ac => <option key={ac} value={ac}>{ac}</option>)}
                </select>
              </div>
              <div className="col-md-auto ms-auto">
                <button className="btn btn-sm btn-outline-secondary" onClick={() => { setFilterTehsil(''); setFilterAC(''); }}>Reset View</button>
              </div>
            </div>
          </div>
        </div>
      )}

      <div className="card border-0 shadow-sm overflow-hidden">
        <div className="table-responsive">
          <table className="table table-hover align-middle mb-0">
            <thead className="table-dark">
              <tr>
                <th className="py-3 px-4 fw-bold small">PART / ASSEMBLY</th>
                <th className="py-3 px-4 fw-bold small">BLO NAME / TEHSIL</th>
                <th className="py-3 px-4 fw-bold small text-primary-emphasis bg-primary-subtle">ACCOUNT NUMBER</th>
                <th className="py-3 px-4 fw-bold small text-center">STATUS</th>
                <th className="py-3 px-4 fw-bold small text-end">ACTIONS</th>
              </tr>
            </thead>
            <tbody>
              {paginatedAccounts.map(blo => (
                <tr key={blo.BLO_ID}>
                  <td className="px-4 py-3">
                    <div className="fw-bold">P-{blo.Part_No}</div>
                    <div className="extra-small text-muted">{blo.AC_Name}</div>
                  </td>
                  <td className="px-4 py-3">
                    <div className="fw-semibold text-primary">{blo.BLO_Name}</div>
                    <div className="extra-small text-muted text-uppercase">{blo.Tehsil}</div>
                  </td>
                  <td className="px-4 py-3 font-monospace">
                    {blo.Account_Number ? <span className="fw-bold">{blo.Account_Number}</span> : <span className="text-danger extra-small italic">Bank Details Pending</span>}
                  </td>
                  <td className="px-4 py-3 text-center">
                    {blo.Verified === 'yes' ? <span className="badge bg-success-subtle text-success rounded-pill px-3">Verified</span> : <span className="badge bg-warning-subtle text-warning-emphasis rounded-pill px-3">Entry Done</span>}
                  </td>
                  <td className="px-4 py-3 text-end">
                    <button onClick={() => handleEdit(blo)} className="btn btn-sm btn-primary px-3 shadow-sm"><i className="bi bi-pencil me-1"></i> Edit Record</button>
                  </td>
                </tr>
              ))}
              {paginatedAccounts.length === 0 && <tr><td colSpan={5} className="text-center py-5 text-muted italic">No records found for the current filter.</td></tr>}
            </tbody>
          </table>
        </div>

        {/* Universal Pagination Footer */}
        <div className="card-footer bg-white border-top p-3">
          <div className="row g-3 align-items-center">
            <div className="col-md-auto text-muted extra-small">
              Showing {filteredAccounts.length > 0 ? (currentPage - 1) * (pageSize === 'all' ? filteredAccounts.length : Number(pageSize)) + 1 : 0} to {Math.min(currentPage * (pageSize === 'all' ? filteredAccounts.length : Number(pageSize)), filteredAccounts.length)} of {filteredAccounts.length} records
            </div>
            <div className="col-md-auto ms-auto d-flex align-items-center gap-3">
              <div className="d-flex align-items-center gap-2">
                <span className="extra-small text-muted text-uppercase fw-bold">Records Per Page:</span>
                <select className="form-select form-select-sm" style={{ width: '90px' }} value={pageSize} onChange={e => setPageSize(e.target.value === 'all' ? 'all' : Number(e.target.value))}>
                  <option value={10}>10</option>
                  <option value={25}>25</option>
                  <option value={50}>50</option>
                  <option value={100}>100</option>
                  <option value="all">Show All</option>
                </select>
              </div>
              <div className="btn-group">
                <button className="btn btn-sm btn-outline-secondary px-3" disabled={currentPage === 1} onClick={() => setCurrentPage(p => p - 1)}><i className="bi bi-chevron-left"></i> Prev</button>
                <button className="btn btn-sm btn-outline-secondary px-3" disabled={currentPage >= totalPages} onClick={() => setCurrentPage(p => p + 1)}>Next <i className="bi bi-chevron-right"></i></button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

