      }
      alert('User record successfully synchronized with the cloud.');
    } catch (err) {
      alert('Failed to update user. Please check connection.');
    } finally {
      setIsSaving(false);
    }
  };

  const filteredUsers = users.filter(u => 
    u.Officer_Name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    u.User_Name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    u.Designation.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const UserEditForm = ({ isSelf }: { isSelf: boolean }) => (
    <div className="card shadow-lg border-0">
      <div className="card-header bg-primary text-white py-3 border-0">
        <h5 className="mb-0 fw-bold d-flex align-items-center">
          <i className={`bi ${isSelf ? 'bi-person-circle' : 'bi-person-gear'} me-2`}></i>
          {isSelf ? 'My Profile Details' : `Manage User: ${editForm?.Officer_Name}`}
        </h5>
      </div>
      <div className="card-body p-4 bg-white">
        <form onSubmit={handleSave}>
          <div className="row g-4">
            <div className="col-md-6">
              <label className="form-label extra-small fw-bold text-muted text-uppercase mb-2">Full Officer Name</label>
              <div className="input-group">
                <span className="input-group-text bg-light border-end-0"><i className="bi bi-person"></i></span>
                <input 
                  type="text" 
                  className="form-control border-start-0 bg-light" 
                  value={editForm?.Officer_Name || ''} 
                  onChange={e => setEditForm(prev => prev ? {...prev, Officer_Name: e.target.value} : null)}
                  required
                />
              </div>
            </div>
            <div className="col-md-6">
              <label className="form-label extra-small fw-bold text-muted text-uppercase mb-2">Mobile Contact Number</label>
              <div className="input-group">
                <span className="input-group-text bg-light border-end-0"><i className="bi bi-phone"></i></span>
                <input 
                  type="text" 
                  className="form-control border-start-0 bg-light" 
                  value={editForm?.Mobile || ''} 
                  onChange={e => setEditForm(prev => prev ? {...prev, Mobile: e.target.value} : null)}
                  required
                />
              </div>
            </div>
            <div className="col-md-6">
              <label className="form-label extra-small fw-bold text-muted text-uppercase mb-2">Portal User ID (Read Only)</label>
              <div className="input-group">
                <span className="input-group-text bg-light border-end-0"><i className="bi bi-shield-lock"></i></span>
                <input 
                  type="text" 
                  className="form-control border-start-0 bg-light-subtle" 
                  value={editForm?.User_Name || ''} 
                  disabled
                />
              </div>
            </div>
            <div className="col-md-6">
              <label className="form-label extra-small fw-bold text-muted text-uppercase mb-2">Portal Access Password</label>
              <div className="input-group shadow-sm">
                <span className="input-group-text bg-white border-end-0"><i className="bi bi-key-fill text-primary"></i></span>
                <input 
                  type="text" 
                  className="form-control border-start-0" 
                  value={editForm?.Password || ''} 
                  onChange={e => setEditForm(prev => prev ? {...prev, Password: e.target.value} : null)}
                  required
                  placeholder="Change current password"
                />
              </div>
            </div>
            <div className="col-md-6">
              <label className="form-label extra-small fw-bold text-muted text-uppercase mb-2">Official Designation</label>
              <input 
                type="text" 
                className="form-control bg-light" 
                value={editForm?.Designation || ''} 
                onChange={e => setEditForm(prev => prev ? {...prev, Designation: e.target.value} : null)}
                disabled={!isAdmin}
              />
            </div>
            {isAdmin && (
              <div className="col-md-6">
                <label className="form-label extra-small fw-bold text-muted text-uppercase mb-2">Security Role</label>
                <select 
                  className="form-select bg-light" 
                  value={editForm?.User_Type} 
                  onChange={e => setEditForm(prev => prev ? {...prev, User_Type: e.target.value as UserType} : null)}
                >
                  <option value={UserType.ADMIN}>Administrator (Full Access)</option>
                  <option value={UserType.TEHSIL}>Tehsil User (Zonal Access)</option>
                </select>
              </div>
            )}
          </div>

          <div className="mt-5 d-flex gap-2 justify-content-end align-items-center">
            {isAdmin && selectedUser && (
              <button 
                type="button" 
                className="btn btn-link text-muted text-decoration-none me-auto"
                onClick={() => { setSelectedUser(null); setEditForm(null); }}
              >
                Back to User List
              </button>
            )}
            <button 
              type="submit" 
              className="btn btn-primary px-5 py-2 shadow-lg fw-bold" 
              disabled={isSaving}
            >
              {isSaving ? (
                <><span className="spinner-border spinner-border-sm me-2"></span>Syncing...</>
              ) : (
                <><i className="bi bi-cloud-upload me-2"></i> Update Official Record</>
              )}
            </button>
          </div>
        </form>
      </div>
    </div>
  );

  return (
    <div className="container-fluid py-2">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <div>
          <h3 className="fw-bold mb-1">Account & Security Hub</h3>
          <p className="text-muted small mb-0">
            {isAdmin ? 'Management of all regional access profiles and security settings.' : 'Update your officer profile and manage portal access credentials.'}
          </p>
        </div>
      </div>

      {isAdmin ? (
        <div className="row g-4">
          <div className="col-lg-12">
            {selectedUser ? (
              <div className="row justify-content-center">
                <div className="col-lg-8">
                  <UserEditForm isSelf={selectedUser.User_ID === currentUser.User_ID} />
                </div>
              </div>
            ) : (
              <>
                <div className="card border-0 shadow-sm mb-4 bg-white">
                  <div className="card-body p-3">
                    <div className="row align-items-center">
                      <div className="col-md-6">
                        <div className="input-group">
                          <span className="input-group-text bg-white border-end-0"><i className="bi bi-search text-muted"></i></span>
                          <input 
                            type="text" 
                            className="form-control border-start-0" 
                            placeholder="Search by name, ID or designation..."
                            value={searchTerm}
                            onChange={e => setSearchTerm(e.target.value)}
                          />
                        </div>
                      </div>
                      <div className="col-md-auto ms-auto">
                         <span className="badge bg-primary px-3 py-2">{filteredUsers.length} Users Listed</span>
                      </div>
                    </div>
                  </div>
                </div>

                <div className="card border-0 shadow-sm overflow-hidden bg-white">
                  <div className="table-responsive">
                    <table className="table table-hover align-middle mb-0">
                      <thead className="table-dark">
                        <tr>
                          <th className="py-3 px-4 fw-bold small">OFFICER / DESIGNATION</th>
                          <th className="py-3 px-4 fw-bold small">USER ID</th>
                          <th className="py-3 px-4 fw-bold small">MOBILE</th>
                          <th className="py-3 px-4 fw-bold small">ACCESS TYPE</th>
                          <th className="py-3 px-4 fw-bold small text-end">ACTIONS</th>
                        </tr>
                      </thead>
                      <tbody>
                        {filteredUsers.map(u => (
                          <tr key={u.User_ID}>
                            <td className="px-4 py-3">
                              <div className="fw-bold text-dark">{u.Officer_Name}</div>
                              <div className="extra-small text-muted fw-semibold">{u.Designation}</div>
                            </td>
                            <td className="px-4 py-3 font-monospace small text-primary">{u.User_Name}</td>
                            <td className="px-4 py-3 small">{u.Mobile}</td>
                            <td className="px-4 py-3">
                              <span className={`badge ${u.User_Type === UserType.ADMIN ? 'bg-primary' : 'bg-info'} text-uppercase`} style={{ fontSize: '0.6rem' }}>
                                {u.User_Type}
                              </span>
                            </td>
                            <td className="px-4 py-3 text-end">
                              <button 
                                onClick={() => handleEdit(u)} 
                                className="btn btn-sm btn-outline-primary px-4 fw-bold shadow-sm"
                              >
                                {u.User_ID === currentUser.User_ID ? 'Manage My Profile' : 'Edit Access'}
                              </button>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              </>
            )}
          </div>
        </div>
      ) : (
        <div className="row justify-content-center">
          <div className="col-lg-8">
            <UserEditForm isSelf={true} />
            <div className="mt-4 card border-0 shadow-sm bg-info bg-opacity-10 p-4">
               <h6 className="fw-bold text-info"><i className="bi bi-shield-lock-fill me-2"></i> Security Tip</h6>
               <p className="small text-muted mb-0">
                 Regularly update your password to maintain the integrity of election data. Ensure your mobile number is always current for emergency notifications.
               </p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default UserManagement;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { BLOAccount, User, UserType, Bank, BankBranch, Department, Designation } from '../types';
import { searchIFSCViaGemini } from '../services/geminiService';

interface AccountEntryProps {
  user: User;
  accounts: BLOAccount[];
  banks: Bank[];
  branches: BankBranch[];
  departments: Department[];
  designations: Designation[];
  onUpdate: (updated: BLOAccount, newBank?: Bank, newBranch?: BankBranch) => void;
}

const AccountEntry: React.FC<AccountEntryProps> = ({ user, accounts, banks, branches, departments, designations, onUpdate }) => {
  const [selectedBLO, setSelectedBLO] = useState<BLOAccount | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const [editForm, setEditForm] = useState<BLOAccount | null>(null);
  const [filterTehsil, setFilterTehsil] = useState('');

  const [searchFeedback, setSearchFeedback] = useState<{ type: 'success' | 'error' | 'info' | 'none', message: string }>({ type: 'none', message: '' });
  const [stagedBank, setStagedBank] = useState<Bank | null>(null);
  const [stagedBranch, setStagedBranch] = useState<BankBranch | null>(null);

  const lastSearchedRef = useRef<string>('');
  const isAdmin = user.User_Type === UserType.ADMIN;

  // Helper to map Designation ID to Name
  const getDesgName = (id: string) => {
    const desg = designations.find(d => String(d.Desg_ID).trim() === String(id).trim());
    return desg ? desg.Desg_Name : 'BLO';
  };

  const getDeptName = (id: string) => {
    const dept = departments.find(d => String(d.Dept_ID).trim() === String(id).trim());
    return dept ? dept.Dept_Name : '---';
  };

  // Unique list of Tehsils for Admin Filter
  const tehsils = useMemo(() => Array.from(new Set(accounts.map(a => a.Tehsil))).sort(), [accounts]);

  // Filtering Logic
  const filteredAccounts = useMemo(() => {
    let list = isAdmin 
      ? accounts 
      : accounts.filter(a => String(a.User_ID).trim() === String(user.User_ID).trim());

    if (isAdmin && filterTehsil) {
      list = list.filter(a => a.Tehsil === filterTehsil);
    }
    return list;
  }, [accounts, user, isAdmin, filterTehsil]);

  const handleEdit = (blo: BLOAccount) => {
    setSelectedBLO(blo);
    setEditForm({ ...blo });
    setSearchFeedback({ type: 'none', message: '' });
    setStagedBank(null);
    setStagedBranch(null);
    lastSearchedRef.current = blo.IFSC_Code || '';
  };

  const triggerIFSCSearch = async (ifscCode: string) => {
    if (!ifscCode || ifscCode.length !== 11) {
      setSearchFeedback({ type: 'error', message: 'Enter valid 11-digit IFSC.' });
      return;
    }

    setIsSearching(true);
    setSearchFeedback({ type: 'none', message: '' });
    lastSearchedRef.current = ifscCode;

    const localBranch = branches.find(br => String(br.IFSC_Code).toUpperCase() === ifscCode.toUpperCase());
    if (localBranch) {
      setEditForm(prev => prev ? ({ ...prev, Bank_ID: localBranch.Bank_ID, Branch_ID: localBranch.Branch_ID }) : null);
      setSearchFeedback({ type: 'success', message: 'Found in local database.' });
      setIsSearching(false);
      return;
    }

    try {
      const result = await searchIFSCViaGemini(ifscCode);
      if (result && editForm) {
        let bank = banks.find(b => String(b.Bank_Name).toLowerCase() === result.bankName.toLowerCase());
        const newBankObj: Bank | undefined = !bank ? { 
          Bank_ID: 'B_' + Date.now(), 
          Bank_Name: result.bankName, 
          T_STMP_ADD: new Date().toISOString(), 
          T_STMP_UPD: new Date().toISOString() 
        } : undefined;

        const targetBankId = bank ? bank.Bank_ID : newBankObj!.Bank_ID;
        const newBranchObj: BankBranch = { 
          Branch_ID: 'BR_' + Date.now(), 
          Branch_Name: result.branchName, 
          IFSC_Code: result.ifsc.toUpperCase(), 
          Bank_ID: targetBankId, 
          T_STMP_ADD: new Date().toISOString(), 
          T_STMP_UPD: new Date().toISOString() 
        };

        setEditForm({ ...editForm, IFSC_Code: result.ifsc.toUpperCase(), Bank_ID: targetBankId, Branch_ID: newBranchObj.Branch_ID });
        if (newBankObj) setStagedBank(newBankObj);
        setStagedBranch(newBranchObj);
        setSearchFeedback({ type: 'info', message: `Detected: ${result.bankName}, ${result.branchName}` });
      }
    } catch (err) {
      setSearchFeedback({ type: 'error', message: 'Search failed.' });
    } finally {
      setIsSearching(false);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && editForm) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setEditForm({ ...editForm, Account_Passbook_Doc: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editForm) {
      if (!editForm.Account_Number || !editForm.IFSC_Code) {
        alert("Account Number and IFSC are required.");
        return;
      }
      onUpdate(editForm, stagedBank || undefined, stagedBranch || undefined);
      setSelectedBLO(null);
    }
  };

  const renderPreview = (doc: string) => {
    if (!doc) return <div className="p-5 text-center text-muted border rounded bg-white">No document proof uploaded.</div>;
    if (doc.includes('drive.google.com')) {
      const previewUrl = doc.replace('/view?usp=sharing', '/preview').replace('/view', '/preview');
      return <iframe src={previewUrl} className="w-100 rounded border shadow-sm" style={{ height: '400px' }} title="Doc Preview"></iframe>;
    }
    if (doc.startsWith('data:image')) return <img src={doc} alt="Passbook" className="img-fluid rounded border shadow-sm d-block mx-auto" style={{ maxHeight: '400px' }} />;
    if (doc.startsWith('data:application/pdf')) return <iframe src={doc} className="w-100 rounded border" style={{ height: '400px' }} title="PDF Preview"></iframe>;
    return <div className="alert alert-secondary">Preview not available for this format.</div>;
  };

  if (selectedBLO && editForm) {
    const isLocked = editForm.Verified === 'yes' && !isAdmin;
    const availableDesignations = designations.filter(d => String(d.Dept_ID).trim() === String(editForm.Dept_ID).trim());

    return (
      <div className="container-fluid py-2">
        <div className="card shadow-lg border-0 overflow-hidden">
          <div className="card-header bg-primary text-white p-4 d-flex justify-content-between align-items-center">
            <h5 className="mb-0 fw-bold"><i className="bi bi-file-earmark-person me-2"></i> Account Entry Finalization: {selectedBLO.BLO_Name}</h5>
            <button onClick={() => setSelectedBLO(null)} className="btn-close btn-close-white"></button>
          </div>
          <div className="card-body p-4 bg-light-subtle">
            <form onSubmit={handleSubmit}>
              {isLocked && <div className="alert alert-warning mb-4 fw-bold shadow-sm"><i className="bi bi-lock-fill me-2"></i> This record is verified and locked for editing.</div>}

              <div className="row g-4">
                {/* 1. Assembly & Region Section */}
                <div className="col-12">
                  <div className="card border-0 shadow-sm bg-white">
                    <div className="card-body">
                      <h6 className="text-secondary fw-bold text-uppercase small mb-3 border-bottom pb-2"><i className="bi bi-geo-alt-fill me-2"></i> Assembly & Region</h6>
                      <div className="row g-3">
                        <div className="col-md-2"><label className="form-label extra-small fw-bold text-muted">AC No</label><input disabled className="form-control form-control-sm bg-light" value={editForm.AC_No} /></div>
                        <div className="col-md-5"><label className="form-label extra-small fw-bold text-muted">Assembly Name</label><input disabled className="form-control form-control-sm bg-light" value={editForm.AC_Name} /></div>
                        <div className="col-md-5"><label className="form-label extra-small fw-bold text-muted">Tehsil</label><input disabled className="form-control form-control-sm bg-light" value={editForm.Tehsil} /></div>
                      </div>
                    </div>
                  </div>
                </div>

                {/* 2. Officer Profile Section */}
                <div className="col-md-6">
                  <div className="card border-0 shadow-sm h-100 bg-white">
                    <div className="card-body">
                      <h6 className="text-primary fw-bold text-uppercase small mb-3 border-bottom pb-2"><i className="bi bi-person-badge-fill me-2"></i> Officer Profile</h6>
                      <div className="mb-3"><label className="form-label extra-small fw-bold">BLO Name</label><input disabled={isLocked} className="form-control fw-semibold" value={editForm.BLO_Name} onChange={e => setEditForm({...editForm, BLO_Name: e.target.value})} /></div>
                      <div className="row g-2 mb-3">
                        <div className="col-6"><label className="form-label extra-small fw-bold">Mobile</label><input disabled={isLocked} className="form-control" value={editForm.Mobile} onChange={e => setEditForm({...editForm, Mobile: e.target.value})} /></div>
                        <div className="col-6"><label className="form-label extra-small fw-bold">EPIC</label><input disabled={isLocked} className="form-control text-uppercase" value={editForm.EPIC} onChange={e => setEditForm({...editForm, EPIC: e.target.value.toUpperCase()})} /></div>
                      </div>
                      <div className="row g-2">
                        <div className="col-6">
                          <label className="form-label extra-small fw-bold">Department</label>
                          <select disabled={isLocked} className="form-select" value={editForm.Dept_ID} onChange={e => setEditForm({...editForm, Dept_ID: e.target.value, Desg_ID: ''})}>
                            <option value="">Select Dept</option>
                            {departments.map(d => <option key={d.Dept_ID} value={d.Dept_ID}>{d.Dept_Name}</option>)}
                          </select>
                        </div>
                        <div className="col-6">
                          <label className="form-label extra-small fw-bold">Designation</label>
                          <select disabled={isLocked} className="form-select" value={editForm.Desg_ID} onChange={e => setEditForm({...editForm, Desg_ID: e.target.value})}>
                            <option value="">Select Desg</option>
                            {availableDesignations.map(d => <option key={d.Desg_ID} value={d.Desg_ID}>{d.Desg_Name}</option>)}
                          </select>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>

                {/* 3. Bank Account Information Section - HIGHLIGHTED IFSC SEARCH */}
                <div className="col-md-6">
                  <div className="card border-0 shadow-sm h-100 border-start border-primary border-5 bg-white">
                    <div className="card-body">
                      <h6 className="text-primary fw-bold text-uppercase small mb-3 border-bottom pb-2"><i className="bi bi-bank me-2"></i> Bank Account Information</h6>
                      <div className="mb-4">
                        <label className="form-label fw-bold text-primary small">IFSC Code (HIGHLIGHTED SEARCH) *</label>
                        <div className="input-group input-group-lg shadow-sm border border-primary rounded overflow-hidden">
                          <input 
                            disabled={isLocked} 
                            className="form-control font-monospace text-uppercase fw-bold border-0" 
                            maxLength={11} 
                            placeholder="SBIN000XXXX"
                            value={editForm.IFSC_Code} 
                            onChange={e => setEditForm({...editForm, IFSC_Code: e.target.value.toUpperCase()})} 
                          />
                          <button 
                            type="button" 
                            className="btn btn-primary px-4 fw-bold" 
                            onClick={() => triggerIFSCSearch(editForm.IFSC_Code)} 
                            disabled={isSearching || isLocked}
                          >
                            {isSearching ? <i className="bi bi-arrow-repeat spin"></i> : 'SEARCH'}
                          </button>
                        </div>
                        {searchFeedback.type !== 'none' && (
                          <div className={`mt-2 p-2 rounded extra-small fw-bold bg-${searchFeedback.type === 'error' ? 'danger' : 'success'}-subtle text-${searchFeedback.type === 'error' ? 'danger' : 'success'}`}>
                            {searchFeedback.message}
                          </div>
                        )}
                      </div>
                      <div className="mb-3">
                        <label className="form-label extra-small fw-bold">Account Number *</label>
                        <input disabled={isLocked} className="form-control form-control-lg font-monospace fw-bold border-primary" value={String(editForm.Account_Number || '')} onChange={e => setEditForm({...editForm, Account_Number: e.target.value.replace(/\D/g, '')})} placeholder="Enter Full Account Number" />
                      </div>
                      <div className="mb-0">
                        <label className="form-label extra-small fw-bold">Upload Passbook Proof *</label>
                        <input disabled={isLocked} type="file" className="form-control" onChange={handleFileChange} accept=".pdf,image/*" />
                      </div>
                    </div>
                  </div>
                </div>

                {/* 4. Document Preview Section */}
                <div className="col-12">
                  <div className="card border-0 shadow-sm bg-white">
                    <div className="card-body">
                      <h6 className="text-muted fw-bold text-uppercase extra-small mb-3"><i className="bi bi-eye-fill me-2"></i> Document Preview</h6>
                      {renderPreview(editForm.Account_Passbook_Doc)}
                    </div>
                  </div>
                </div>
              </div>

              <div className="mt-5 text-end p-3 border-top bg-white rounded shadow-sm">
                <button type="button" onClick={() => setSelectedBLO(null)} className="btn btn-outline-secondary me-3 px-4">Discard</button>
                <button type="submit" disabled={isLocked} className="btn btn-primary px-5 py-2 fw-bold shadow-lg">SAVE & FINALIZE</button>
              </div>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="container-fluid py-2">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <div>
          <h3 className="fw-bold mb-0">Booth Bank Directory</h3>
          <p className="text-muted small mb-0">Manage bank details for your assigned election personnel.</p>
        </div>
      </div>

      {isAdmin && (
        <div className="card border-0 shadow-sm mb-4 bg-white">
          <div className="card-body p-3">
            <div className="row g-3 align-items-center">
              <div className="col-md-auto"><span className="fw-bold extra-small text-muted text-uppercase">Admin Tehsil Filter:</span></div>
              <div className="col-md-4">
                <select className="form-select form-select-sm" value={filterTehsil} onChange={e => setFilterTehsil(e.target.value)}>
                  <option value="">All Tehsils (District Wide)</option>
                  {tehsils.map(t => <option key={t} value={t}>{t}</option>)}
                </select>
              </div>
              <div className="col-md-auto ms-auto">
                <span className="badge bg-primary px-3 py-2">{filteredAccounts.length} Records Found</span>
              </div>
            </div>
          </div>
        </div>
      )}

      <div className="card border-0 shadow-sm overflow-hidden bg-white">
        <div className="table-responsive">
          <table className="table table-hover align-middle mb-0">
            <thead className="table-dark">
              <tr>
                <th className="py-3 px-4 fw-bold small">PART / ASSEMBLY</th>
                <th className="py-3 px-4 fw-bold small">BLO NAME & DESIGNATION</th>
                <th className="py-3 px-4 fw-bold small bg-primary-subtle text-primary">ACCOUNT NUMBER</th>
                <th className="py-3 px-4 fw-bold small text-center">STATUS</th>
