      branches: getSheetData('Bank_Branch'),
      departments: getSheetData('Department'),
      designations: getSheetData('Designation')
    };

    return createSafeResponse(data);
  } catch (err) {
    return createSafeResponse({ success: false, error: err.toString() });
  }
}

function doPost(e) {
  try {
    const params = JSON.parse(e.postData.contents);
    const action = params.action;
    const payload = params.payload;

    let result = { success: false };

    // Robust ID lookup
    const id = payload.BLO_ID || payload.Supervisor_ID || payload.Avihit_ID || payload.ID;

    if (action === 'updateAccount') {
      result = updateRecord('BLO_Account', 'BLO_ID', id, payload);
    } else if (action === 'updateAvihitAccount') {
      result = updateRecord('Avihit_Account', 'BLO_ID', id, payload);
    } else if (action === 'updateSupervisorAccount') {
      result = updateRecord('Supervisor_Account', 'BLO_ID', id, payload);
    } else if (action === 'verifyAccount') {
      result = updateRecord('BLO_Account', 'BLO_ID', id, { Verified: payload.Verified });
    } else if (action === 'verifyAvihitAccount') {
      result = updateRecord('Avihit_Account', 'BLO_ID', id, { Verified: payload.Verified });
    } else if (action === 'verifySupervisorAccount') {
      result = updateRecord('Supervisor_Account', 'BLO_ID', id, { Verified: payload.Verified });
    } else if (action === 'updateUser') {
      result = updateRecord('User', 'User_ID', payload.User_ID, payload);
    } else if (action === 'addBank') {
      result = addRecord('Bank', payload);
    } else if (action === 'addBranch') {
      result = addRecord('Bank_Branch', payload);
    }

    return createSafeResponse(result);
  } catch (error) {
    return createSafeResponse({ success: false, error: "Post Error: " + error.toString() });
  }
}

function createSafeResponse(data) {
  const json = JSON.stringify(data);
  return ContentService.createTextOutput(json)
    .setMimeType(ContentService.MimeType.TEXT);
}

function getSheetData(sheetName) {
  try {
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const sheet = ss.getSheetByName(sheetName);
    if (!sheet) return [];

    const values = sheet.getDataRange().getValues();
    if (values.length <= 1) return [];

    const rawHeaders = values[0];
    const headers = rawHeaders.map(h => normalizeHeader(h));
    const data = [];

    // Identity & Name Column Aliasing
    const idAlts = ['BLO_ID', 'Supervisor_ID', 'Avihit_ID', 'ID', 'User_ID'];
    const nameAlts = ['BLO_Name', 'Supervisor_Name', 'Avihit_Name', 'Officer_Name', 'Name'];
    const genderAlts = ['Gender', 'Sex'];

    let idHeader = idAlts.find(alt => headers.includes(alt)) || '';
    let nameHeader = nameAlts.find(alt => headers.includes(alt)) || '';
    let genderHeader = genderAlts.find(alt => headers.includes(alt)) || '';

    for (let i = 1; i < values.length; i++) {
      const obj = {};
      for (let j = 0; j < headers.length; j++) {
        const h = headers[j];
        const val = String(values[i][j]);
        obj[h] = val;

        // Ensure frontend sees standardized keys
        if (sheetName.toLowerCase().includes('account')) {
          if (h === idHeader) obj['BLO_ID'] = val;
          if (h === nameHeader) obj['BLO_Name'] = val;
          if (h === genderHeader) obj['Gender'] = val;
        }
      }
      data.push(obj);
    }
    return data;
  } catch (e) {
    return [];
  }
}

/**
 * Updates a record.
 * Handles field aliasing and ensures standardized keys (BLO_Name, Gender) 
 * take priority over sheet-specific keys in the payload.
 */
function updateRecord(sheetName, idColumnName, idValue, updateObj) {
  try {
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const sheet = ss.getSheetByName(sheetName);
    if (!sheet) return { success: false, message: 'Sheet not found: ' + sheetName };

    const data = sheet.getDataRange().getValues();
    const headers = data[0].map(h => normalizeHeader(h));

    // 1. Find the ID Column
    let idColIndex = headers.indexOf(normalizeHeader(idColumnName));
    if (idColIndex === -1) {
      const alternatives = ['BLO_ID', 'ID', 'Supervisor_ID', 'Avihit_ID', 'User_ID'];
      for (let alt of alternatives) {
        let idx = headers.indexOf(normalizeHeader(alt));
        if (idx !== -1) { idColIndex = idx; break; }
      }
    }
    if (idColIndex === -1) idColIndex = 0;

    // 2. Resolve Field Mappings & Priority
    // If standardized keys exist in payload, we must use them and ignore aliases in the same payload
    const fieldMappings = {
      'BLO_Name': ['Supervisor_Name', 'Avihit_Name', 'Officer_Name', 'Name', 'BLO_Name'],
      'Gender': ['Sex', 'Gender']
    };

    // Clean up payload: if a standard key is present, remove all its aliases from the updateObj
    // to prevent the old sheet-specific data from overwriting the new standardized data.
    for (let standardKey in fieldMappings) {
      if (updateObj[standardKey] !== undefined) {
        fieldMappings[standardKey].forEach(alias => {
          if (alias !== standardKey) delete updateObj[alias];
        });
      }
    }

    // 3. Find the Row and Update
    for (let i = 1; i < data.length; i++) {
      if (String(data[i][idColIndex]) === String(idValue)) {
        updateObj['T_STMP_UPD'] = new Date().toISOString();

        // Loop through all keys to find where to save them in the sheet
        for (let key in updateObj) {
          let colIndex = headers.indexOf(normalizeHeader(key));

          // If standard key isn't found directly, check its aliases
          if (colIndex === -1 && fieldMappings[key]) {
            for (let alias of fieldMappings[key]) {
              let altIdx = headers.indexOf(normalizeHeader(alias));
              if (altIdx !== -1) {
                colIndex = altIdx;
                break;
              }
            }
          }

          if (colIndex !== -1) {
            let val = updateObj[key];

            // Special handling for specific fields
            if (key === 'Account_Number') {
               val = String(val);
               if (!val.startsWith("'")) val = "'" + val;
            }
            if (key === 'Account_Passbook_Doc' && String(val).startsWith('data:')) {
               const partInfo = updateObj['Sector_No'] ? ("S_" + updateObj['Sector_No']) : (updateObj['Part_No'] ? ("P_" + updateObj['Part_No']) : "ID_" + idValue);
               val = uploadBase64ToDrive(val, partInfo + "_" + (updateObj['BLO_Name'] || 'Officer')) || val;
            }

            sheet.getRange(i + 1, colIndex + 1).setValue(val);
          }
        }
        return { success: true };
      }
    }
    return { success: false, message: 'ID not found: ' + idValue };
  } catch (e) {
    return { success: false, message: e.toString() };
  }
}

function uploadBase64ToDrive(base64Data, fileName) {
  try {
    const parts = base64Data.split(',');
    if (parts.length < 2) return null;
    const mimeType = parts[0].match(/:(.*?);/)[1];
    const decodedData = Utilities.base64Decode(parts[1].replace(/\s/g, ''));
    const blob = Utilities.newBlob(decodedData, mimeType, fileName);
    const folder = DriveApp.getFolderById(TARGET_FOLDER_ID);
    const file = folder.createFile(blob);
    file.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);
    return file.getUrl();
  } catch (e) { return null; }
}

function addRecord(sheetName, recordObj) {
  try {
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const sheet = ss.getSheetByName(sheetName);
    const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0].map(h => normalizeHeader(h));
    const newRow = new Array(headers.length).fill('');
    recordObj['T_STMP_ADD'] = recordObj['T_STMP_UPD'] = new Date().toISOString();
    for (let key in recordObj) {
      const idx = headers.indexOf(normalizeHeader(key));
      if (idx !== -1) newRow[idx] = recordObj[key];
    }
    sheet.appendRow(newRow);
    return { success: true };
  } catch (e) { return { success: false, error: e.toString() }; }
}

function checkConfig() {
  try {
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    return { success: true, spreadsheet: ss.getName() };
  } catch (e) { return { success: false, error: e.toString() }; }
}

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { BLOAccount, User, UserType, Bank, BankBranch, Department, Designation, AccountCategory } from '../types';
import { searchIFSC } from '../services/ifscService';

interface AccountEntryProps {
  user: User;
  accounts: BLOAccount[];
  banks: Bank[];
  branches: BankBranch[];
  departments: Department[];
  designations: Designation[];
  onUpdate: (updated: BLOAccount, type: AccountCategory, newBank?: Bank, newBranch?: BankBranch) => void;
  type: AccountCategory;
}

const AccountEntry: React.FC<AccountEntryProps> = ({ user, accounts, banks, branches, departments, designations, onUpdate, type }) => {
  const [selectedBLO, setSelectedBLO] = useState<BLOAccount | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const [editForm, setEditForm] = useState<BLOAccount | null>(null);

  const [filterTehsil, setFilterTehsil] = useState('');
  const [filterAC, setFilterAC] = useState('');

  const [searchFeedback, setSearchFeedback] = useState<{ type: 'success' | 'error' | 'info' | 'none', message: string }>({ type: 'none', message: '' });
  const [stagedBank, setStagedBank] = useState<Bank | null>(null);
  const [stagedBranch, setStagedBranch] = useState<BankBranch | null>(null);

  const lastSearchedRef = useRef<string>('');
  const isAdmin = user.User_Type === UserType.ADMIN;

  const typeLabels: Record<AccountCategory, string> = {
    blo: 'BLO',
    avihit: 'Avihit',
    supervisor: 'Supervisor'
  };

  const uniqueTehsils = useMemo(() => Array.from(new Set(accounts.map(a => a.Tehsil))).sort(), [accounts]);
  const uniqueACs = useMemo(() => Array.from(new Set(accounts.map(a => a.AC_Name))).sort(), [accounts]);

  const filteredAccounts = useMemo(() => {
    let list = user.User_Type === UserType.ADMIN 
      ? accounts 
      : accounts.filter(a => String(a.User_ID).trim() === String(user.User_ID).trim());

    if (isAdmin) {
      if (filterTehsil) list = list.filter(a => a.Tehsil === filterTehsil);
      if (filterAC) list = list.filter(a => a.AC_Name === filterAC);
    }

    return list;
  }, [accounts, user, isAdmin, filterTehsil, filterAC]);

  const getEntityLabel = (obj: any, preferredKeys: string[]): string => {
    if (!obj) return '---';
    for (const key of preferredKeys) {
      if (obj[key] !== undefined && obj[key] !== null && String(obj[key]).trim() !== '') {
        return String(obj[key]).trim();
      }
    }
    return 'Unknown';
  };

  const getDeptName = (id: any) => {
    const dept = departments.find(d => String(d.Dept_ID).trim() === String(id).trim());
    return getEntityLabel(dept, ['Dept_Name', 'Department', 'Name']);
  };

  const getDesgName = (id: any) => {
    const desg = designations.find(d => String(d.Desg_ID).trim() === String(id).trim());
    return getEntityLabel(desg, ['Desg_Name', 'Designation', 'Name']);
  };

  const handleEdit = (blo: BLOAccount) => {
    setSelectedBLO(blo);
    setEditForm({ ...blo });
    setSearchFeedback({ type: 'none', message: '' });
    setStagedBank(null);
    setStagedBranch(null);
    lastSearchedRef.current = blo.IFSC_Code || '';
  };

  const triggerIFSCSearch = async (ifscCode: string) => {
    if (!ifscCode || ifscCode.length !== 11) {
      setSearchFeedback({ type: 'error', message: 'Please enter a valid 11-digit IFSC code.' });
      return;
    }

    setIsSearching(true);
    setSearchFeedback({ type: 'none', message: '' });
    setStagedBank(null);
    setStagedBranch(null);
    lastSearchedRef.current = ifscCode;

    // 1. Check local branches first (as requested)
    const localBranch = branches.find(br => String(br.IFSC_Code).toUpperCase() === ifscCode.toUpperCase());
    if (localBranch) {
      setEditForm(prev => prev ? ({
        ...prev,
        Bank_ID: localBranch.Bank_ID,
        Branch_ID: localBranch.Branch_ID
      }) : null);
      setStagedBranch(localBranch);
      setSearchFeedback({ type: 'success', message: 'Bank details found in current directory.' });
      setIsSearching(false);
      return;
    }

    // 2. Fetch externally and generate sequential IDs if needed
    try {
      const result = await searchIFSC(ifscCode);
      if (result) {
        const normalizedBankName = result.bankName.trim().toUpperCase();
        let bank = banks.find(b => String(b.Bank_Name).toUpperCase() === normalizedBankName);

        let targetBankId = '';
        let newBankObj: Bank | null = null;

        if (bank) {
          targetBankId = bank.Bank_ID;
        } else {
          // Calculate max Bank ID + 1
          const bankNums = banks.map(b => {
            const m = b.Bank_ID.match(/\d+/);
            return m ? parseInt(m[0]) : 0;
          });
          const nextBankNum = bankNums.length > 0 ? Math.max(...bankNums) + 1 : 1;
          targetBankId = `B_${nextBankNum}`;

          newBankObj = {
            Bank_ID: targetBankId,
            Bank_Name: result.bankName.toUpperCase(),
            T_STMP_ADD: new Date().toISOString(),
            T_STMP_UPD: new Date().toISOString()
          };
        }

        // Calculate max Branch ID + 1
        const branchNums = branches.map(br => {
          const m = br.Branch_ID.match(/\d+/);
          return m ? parseInt(m[0]) : 0;
        });
        const nextBranchNum = branchNums.length > 0 ? Math.max(...branchNums) + 1 : 1;
        const targetBranchId = `BR_${nextBranchNum}`;

        const newBranchObj: BankBranch = {
          Branch_ID: targetBranchId,
          Branch_Name: result.branchName.toUpperCase(),
          IFSC_Code: result.ifsc.toUpperCase(),
          Bank_ID: targetBankId,
          T_STMP_ADD: new Date().toISOString(),
          T_STMP_UPD: new Date().toISOString()
        };

        setEditForm(prev => prev ? ({
          ...prev,
          IFSC_Code: result.ifsc.toUpperCase(),
          Bank_ID: targetBankId,
          Branch_ID: targetBranchId
        }) : null);

        if (newBankObj) setStagedBank(newBankObj);
        setStagedBranch(newBranchObj);

        setSearchFeedback({ 
          type: 'info', 
          message: `Discovered new details! Bank: ${result.bankName}, Branch: ${result.branchName}. This will be added with IDs ${targetBankId} / ${targetBranchId} upon save.` 
        });
      } else {
        setSearchFeedback({ type: 'error', message: 'Could not find bank details for this IFSC code.' });
      }
    } catch (err) {
      setSearchFeedback({ type: 'error', message: 'Search failed.' });
    } finally {
      setIsSearching(false);
    }
  };

  useEffect(() => {
    if (editForm && String(editForm.IFSC_Code).length === 11 && String(editForm.IFSC_Code) !== lastSearchedRef.current) {
      triggerIFSCSearch(editForm.IFSC_Code);
    }
