              </div>
            </div>

            <div className="mt-5 text-center">
              <button onClick={() => setAuthStep('edit')} className="btn btn-primary btn-lg rounded-pill px-5 shadow-lg fw-bold">
                <i className="bi bi-pencil-square me-2"></i>
