                        onClick={() => { onNavigate(subItem.id); setIsOpen(false); }}
                        className={`nav-link w-100 text-start border-0 extra-small py-2 ${currentPage === subItem.id ? 'active text-white' : 'text-white-50'}`}
                        style={{ fontSize: '0.75rem' }}
                      >
                        {subItem.label}
                      </button>
                    ))}
                  </div>
                </>
              )}
            </li>
          ))}
        </ul>

        <div className="flex-shrink-0 mt-3">
          <hr className="border-secondary opacity-25" />
          <button 
            onClick={onLogout}
            className="btn btn-outline-danger w-100 d-flex align-items-center justify-content-center py-2 btn-sm mb-2"
          >
            <i className="bi bi-box-arrow-right me-2"></i>
            Logout
          </button>
        </div>
      </div>
    </>
  );
};

export default Sidebar;

import React, { useState, useEffect, useCallback } from 'react';
import { User, BLOAccount, Bank, BankBranch, AppState, Department, Designation, AccountCategory } from './types';
import { fetchAllData, updateAccountOnSheet, updateVerificationOnSheet, addBankOnSheet, addBranchOnSheet, updateUserOnSheet } from './services/dataService';
import Login from './pages/Login';
import Dashboard from './pages/Dashboard';
import AccountEntry from './pages/AccountEntry';
import Verification from './pages/Verification';
import Reports from './pages/Reports';
import ConsolidatedReport from './pages/ConsolidatedReport';
import UserManagement from './pages/UserManagement';
import Sidebar from './components/Sidebar';
import BLOApp from './pages/BLOApp';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    currentUser: null,
    currentBLO: null,
    accounts: [],
    avihitAccounts: [],
    supervisorAccounts: [],
    banks: [],
    branches: [],
    users: [],
    departments: [],
    designations: []
  });

  const [currentPage, setCurrentPage] = useState('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isInitialized, setIsInitialized] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [isMobileMode, setIsMobileMode] = useState(false);

  const loadData = async () => {
    setIsLoading(true);
    try {
      const data = await fetchAllData();
      setState(prev => ({ ...prev, ...data }));
    } catch (error) {
      console.error("Could not load data:", error);
      alert("Cloud Database Error. Check API_URL.");
    } finally {
      setIsLoading(false);
      setIsInitialized(true);
    }
  };

  useEffect(() => { loadData(); }, []);

  const updateAccount = useCallback(async (updated: BLOAccount, type: AccountCategory, newBank?: Bank, newBranch?: BankBranch) => {
    setIsLoading(true);
    try {
      if (newBank) await addBankOnSheet(newBank);
      if (newBranch) await addBranchOnSheet(newBranch);

      const result = await updateAccountOnSheet(updated, type);
      if (result.success) { 
        await loadData(); 
      } else { 
        alert("Failed to update: " + result.message); 
      }
    } catch (e) { 
      alert("Error updating record."); 
    } finally { setIsLoading(false); }
  }, [loadData]);

  const handleLogout = () => {
    setState(p => ({ ...p, currentUser: null, currentBLO: null }));
    setIsMobileMode(false);
    setCurrentPage('dashboard');
  };

  if (!isInitialized) return <div className="min-vh-100 d-flex align-items-center justify-content-center bg-light">
    <div className="text-center"><div className="spinner-border text-primary mb-3"></div><div>Syncing Cloud Database...</div></div>
  </div>;

  if (isMobileMode) {
    return <BLOApp 
      accounts={state.accounts} 
      banks={state.banks} 
      branches={state.branches} 
      departments={state.departments} 
      designations={state.designations} 
      onUpdateAccount={updateAccount}
      onLogout={handleLogout}
    />;
  }

  if (!state.currentUser) {
    return <Login 
      users={state.users} 
      onLogin={u => { setState(p => ({...p, currentUser: u})); setCurrentPage('dashboard'); }}
      onEnterBLOApp={() => setIsMobileMode(true)}
    />;
  }

  const renderContent = () => {
    if (currentPage.startsWith('entry-')) {
      const type = currentPage.split('-')[1] as AccountCategory;
      const data = type === 'blo' ? state.accounts : type === 'avihit' ? state.avihitAccounts : state.supervisorAccounts;
      return <AccountEntry type={type} accounts={data} user={state.currentUser!} banks={state.banks} branches={state.branches} departments={state.departments} designations={state.designations} onUpdate={updateAccount} />;
    }
    if (currentPage.startsWith('verification-')) {
      const type = currentPage.split('-')[1] as AccountCategory;
      const data = type === 'blo' ? state.accounts : type === 'avihit' ? state.avihitAccounts : state.supervisorAccounts;
      return <Verification type={type} accounts={data} user={state.currentUser!} banks={state.banks} branches={state.branches} departments={state.departments} designations={state.designations} onVerify={async (id, v, t) => {
        setIsLoading(true);
        const success = await updateVerificationOnSheet(id, v, t);
        if (success) await loadData();
        setIsLoading(false);
      }} />;
    }
    if (currentPage.startsWith('reports-')) {
      const type = currentPage.split('-')[1] as AccountCategory;
      const data = type === 'blo' ? state.accounts : type === 'avihit' ? state.avihitAccounts : state.supervisorAccounts;
      return (
        <Reports 
          type={type} 
          accounts={data} 
          bloAccounts={state.accounts}
          avihitAccounts={state.avihitAccounts}
          supervisorAccounts={state.supervisorAccounts}
          users={state.users} 
          user={state.currentUser!} 
        />
      );
    }

    switch (currentPage) {
      case 'dashboard': return <Dashboard user={state.currentUser!} accounts={[...state.accounts, ...state.avihitAccounts, ...state.supervisorAccounts]} />;
      case 'consolidated-report': return <ConsolidatedReport user={state.currentUser!} bloAccounts={state.accounts} avihitAccounts={state.avihitAccounts} supervisorAccounts={state.supervisorAccounts} />;
      case 'users': return <UserManagement currentUser={state.currentUser!} users={state.users} onUpdateUser={async (u) => { await updateUserOnSheet(u); await loadData(); }} />;
      default: return <Dashboard user={state.currentUser!} accounts={[...state.accounts, ...state.avihitAccounts, ...state.supervisorAccounts]} />;
    }
  };

  return (
    <div className="app-container">
      {isLoading && <div className="position-fixed top-0 start-0 w-100 h-100 d-flex align-items-center justify-content-center bg-white bg-opacity-75 z-3"><div className="spinner-border text-primary"></div></div>}
      <Sidebar user={state.currentUser!} currentPage={currentPage} onNavigate={setCurrentPage} isOpen={isSidebarOpen} setIsOpen={setIsSidebarOpen} onLogout={handleLogout} />
      <div className="main-content">
        <div className="d-lg-none bg-white p-3 mb-4 d-flex justify-content-between"><h5>ACCOUNT PORTAL</h5><button className="btn btn-light" onClick={() => setIsSidebarOpen(true)}><i className="bi bi-list"></i></button></div>
        {renderContent()}
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { BLOAccount, User, UserType, AccountCategory } from '../types';

interface ReportsProps {
  user: User;
  accounts: BLOAccount[]; // This is the 'active' category filtered for current view
  bloAccounts?: BLOAccount[];
  avihitAccounts?: BLOAccount[];
  supervisorAccounts?: BLOAccount[];
  users: User[];
  type: AccountCategory;
}

const Reports: React.FC<ReportsProps> = ({ user, accounts, users, type }) => {
  const isAdmin = user.User_Type === UserType.ADMIN;
  const typeLabels: Record<AccountCategory, string> = { blo: 'BLO', avihit: 'Avihit', supervisor: 'Supervisor' };

  // Helper to filter data by user context
  const filterByContext = (list: BLOAccount[]) => {
    return isAdmin 
      ? list 
      : list.filter(a => String(a.User_ID).trim() === String(user.User_ID).trim());
  };

  const displayedAccounts = filterByContext(accounts);

  const globalTotal = displayedAccounts.length;
  const globalEntered = displayedAccounts.filter(a => a.Account_Number && String(a.Account_Number).trim() !== '').length;
  const globalVerified = displayedAccounts.filter(a => a.Verified === 'yes').length;

  const globalEntryPct = globalTotal > 0 ? Math.round((globalEntered / globalTotal) * 100) : 0;
  const globalVerifyPct = globalTotal > 0 ? Math.round((globalVerified / globalTotal) * 100) : 0;

  // User breakdown for the active category
  const userBreakdown = isAdmin ? users.map(u => {
    const userAccounts = accounts.filter(a => String(a.User_ID).trim() === String(u.User_ID).trim());
    const total = userAccounts.length;
    const entered = userAccounts.filter(a => a.Account_Number && String(a.Account_Number).trim() !== '').length;
    const verified = userAccounts.filter(a => a.Verified === 'yes').length;
    const tehsilName = userAccounts.length > 0 ? userAccounts[0].Tehsil : 'N/A';

    return {
      userId: u.User_ID,
      officerName: u.Officer_Name,
      tehsil: tehsilName,
      total, entered, verified,
      entryProgress: total > 0 ? Math.round((entered / total) * 100) : 0,
      verifyProgress: total > 0 ? Math.round((verified / total) * 100) : 0
    };
  }).filter(u => u.total > 0) : [];

  return (
    <div className="container-fluid py-2 pb-5">
      <div className="card shadow-sm p-4 border-0 mb-4">
        <h3 className="fw-bold mb-1">{typeLabels[type]} Report</h3>
        <p className="text-muted small mb-0">Milestones for {typeLabels[type]} data entries.</p>
      </div>

      <div className="row g-4 mb-5">
        <div className="col-md-4">
          <div className="card border-0 shadow-sm bg-primary text-white p-4">
            <div className="d-flex justify-content-between align-items-center">
              <div>
                <small className="opacity-75">TOTAL {type === 'supervisor' ? 'SECTORS' : 'PARTS'}</small>
                <h2 className="fw-bold mb-0">{globalTotal}</h2>
              </div>
              <i className="bi bi-people-fill fs-1 opacity-25"></i>
            </div>
          </div>
        </div>
        <div className="col-md-4">
          <div className="card border-0 shadow-sm bg-info text-white p-4">
            <div className="d-flex justify-content-between align-items-center">
              <div>
                <small className="opacity-75">ENTRIES DONE</small>
                <h2 className="fw-bold mb-0">{globalEntered} <small className="fs-6 opacity-75">({globalEntryPct}%)</small></h2>
              </div>
              <i className="bi bi-pencil-fill fs-1 opacity-25"></i>
            </div>
          </div>
        </div>
        <div className="col-md-4">
          <div className="card border-0 shadow-sm bg-success text-white p-4">
            <div className="d-flex justify-content-between align-items-center">
              <div>
                <small className="opacity-75">VERIFIED</small>
                <h2 className="fw-bold mb-0">{globalVerified} <small className="fs-6 opacity-75">({globalVerifyPct}%)</small></h2>
              </div>
              <i className="bi bi-patch-check-fill fs-1 opacity-25"></i>
            </div>
          </div>
        </div>
      </div>

      {isAdmin && (
        <div className="card border-0 shadow-sm overflow-hidden bg-white">
          <div className="card-header bg-light py-3 px-4">
            <h6 className="mb-0 fw-bold text-muted text-uppercase small">Officer Performance: {typeLabels[type]}</h6>
          </div>
          <div className="table-responsive">
            <table className="table table-hover align-middle mb-0">
              <thead className="table-light">
                <tr>
                  <th className="ps-4 py-3">TEHSIL</th>
                  <th className="py-3">OFFICER</th>
                  <th className="py-3 text-center">TOTAL</th>
                  <th className="py-3">ENTRY STATUS (COUNT)</th>
                  <th className="py-3">VERIFY STATUS (COUNT)</th>
                </tr>
              </thead>
              <tbody>
                {userBreakdown.map(item => (
                  <tr key={item.userId}>
                    <td className="ps-4">
                      <span className="badge bg-light text-dark border px-2 py-1">{item.tehsil}</span>
                    </td>
                    <td>
                      <div className="fw-bold text-primary">{item.officerName}</div>
                    </td>
                    <td className="text-center fw-bold">{item.total}</td>
                    <td>
                      <div className="progress mb-1" style={{ height: '6px' }}>
                        <div className="progress-bar bg-info" style={{ width: `${item.entryProgress}%` }}></div>
                      </div>
                      <div className="d-flex justify-content-between align-items-center">
                        <small className="fw-bold text-info">{item.entryProgress}%</small>
                        <small className="extra-small text-muted">{item.entered} / {item.total}</small>
                      </div>
                    </td>
                    <td>
                      <div className="progress mb-1" style={{ height: '6px' }}>
                        <div className="progress-bar bg-success" style={{ width: `${item.verifyProgress}%` }}></div>
                      </div>
                      <div className="d-flex justify-content-between align-items-center">
                        <small className="fw-bold text-success">{item.verifyProgress}%</small>
                        <small className="extra-small text-muted">{item.verified} / {item.total}</small>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
};

export default Reports;

import React, { useState, useEffect, useMemo } from 'react';
import { BLOAccount, User, UserType, Bank, BankBranch, Department, Designation, AccountCategory } from '../types';
import * as XLSX from 'xlsx';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';

interface VerificationProps {
  user: User;
  accounts: BLOAccount[];
  banks: Bank[];
  branches: BankBranch[];
  departments: Department[];
  designations: Designation[];
  onVerify: (bloId: string, verified: 'yes' | 'no', type: AccountCategory) => void;
  type: AccountCategory;
}

const Verification: React.FC<VerificationProps> = ({ user, accounts, banks, branches, departments, designations, onVerify, type }) => {
  const [selectedBLO, setSelectedBLO] = useState<BLOAccount | null>(null);
  const [isExporting, setIsExporting] = useState(false);

  const [filterTehsil, setFilterTehsil] = useState('');
  const [filterAC, setFilterAC] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [pageSize, setPageSize] = useState<number | 'all'>(10);

  const isAdmin = user.User_Type === UserType.ADMIN;
  const typeLabels: Record<AccountCategory, string> = { blo: 'BLO', avihit: 'Avihit', supervisor: 'Supervisor' };

  const getDesgName = (id: string) => {
    const desg = designations.find(d => String(d.Dept_ID).trim() === String(id).trim());
    return desg ? desg.Desg_Name : 'Officer';
  };

  const formatId = (val: string | number | undefined) => {
    if (val === undefined || val === null) return '000';
    return String(val).padStart(3, '0');
  };

  const filteredAccounts = useMemo(() => {
    let list = (user.User_Type === UserType.ADMIN 
      ? accounts 
      : accounts.filter(a => String(a.User_ID).trim() === String(user.User_ID).trim()))
      .filter(a => a.Account_Number && String(a.Account_Number).trim() !== '');

    if (isAdmin) {
      if (filterTehsil) list = list.filter(a => a.Tehsil === filterTehsil);
      if (filterAC) list = list.filter(a => a.AC_Name === filterAC);
    }
    return list;
  }, [accounts, user, isAdmin, filterTehsil, filterAC]);

  const totalPages = pageSize === 'all' ? 1 : Math.ceil(filteredAccounts.length / Number(pageSize));
  const paginatedAccounts = useMemo(() => {
    if (pageSize === 'all') return filteredAccounts;
    const start = (currentPage - 1) * Number(pageSize);
    return filteredAccounts.slice(start, start + Number(pageSize));
  }, [filteredAccounts, currentPage, pageSize]);

  const uniqueTehsils = useMemo(() => Array.from(new Set(accounts.map(a => a.Tehsil))).sort(), [accounts]);
  const uniqueACs = useMemo(() => Array.from(new Set(accounts.map(a => a.AC_Name))).sort(), [accounts]);

  useEffect(() => { setCurrentPage(1); }, [filterTehsil, filterAC, pageSize]);

  const handleVerifyToggle = (blo: BLOAccount) => {
    if (blo.Verified === 'yes' && !isAdmin) {
      alert("Only administrators can un-verify.");
      return;
    }
    const nextState = blo.Verified === 'yes' ? 'no' : 'yes';
    onVerify(blo.BLO_ID, nextState, type);
    if (selectedBLO?.BLO_ID === blo.BLO_ID) {
      setSelectedBLO({...blo, Verified: nextState});
    }
  };

  const getExportData = () => {
    // Requirements fulfilled: 
    // 1. Uses filteredAccounts (handles Admin filters vs Normal User scope)
    // 2. Sorts by AC_No (numeric) then Identifier
    return filteredAccounts
      .filter(a => a.Verified === 'yes')
      .map(a => {
        const bank = banks.find(b => String(b.Bank_ID).trim() === String(a.Bank_ID).trim());
        const idVal = type === 'supervisor' ? a.Sector_No : a.Part_No;
        const identifier = type === 'supervisor' ? `S-${formatId(idVal)}` : `P-${formatId(idVal)}`;
        return {
          'Identifier': identifier,
          'AC': a.AC_No,
          'Name': a.BLO_Name,
          'Bank': bank ? bank.Bank_Name : '---',
          'IFSC': a.IFSC_Code,
          'Account': a.Account_Number,
          'Status': 'Verified'
        };
      })
      .sort((a, b) => {
        // Numeric sort for AC first
        const acA = Number(a.AC) || 0;
        const acB = Number(b.AC) || 0;
        if (acA !== acB) return acA - acB;
        // Then alphanumeric sort for Identifier
        return a.Identifier.localeCompare(b.Identifier);
      });
  };

  const handleExportExcel = () => {
    const data = getExportData();
    if (data.length === 0) {
      alert("No verified accounts to export.");
      return;
    }
    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Verified");
    XLSX.writeFile(wb, `${typeLabels[type]}_Verified.xlsx`);
  };

  const handleExportPDF = () => {
    const data = getExportData();
    if (data.length === 0) {
      alert("No verified accounts to export.");
      return;
    }

    const doc = new jsPDF();
    const tableColumn = Object.keys(data[0]);
    const tableRows = data.map(item => Object.values(item));

    const title = `${typeLabels[type]} Verified Bank Accounts Report`;
    const dateStr = `Generated on: ${new Date().toLocaleDateString()}`;

    doc.setFontSize(18);
    doc.text(title, 14, 15);
    doc.setFontSize(11);
    doc.text(dateStr, 14, 22);

    autoTable(doc, {
      head: [tableColumn],
      body: tableRows,
      startY: 28,
      theme: 'grid',
      styles: { fontSize: 8, cellPadding: 2 },
      headStyles: { fillColor: [41, 128, 185], textColor: 255, fontStyle: 'bold' },
      margin: { bottom: 45 }, // Space for footer
      didDrawPage: (dataArg) => {
        const pageSize = doc.internal.pageSize;
        const pageHeight = pageSize.height ? pageSize.height : pageSize.getHeight();
        const pageWidth = pageSize.width ? pageSize.width : pageSize.getWidth();

        // Footer signature block
        const footerY = pageHeight - 35;
        doc.setDrawColor(200);
        doc.line(14, footerY, pageWidth - 14, footerY);

        doc.setFontSize(10);
        doc.setTextColor(0);
        doc.setFont("helvetica", "bold");
        doc.text(`Verifying Authority:`, 14, footerY + 10);

        doc.setFont("helvetica", "normal");
        doc.text(`${user.Officer_Name}`, 14, footerY + 18);
        doc.text(`${user.Designation}`, 14, footerY + 24);

        doc.setFontSize(9);
        doc.text(`Signature: __________________________`, 14, footerY + 30);

        // Page numbering
        const str = `Page ${dataArg.pageNumber}`;
        doc.setFontSize(8);
        doc.setTextColor(150);
        doc.text(str, pageWidth - 25, footerY + 10);
      }
    });

    doc.save(`${typeLabels[type]}_Verified_Accounts.pdf`);
  };

  const renderDocumentViewer = (doc: string) => {
    if (!doc) return <div className="text-center text-muted p-5">No Document</div>;
    if (doc.includes('drive.google.com')) {
      const previewUrl = doc.replace('/view?usp=sharing', '/preview').replace('/view', '/preview');
      return <iframe src={previewUrl} className="w-100 h-100 rounded border-0"></iframe>;
    }
    if (doc.startsWith('data:image')) return <img src={doc} alt="Passbook" className="img-fluid m-auto" style={{maxHeight: '95%'}} />;
    if (doc.startsWith('data:application/pdf')) return <iframe src={doc} className="w-100 h-100 rounded border-0"></iframe>;
    return <div className="p-4 text-center">Format not viewable.</div>;
  };

  return (
    <div className="container-fluid py-2">
      <div className="row g-4">
        <div className={`col-12 col-lg-4 ${selectedBLO ? 'd-none d-lg-block' : ''}`}>
          <div className="d-flex flex-column gap-3 mb-3">
            <h3 className="fw-bold mb-0">{typeLabels[type]} Audit</h3>
            {isAdmin && (
              <div className="card border-0 shadow-sm bg-white p-3">
                <div className="row g-2">
                  <div className="col-6"><select className="form-select form-select-sm" value={filterTehsil} onChange={e => setFilterTehsil(e.target.value)}><option value="">Tehsils</option>{uniqueTehsils.map(t => <option key={t} value={t}>{t}</option>)}</select></div>
                  <div className="col-6"><select className="form-select form-select-sm" value={filterAC} onChange={e => setFilterAC(e.target.value)}><option value="">ACs</option>{uniqueACs.map(ac => <option key={ac} value={ac}>{ac}</option>)}</select></div>
                </div>
              </div>
            )}
            <div className="d-flex gap-2">
              <button onClick={handleExportExcel} className="btn btn-success btn-sm flex-grow-1">
                <i className="bi bi-file-earmark-excel me-2"></i>Export Excel
              </button>
              <button onClick={handleExportPDF} className="btn btn-danger btn-sm flex-grow-1">
                <i className="bi bi-file-earmark-pdf me-2"></i>Export PDF
              </button>
            </div>
          </div>

          <div className="card shadow-sm border-0 overflow-hidden bg-white">
            <div className="list-group list-group-flush" style={{maxHeight: '52vh', overflowY: 'auto'}}>
              {paginatedAccounts.map(blo => (
                <button key={blo.BLO_ID} onClick={() => setSelectedBLO(blo)} className={`list-group-item list-group-item-action p-3 border-0 border-bottom ${selectedBLO?.BLO_ID === blo.BLO_ID ? 'bg-primary-subtle' : ''}`}>
                  <div className="d-flex justify-content-between">
                    <div>
                      <h6 className="fw-bold mb-0">{blo.BLO_Name}</h6>
                      <small>
                        {type === 'supervisor' ? `S-${formatId(blo.Sector_No)}` : `P-${formatId(blo.Part_No)}`} | {blo.Tehsil}
                      </small>
                    </div>
                    {blo.Verified === 'yes' && <i className="bi bi-check-circle-fill text-success"></i>}
                  </div>
                </button>
              ))}
            </div>
            <div className="card-footer bg-white border-top p-2 d-flex justify-content-between align-items-center">
              <span className="extra-small">Page {currentPage}/{totalPages}</span>
              <div className="btn-group btn-group-sm">
                <button className="btn btn-outline-secondary" disabled={currentPage === 1} onClick={() => setCurrentPage(p => p - 1)}>Prev</button>
                <button className="btn btn-outline-secondary" disabled={currentPage >= totalPages} onClick={() => setCurrentPage(p => p + 1)}>Next</button>
              </div>
            </div>
          </div>
        </div>

        {selectedBLO ? (
          <div className="col-12 col-lg-8">
            <div className="card shadow-lg border-0 h-100 flex-column overflow-hidden bg-white">
              <div className="card-header bg-dark text-white p-3 d-flex justify-content-between align-items-center">
                <h5 className="mb-0 fw-bold">Audit: {selectedBLO.BLO_Name}</h5>
                <button onClick={() => setSelectedBLO(null)} className="btn btn-sm btn-outline-light">Close</button>
              </div>
              <div className="row g-0 flex-grow-1">
                <div className="col-md-7 bg-dark bg-opacity-10 d-flex flex-column border-end" style={{ minHeight: '500px' }}>{renderDocumentViewer(selectedBLO.Account_Passbook_Doc)}</div>
                <div className="col-md-5 p-4 bg-white d-flex flex-column">
                  <div className="mb-4">
                    <div className="card border-0 bg-primary bg-opacity-10 mb-3 text-center p-3">
                      <small className="fw-bold text-uppercase">{banks.find(b => String(b.Bank_ID).trim() === String(selectedBLO.Bank_ID).trim())?.Bank_Name || '---'}</small>
                      <div className="h3 fw-bold mb-0 font-monospace">{selectedBLO.Account_Number}</div>
                    </div>
                    <div className="card border-0 bg-info bg-opacity-10 text-center p-3">
                      <small className="fw-bold text-uppercase">{branches.find(br => String(br.Branch_ID).trim() === String(selectedBLO.Branch_ID).trim())?.Branch_Name || '---'}</small>
                      <div className="h4 fw-bold mb-0 font-monospace">{selectedBLO.IFSC_Code}</div>
                    </div>
                  </div>
                  <div className="bg-light p-3 rounded mb-4">
                    <div className="small mb-1"><span className="fw-bold">Tehsil:</span> {selectedBLO.Tehsil}</div>
                    <div className="small mb-1"><span className="fw-bold">{type === 'supervisor' ? 'Sector' : 'Part'}:</span> {type === 'supervisor' ? formatId(selectedBLO.Sector_No) : formatId(selectedBLO.Part_No)}</div>
                    <div className="small"><span className="fw-bold">Mobile:</span> {selectedBLO.Mobile}</div>
                  </div>
                  <button onClick={() => handleVerifyToggle(selectedBLO)} className={`btn ${selectedBLO.Verified === 'yes' ? 'btn-danger' : 'btn-success'} py-3 mt-auto fw-bold`}>
                    {selectedBLO.Verified === 'yes' ? 'REVOKE VERIFICATION' : 'VERIFY ACCOUNT'}
                  </button>
                </div>
              </div>
            </div>
          </div>
        ) : (
          <div className="col-lg-8 d-none d-lg-flex align-items-center justify-content-center bg-light border border-dashed rounded-4">
            <div className="text-center"><i className="bi bi-shield-check display-1 opacity-25"></i><h4 className="text-muted mt-3">Ready to Audit</h4></div>
          </div>
        )}
      </div>
    </div>
  );
};

export default Verification;

import React, { useMemo } from 'react';
import { BLOAccount, User, UserType } from '../types';
import * as XLSX from 'xlsx';

interface ConsolidatedReportProps {
  user: User;
  bloAccounts: BLOAccount[];
  avihitAccounts: BLOAccount[];
  supervisorAccounts: BLOAccount[];
}

const ConsolidatedReport: React.FC<ConsolidatedReportProps> = ({ user, bloAccounts, avihitAccounts, supervisorAccounts }) => {
  const isAdmin = user.User_Type === UserType.ADMIN;

  const filterByContext = (list: BLOAccount[]) => {
    return isAdmin 
      ? list 
      : list.filter(a => String(a.User_ID).trim() === String(user.User_ID).trim());
  };

  const tehsilSummary = useMemo(() => {
    const contextBlo = filterByContext(bloAccounts);
    const contextAvihit = filterByContext(avihitAccounts);
    const contextSup = filterByContext(supervisorAccounts);

    const allTehsils = Array.from(new Set([
      ...contextBlo.map(a => a.Tehsil),
      ...contextAvihit.map(a => a.Tehsil),
      ...contextSup.map(a => a.Tehsil)
    ])).filter(t => t && t.trim() !== '').sort();

    return allTehsils.map(tehsil => {
      const getStats = (list: BLOAccount[]) => {
        const tAccounts = list.filter(a => a.Tehsil === tehsil);
        const target = tAccounts.length;
        const entry = tAccounts.filter(a => a.Account_Number && String(a.Account_Number).trim() !== '').length;
        const verified = tAccounts.filter(a => a.Verified === 'yes').length;
        return { target, entry, verified, remaining: target - entry };
      };

      return {
        tehsil,
        blo: getStats(contextBlo),
        avihit: getStats(contextAvihit),
        supervisor: getStats(contextSup)
      };
    });
  }, [bloAccounts, avihitAccounts, supervisorAccounts, isAdmin, user.User_ID]);

  const totals = useMemo(() => {
    return tehsilSummary.reduce((acc, row) => ({
      blo: { 
        target: acc.blo.target + row.blo.target, 
        entry: acc.blo.entry + row.blo.entry, 
        verified: acc.blo.verified + row.blo.verified,
        remaining: acc.blo.remaining + row.blo.remaining 
      },
      avihit: { 
        target: acc.avihit.target + row.avihit.target, 
        entry: acc.avihit.entry + row.avihit.entry, 
        verified: acc.avihit.verified + row.avihit.verified,
        remaining: acc.avihit.remaining + row.avihit.remaining 
      },
      supervisor: { 
        target: acc.supervisor.target + row.supervisor.target, 
        entry: acc.supervisor.entry + row.supervisor.entry, 
        verified: acc.supervisor.verified + row.supervisor.verified,
        remaining: acc.supervisor.remaining + row.supervisor.remaining 
      }
    }), {
      blo: { target: 0, entry: 0, verified: 0, remaining: 0 },
      avihit: { target: 0, entry: 0, verified: 0, remaining: 0 },
      supervisor: { target: 0, entry: 0, verified: 0, remaining: 0 }
    });
  }, [tehsilSummary]);

  const handleExportExcel = () => {
    const exportData = tehsilSummary.map(row => ({
      'Tehsil': row.tehsil,
      'BLO Target': row.blo.target, 'BLO Entry': row.blo.entry, 'BLO Verified': row.blo.verified, 'BLO Remaining': row.blo.remaining,
      'Avihit Target': row.avihit.target, 'Avihit Entry': row.avihit.entry, 'Avihit Verified': row.avihit.verified, 'Avihit Remaining': row.avihit.remaining,
      'Supervisor Target': row.supervisor.target, 'Supervisor Entry': row.supervisor.entry, 'Supervisor Verified': row.supervisor.verified, 'Supervisor Remaining': row.supervisor.remaining
    }));

    const ws = XLSX.utils.json_to_sheet(exportData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Consolidated Summary");
    XLSX.writeFile(wb, "Consolidated_Tehsil_Summary.xlsx");
  };

  return (
    <div className="container-fluid py-2 pb-5">
      <div className="card shadow-sm p-4 border-0 mb-4 bg-white d-flex flex-row justify-content-between align-items-center">
        <div>
          <h3 className="fw-bold mb-1">Consolidated Tehsil Summary</h3>
          <p className="text-muted small mb-0">Cross-category comparison of Target vs Actual entries.</p>
        </div>
        <button onClick={handleExportExcel} className="btn btn-success shadow-sm">
          <i className="bi bi-file-earmark-excel me-2"></i>Export Summary
        </button>
      </div>

      <div className="card border-0 shadow-sm mb-5 bg-white">
        <div className="table-responsive">
          <table className="table table-bordered align-middle mb-0 text-center">
            <thead className="table-light">
              <tr className="extra-small fw-bold">
                <th rowSpan={2} className="align-middle bg-light text-start ps-4" style={{ width: '15%' }}>TEHSIL NAME</th>
                <th colSpan={4} className="bg-primary bg-opacity-10 text-primary py-2 border-bottom-0">BLO (PARTS)</th>
                <th colSpan={4} className="bg-info bg-opacity-10 text-info py-2 border-bottom-0">AVIHIT (PARTS)</th>
                <th colSpan={4} className="bg-success bg-opacity-10 text-success py-2 border-bottom-0">SUPERVISOR (SECTORS)</th>
              </tr>
              <tr className="extra-small fw-bold" style={{ fontSize: '0.65rem' }}>
                <th className="bg-primary text-white py-1">Target</th>
                <th className="bg-primary text-white py-1">Entry</th>
                <th className="bg-primary text-white py-1">Verf.</th>
                <th className="bg-primary text-white py-1">Rem.</th>
                <th className="bg-info text-white py-1">Target</th>
                <th className="bg-info text-white py-1">Entry</th>
                <th className="bg-info text-white py-1">Verf.</th>
                <th className="bg-info text-white py-1">Rem.</th>
                <th className="bg-success text-white py-1">Target</th>
                <th className="bg-success text-white py-1">Entry</th>
                <th className="bg-success text-white py-1">Verf.</th>
                <th className="bg-success text-white py-1">Rem.</th>
              </tr>
            </thead>
            <tbody className="small">
              {tehsilSummary.map(row => (
                <tr key={row.tehsil}>
                  <td className="text-start ps-4 fw-bold">{row.tehsil}</td>
                  <td className="bg-primary bg-opacity-10">{row.blo.target}</td>
                  <td className="bg-primary bg-opacity-10">{row.blo.entry}</td>
                  <td className="bg-primary bg-opacity-10 text-success">{row.blo.verified}</td>
                  <td className={`bg-primary bg-opacity-10 fw-bold ${row.blo.remaining > 0 ? 'text-danger' : 'text-success'}`}>{row.blo.remaining}</td>
                  <td className="bg-info bg-opacity-10">{row.avihit.target}</td>
                  <td className="bg-info bg-opacity-10">{row.avihit.entry}</td>
                  <td className="bg-info bg-opacity-10 text-success">{row.avihit.verified}</td>
                  <td className={`bg-info bg-opacity-10 fw-bold ${row.avihit.remaining > 0 ? 'text-danger' : 'text-success'}`}>{row.avihit.remaining}</td>
                  <td className="bg-success bg-opacity-10">{row.supervisor.target}</td>
                  <td className="bg-success bg-opacity-10">{row.supervisor.entry}</td>
                  <td className="bg-success bg-opacity-10 text-success">{row.supervisor.verified}</td>
                  <td className={`bg-success bg-opacity-10 fw-bold ${row.supervisor.remaining > 0 ? 'text-danger' : 'text-success'}`}>{row.supervisor.remaining}</td>
                </tr>
              ))}
            </tbody>
            <tfoot className="table-dark">
              <tr className="fw-bold">
                <td className="text-start ps-4">GRAND TOTAL</td>
                <td>{totals.blo.target}</td>
                <td>{totals.blo.entry}</td>
                <td className="text-success">{totals.blo.verified}</td>
                <td className="text-warning">{totals.blo.remaining}</td>
                <td>{totals.avihit.target}</td>
                <td>{totals.avihit.entry}</td>
                <td className="text-success">{totals.avihit.verified}</td>
                <td className="text-warning">{totals.avihit.remaining}</td>
                <td>{totals.supervisor.target}</td>
                <td>{totals.supervisor.entry}</td>
                <td className="text-success">{totals.supervisor.verified}</td>
                <td className="text-warning">{totals.supervisor.remaining}</td>
              </tr>
            </tfoot>
          </table>
        </div>
      </div>

      <div className="row g-4">
        <div className="col-md-4">
          <div className="card p-4 border-0 shadow-sm bg-white text-center">
            <h1 className="fw-bold text-primary mb-0">{Math.round((totals.blo.entry / (totals.blo.target || 1)) * 100)}%</h1>
            <div className="extra-small fw-bold text-muted">BLO COMPLETION</div>
          </div>
        </div>
        <div className="col-md-4">
          <div className="card p-4 border-0 shadow-sm bg-white text-center">
            <h1 className="fw-bold text-info mb-0">{Math.round((totals.avihit.entry / (totals.avihit.target || 1)) * 100)}%</h1>
            <div className="extra-small fw-bold text-muted">AVIHIT COMPLETION</div>
          </div>
        </div>
        <div className="col-md-4">
          <div className="card p-4 border-0 shadow-sm bg-white text-center">
            <h1 className="fw-bold text-success mb-0">{Math.round((totals.supervisor.entry / (totals.supervisor.target || 1)) * 100)}%</h1>
            <div className="extra-small fw-bold text-muted">SUPERVISOR COMPLETION</div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ConsolidatedReport;
